-- Poems batch 77
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('39f226b1-5df7-4a5b-9635-2ddf424f3482','述懷呈十七家叔  其三','陳與義','宋','宋诗','song-poetry','','[]','眼送飛鳥。',32,'全唐诗/poet.song.100000.json','["眼送飛鳥。", "兩翁觀光今幾時，賦歸有約時已稽。", "未暇藏身北山北，且須。"]'),
('0ab6230f-b089-4e78-bcd0-7ae386dbebac','述懷呈十七家叔  其四','陳與義','宋','宋诗','song-poetry','','[]','覓地西枝西。',38,'全唐诗/poet.song.100000.json','["覓地西枝西。", "願從我翁歸洗耳，不用妓女汙山水。", "肩輿亦莫要僕夫，自有門生與兒子。"]'),
('a15ae7b7-3b93-471b-af2f-71af4af07af6','同叔易于觀我齋分韻得自字','陳與義','宋','宋诗','song-poetry','','[]','小草浪出山，大隱乃居市。',120,'全唐诗/poet.song.100000.json','["小草浪出山，大隱乃居市。", "功名一畫餅，甚矣癡兒計。", "傾身犯火宅，顧自以爲戲。", "汗顔逢冰子，更復問奚自。", "三肅齋中人，本是青雲器。", "雖然山上山，政爾吏非吏。", "肅肅窗前竹，見引著勝地。", "世間劇寒暑，了不受榮悴。", "門前剝啄客，欲問觀我意。", "但持邯鄲枕，贈我一覺睡。"]'),
('871c702f-379f-41d9-abf0-ba0f112a2735','觀我齋再分韻得下字','陳與義','宋','宋诗','song-poetry','','[]','一慵縛兩脚，閉戶了晨夜。',120,'全唐诗/poet.song.100000.json','["一慵縛兩脚，閉戶了晨夜。", "夢攀城西樹，起造君子舍。", "紫髯出堂堂，見客披衣謝。", "平生功名手，嗜靜如食蔗。", "小齋劇冰壺，中明外無罅。", "要知日用事，趺坐看鳥下。", "主人心了了，竹石亦閒暇。", "兒童慣看客，我車當日駕。", "平分齋中閒，風月不待借。", "還須酒屢費，不用牛心炙。"]'),
('939f6537-7599-42a1-9cf3-a4ffd50dd03e','寄題商洛宰令狐勵迎翠樓','陳與義','宋','宋诗','song-poetry','','[]','西來金衣鶴，書落汝水湄。',168,'全唐诗/poet.song.100000.json','["西來金衣鶴，書落汝水湄。", "雲霞映道路，中有迎翠詩。", "遥知五斗粟，未辦買山資。", "政要百尺樓，了此浮天眉。", "森然詩中畫，想見憑欄時。", "朝曦與暮靄，百變皆令姿。", "君方領此意，簿書何急爲。", "衆手劇雲雨，唯山不瑕疪。", "當年四老翁，視世輕於芝。", "坐令山偃蹇，不受人招麾。", "誰歟樓中客，俯仰與山期。", "顧要君折腰，督郵真小兒。", "因之感我意，故巖歸已遲。", "便携靈運屐，不待德璋移。"]'),
('1e4b5f72-2b6e-40fe-8310-59013dccf942','次韻謝天寧老見貽','陳與義','宋','宋诗','song-poetry','','[]','庭柏不受寒，依然照人綠。',168,'全唐诗/poet.song.100000.json','["庭柏不受寒，依然照人綠。", "霧收晨光發，可玩不可掬。", "道人方出定，不復辨羊鹿。", "微雲度遥天，一笑立於獨。", "嗟予晚聞道，學看傳燈錄。", "三生蠹書魚，萬卷今可束。", "轂雖已破碎，猶欲大其輻。", "是身堪底用，况乃五斗粟。", "自從識師面，日月幾轉轂。", "受師爐中煙，無處著榮辱。", "周妻與何肉，恨我未免俗。", "從今謝百事，請作龜頭縮。", "却笑長沙傅，區區問淹速。", "聊將非舌言，往和無譜曲。"]'),
('00101eb7-49a8-4fe7-a79e-f0da1b97e893','陳叔易學士母阮氏挽詞  其一','陳與義','宋','宋诗','song-poetry','','[]','典刑奕奕照來今，鶴髮魚軒汝水潯。',64,'全唐诗/poet.song.100000.json','["典刑奕奕照來今，鶴髮魚軒汝水潯。", "避地梁鴻不偕老，弄烏萊子若爲心。", "送葬忽見三千乘，奉裞那聞五百金。", "婦德母儀俱不愧，碑銘知已託張林。"]'),
('7fcaec79-6597-44d6-b391-145215969f78','陳叔易學士母阮氏挽詞  其二','陳與義','宋','宋诗','song-poetry','','[]','去年披霧識儒先，欲拜萱堂未敢前。',64,'全唐诗/poet.song.100000.json','["去年披霧識儒先，欲拜萱堂未敢前。", "盧壺要傳紗縵業，王裒忽廢蓼莪篇。", "秀眉隔夢黄壚裏，落日驅風丹旐邊。", "佛子歸真定何處，空令苦淚漲黄泉。"]'),
('634a8f96-3d19-42a1-a696-e3b0cee67d8d','歸洛道中','陳與義','宋','宋诗','song-poetry','','[]','洛陽城邊風起沙，征衫歲歲負年華。',64,'全唐诗/poet.song.100000.json','["洛陽城邊風起沙，征衫歲歲負年華。", "歸途忽踐楊柳影，春事已到蕪菁花。", "道路無窮幾傾轂，牛羊既飽各知家。", "人生擾擾成底事，馬上哦詩日又斜。"]'),
('2fdbf61b-fd75-4228-8c8d-57bc539059d2','道中寒食  其一','陳與義','宋','宋诗','song-poetry','','[]','飛絮春猶冷，離家食更寒。',48,'全唐诗/poet.song.100000.json','["飛絮春猶冷，離家食更寒。", "能供幾歲月，不辦了悲歡。", "刺史蒲萄酒，先生苜蓿盤。", "一官違壯節，百慮集征鞍。"]'),
('321ca2b0-2ae5-4d22-b0ea-3b603e943d01','道中寒食  其二','陳與義','宋','宋诗','song-poetry','','[]','斗粟淹吾駕，浮雲笑此生。',48,'全唐诗/poet.song.100000.json','["斗粟淹吾駕，浮雲笑此生。", "有酒酬歲月，無夢到功名。", "客裏逢歸雁，愁邊有亂鶯。", "楊花不解事，更作倚風輕。"]'),
('7dde9cfc-a619-4ba6-b8b5-ee7cc47a598c','龍門','陳與義','宋','宋诗','song-poetry','','[]','不到龍門十載强，斷崖依舊挂斜陽。',64,'全唐诗/poet.song.100000.json','["不到龍門十載强，斷崖依舊挂斜陽。", "金銀佛寺浮佳氣，花木禪房接上方。", "羸馬暫來還徑去，流鶯多處最難忘。", "老僧不作留人意，看水看山白髮長。"]'),
('cc507f3d-9ccd-43fd-a71e-f5dbf5bfe59d','次韻謝心老以緣事至魯山','陳與義','宋','宋诗','song-poetry','','[]','禪師瓶貯幾多空，欲問以書無去鴻。',64,'全唐诗/poet.song.100000.json','["禪師瓶貯幾多空，欲問以書無去鴻。", "魯縣人迎波若杖，天寧樹起吉祥風。", "荒山春色篇章裏，快士交情筆硯中。", "一日塵沙雙碧眼，歸時應與去時同。"]'),
('b566fddd-3779-4ea0-ba97-ea17660c100f','友人惠石兩峰巉然取杜子美玉山高並兩峰寒之句名曰小玉山','陳與義','宋','宋诗','song-poetry','','[]','舊喜看書今不看，且留雙眼向孱顔。',64,'全唐诗/poet.song.100000.json','["舊喜看書今不看，且留雙眼向孱顔。", "從來作夢大槐國，此去藏身小玉山。", "暮靄朝曦一生了，高天厚地兩峰閑。", "九華詩句喧寰宇，細比真形伯仲間。"]'),
('61397717-547f-4011-b477-83862c8f9636','秋夜','陳與義','宋','宋诗','song-poetry','','[]','中庭淡月照三更，白露洗空河漢明。',32,'全唐诗/poet.song.100000.json','["中庭淡月照三更，白露洗空河漢明。", "莫遣西風吹葉盡，却愁無處著秋聲。"]'),
('b1753e42-6f12-45d6-863b-eeb29af41238','跋外祖存誠子帖','陳與義','宋','宋诗','song-poetry','','[]','亂眼龍蛇起平陸，前身羲獻已黄墟。',32,'全唐诗/poet.song.100000.json','["亂眼龍蛇起平陸，前身羲獻已黄墟。", "客來空認袁公額，淚盡慚無楊惲書。"]'),
('1ea2d7c3-74be-43bf-bb56-a57ebd4654e6','詠蟹','陳與義','宋','宋诗','song-poetry','','[]','量才不數制魚額，四海神交顧建康。',32,'全唐诗/poet.song.100000.json','["量才不數制魚額，四海神交顧建康。", "但見橫行疑長躁，不知公子實無腸。"]'),
('2c578e98-a328-4425-99e5-75ba1f470af5','留別心老','陳與義','宋','宋诗','song-poetry','','[]','老心霜下松，名與隆公齊。',96,'全唐诗/poet.song.100000.json','["老心霜下松，名與隆公齊。", "人物北斗南，佛事東院西。", "平生四海脚，不踏四海泥。", "晚說汝州禪，飽啖天寧虀。", "夢中與我遇，相扶兩枯藜。", "每見眼自明，不復煩金篦。", "却從夢中別，未免意慘汙。", "它時訪生死，林深路應迷。"]'),
('bf8212ac-aefa-455c-9039-b8d8299397ec','中牟道中二首  其一','陳與義','宋','宋诗','song-poetry','','[]','雨意欲成還未成，歸雲却作伴人行。',32,'全唐诗/poet.song.100000.json','["雨意欲成還未成，歸雲却作伴人行。", "依然壤郭中牟縣，千尺浮屠管送迎。"]'),
('e1473b47-55de-4ed4-b0bb-f8943f6bed4d','中牟道中二首  其二','陳與義','宋','宋诗','song-poetry','','[]','楊柳招人不待媒，蜻蜓近馬忽相猜。',32,'全唐诗/poet.song.100000.json','["楊柳招人不待媒，蜻蜓近馬忽相猜。", "如何得與凉風約，不共塵沙一并來。"]'),
('7a67d1af-ab60-4a0f-94ef-4ab8b668a2a2','秋雨','陳與義','宋','宋诗','song-poetry','','[]','塵起一月憂無禾，瓦鳴三日憂雨多。',114,'全唐诗/poet.song.100000.json','["塵起一月憂無禾，瓦鳴三日憂雨多。", "書生重口輕肝腎，不如牆角蚯蚓方長哦。", "少昊行秋龍洒道，風作萬木皆商歌。", "病夫强起開戶立，萬箇銀竹驚森羅。", "人間偉觀如此少，倚杖不覺泥及靴。", "菊叢欹倒未足道，老境知奈梧桐何。", "是事且置當務本，菜圃已添三萬科。"]'),
('23c353d5-02b7-4dd4-9bbf-55a8edeaafe7','中秋不見月','陳與義','宋','宋诗','song-poetry','','[]','去年中秋端正月，照我霑襟萬條血。',128,'全唐诗/poet.song.100000.json','["去年中秋端正月，照我霑襟萬條血。", "姮娥留笑待今年，凈洗金觥對銀闕。", "高唐妬婦心不閑，招得封姨同作難。", "豈惟恨滿月宮裏，腸斷西山吳綵鸞。", "却疑周生懷月去，待到三更黑如故。", "人間今乏趙知微，無復清遊繼天柱。", "南枝烏鵲不敢譁，倚杖三嘆風枝斜。", "明年强健更相約，會見林間金背蟆。"]'),
('abbe63af-ec85-48f3-a30e-350c77308f0d','九日賞菊','陳與義','宋','宋诗','song-poetry','','[]','黄花不負秋，與秋作光輝。',96,'全唐诗/poet.song.100000.json','["黄花不負秋，與秋作光輝。", "夜霜猶作惡，朝日爲解圍。", "今晨豈重九，節意入幽菲。", "孤芳擅天地，衆卉亦已微。", "殷勤黄金靨，照耀白板扉。", "沽酒欲壽花，孔兄與我違。", "清坐絕省事，未覺此計非。", "夕英豈不腴，騷人自難肥。"]'),
('b99cfe0b-26dd-4c63-9d18-b559b01a1da5','遊葆真池上','陳與義','宋','宋诗','song-poetry','','[]','牆厚不盈咫，人間隔蓬萊。',96,'全唐诗/poet.song.100000.json','["牆厚不盈咫，人間隔蓬萊。", "高柳喚客遊，我輩御風來。", "坐久落日盡，澹澹池光開。", "白雲行水中，一笑三徘徊。", "鴨兒輕歲月，不受急景催。", "試作弄篙驚，徐去首不迴。", "無心與境接，偶遇信悠哉。", "再來知何似，有句端難裁。"]'),
('c7817167-c131-4d05-93dd-19110897ff70','次韻王堯明郊祀顯相之作','陳與義','宋','宋诗','song-poetry','','[]','奏書初不待衡譚，奠璧都南萬玉參。',64,'全唐诗/poet.song.100000.json','["奏書初不待衡譚，奠璧都南萬玉參。", "黄屋倚霄明半夜，紫壇承月眩諸龕。", "聲喧大呂初終六，影動玄圭陟降三。", "可是天公須羯鼓，已回寒馭作春酣。"]'),
('221335a7-0d5d-407f-9dd1-270dc2309205','端門聽赦詠雪','陳與義','宋','宋诗','song-poetry','','[]','雲葉垂雞竿，雪花眩鸞旗。',120,'全唐诗/poet.song.100000.json','["雲葉垂雞竿，雪花眩鸞旗。", "一天豐年意，飄入萬壽巵。", "茫茫玉妃班，影亂千官儀。", "也知樓頭喜，舞態方自持。", "教坊可憐女，面赤婆娑時。", "天公一笑罷，未覺風來遲。", "小儒驚偉觀，到笏不敢吹。", "歸家得細說，平分遺妻兒。", "茅檐玉三尺，坐玩可樂饑。", "生活太冷淡，侑以一篇詩。"]'),
('6daf31c8-b16c-4d16-a378-a05041bee0e5','遊玉仙觀以春風吹倒人爲韻得吹字','陳與義','宋','宋诗','song-poetry','','[]','清遊天不借，破帽沙疾吹。',96,'全唐诗/poet.song.100000.json','["清遊天不借，破帽沙疾吹。", "下馬榱桷鳴，未恨十里陂。", "風餘檐鐸語，坐定爐煙遲。", "新春碧瓦麗，古意喬木奇。", "黄冠見客喜，此士定不羈。", "但愧城中塵，浼子青松枝。", "人間爭奪醜，我亦寄枯棋。", "輸贏共一笑，馬影催歸時。"]'),
('4fb267fa-f871-4ce7-89bc-d82626cc26d8','路歸馬上再賦','陳與義','宋','宋诗','song-poetry','','[]','偶然思玉仙，便到玉仙遊。',72,'全唐诗/poet.song.100000.json','["偶然思玉仙，便到玉仙遊。", "興盡未及郭，玉仙失回頭。", "成毀俱一念，今昔浪百憂。", "未知橫笛子，亦解此意不。", "春風所經過，水色如潑油。", "垂鞭見落日，世事劇悠悠。"]'),
('037a7925-f01d-4871-a38c-611f49456631','來禽花','陳與義','宋','宋诗','song-poetry','','[]','來禽花高不受折，滿意清明好時節。',64,'全唐诗/poet.song.100000.json','["來禽花高不受折，滿意清明好時節。", "人間風日不貸春，昨暮煙脂今日雪。", "舍東蕪菁滿眼黄，胡蝶飛去專斜陽。", "妍嗤都無十日事，付與梧桐一夏凉。"]'),
('155d7a58-cd02-49d8-b442-8c1f9cafba1e','放慵','陳與義','宋','宋诗','song-poetry','','[]','暖日薰楊柳，濃春醉海棠。',48,'全唐诗/poet.song.100000.json','["暖日薰楊柳，濃春醉海棠。", "放慵真有味，應俗苦相妨。", "宦拙從人笑，交疏得自藏。", "雲移穩扶杖，燕坐獨焚香。"]'),
('4d4a5dca-3418-4915-89c6-df3d340dd740','清明二絕  其一','陳與義','宋','宋诗','song-poetry','','[]','街頭女兒雙髻鴉，隨蜂趁蝶學夭邪。',32,'全唐诗/poet.song.100000.json','["街頭女兒雙髻鴉，隨蜂趁蝶學夭邪。", "東風也作清明節，開遍來禽一樹花。"]'),
('8a5fac5a-4870-4662-a0c9-5a89b5bf7331','清明二絕  其二','陳與義','宋','宋诗','song-poetry','','[]','卷地風拋市井聲，病夫危坐了清明。',32,'全唐诗/poet.song.100000.json','["卷地風拋市井聲，病夫危坐了清明。", "一簾晚日看收盡，楊柳微風百媚生。"]'),
('390f07a6-f46b-4493-b67f-a3e5e15237da','春日  其一','陳與義','宋','宋诗','song-poetry','','[]','朝來庭樹有鳴禽，紅綠扶春上遠林。',32,'全唐诗/poet.song.100000.json','["朝來庭樹有鳴禽，紅綠扶春上遠林。", "忽有好詩生眼底，安排句法已難尋。"]'),
('d1e73d7a-b543-4a46-b897-4b5aa97bd37a','春日  其二','陳與義','宋','宋诗','song-poetry','','[]','憶看梅雪縞中庭，轉眼桃梢無數青。',32,'全唐诗/poet.song.100000.json','["憶看梅雪縞中庭，轉眼桃梢無數青。", "萬事一身雙鬢髮，竹床欹卧數窗櫺。"]'),
('60469651-b783-482a-adef-77d3186f5185','夏日集葆真池上以綠陰生晝靜賦詩得靜字','陳與義','宋','宋诗','song-poetry','','[]','清池不受暑，幽討起予病。',144,'全唐诗/poet.song.100000.json','["清池不受暑，幽討起予病。", "長安車轍邊，有此荷萬柄。", "是身雖可懶，共寄無盡興。", "魚遊水底凉，鳥宿林間靜。", "談餘日亭午，樹影一時正。", "清風不負客，意重百金贈。", "聊將兩鬢蓬，起照千丈鏡。", "微波喜摇人，小立待其定。", "梁王今何許，柳色幾衰盛。", "人生行樂耳，詩律已其剩。", "邂逅一樽酒，它年五君詠。", "重期踏月來，夜半嘯煙艇。"]'),
('6008ad12-adab-4a07-901f-41de1f3f2159','遊慧林寺以三峽炎蒸定有無爲韻得定字是日欲逃暑閣下而守閣童子持不可','陳與義','宋','宋诗','song-poetry','','[]','我如東郊馬，欹側甘瘦病。',120,'全唐诗/poet.song.100000.json','["我如東郊馬，欹側甘瘦病。", "今晨舉足輕，起行得幽勝。", "撫窗喚懶融，槁面初出定。", "眼中無長物，坐久爐煙正。", "門前幾烏帽，來往送朝暝。", "豈知帽影邊，有地白日靜。", "寶閣陰肅肅，童子色不令。", "年來惜違人，一笑取歸徑。", "願言捐何肉，終歲奉清凈。", "檐鐸豈印吾，出門有餘聽。"]'),
('1627d749-f722-48bf-adbe-d61251177e5b','道山宿直','陳與義','宋','宋诗','song-poetry','','[]','離離樹子鵲驚飛，獨倚枯筇無限時。',64,'全唐诗/poet.song.100000.json','["離離樹子鵲驚飛，獨倚枯筇無限時。", "千丈虛廊貯明月，十分奇事更新詩。", "人間路絕窗扉語，天上雲空閣影移。", "遥想王戎燭下算，百年辛苦一生癡。"]'),
('b8328c3f-b4af-453c-9923-1b270bee5257','雨晴','陳與義','宋','宋诗','song-poetry','','["\u5199\u96e8", "\u6292\u60c5", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u96e8"]','天缺西南江面清，纖雲不動小灘橫。',64,'全唐诗/poet.song.100000.json','["天缺西南江面清，纖雲不動小灘橫。", "牆頭語鵲衣猶濕，樓外殘雷氣未平。", "盡取微凉供穩睡，急搜奇句報新晴。", "今宵絕勝無人共，卧看星河盡意明。"]'),
('d8656fc0-b4b4-4455-b814-20925d8a7501','十月','陳與義','宋','宋诗','song-poetry','','[]','十月天公作許悲，負霜鴻雁不停飛。',64,'全唐诗/poet.song.100000.json','["十月天公作許悲，負霜鴻雁不停飛。", "莽連萬里雲一去，紅盡千林秋徑歸。", "病夫搜句了節序，小齋焚香無是非。", "睡過三冬莫開戶，北風不貸芰荷衣。"]'),
('4e1af516-3d06-4c7c-a54a-bf02198140bf','漫郎','陳與義','宋','宋诗','song-poetry','','[]','漫郎功業大悠然，拄笏看山了十年。',64,'全唐诗/poet.song.100000.json','["漫郎功業大悠然，拄笏看山了十年。", "黑白半頭明鏡裏，丹青千樹惡風前。", "星霜屢費驚人句，天地元須使鬼錢。", "踏破九州無一事，只今分付結跏禪。"]'),
('3f99c656-78df-49fb-9839-89ae4bef3ceb','柳絮','陳與義','宋','宋诗','song-poetry','','[]','柳送腰支日幾回，更教飛絮舞樓臺。',32,'全唐诗/poet.song.100000.json','["柳送腰支日幾回，更教飛絮舞樓臺。", "顛狂忽作高千丈，風力微時穩下來。"]'),
('bc6e8770-5335-49cf-a891-4aa03ea74b5c','侯處士女挽詞','陳與義','宋','宋诗','song-poetry','','[]','疇昔翁才比太師，固應生女作門楣。',64,'全唐诗/poet.song.100000.json','["疇昔翁才比太師，固應生女作門楣。", "人間似夢風旌出，佛子何之宰樹悲。", "五百裞金空繐帳，三千車乘忽荒陂。", "它年不共江流去，突兀張林婦德碑。"]'),
('d08dc613-dd11-4936-bab4-7182e0549342','登天清寺塔','陳與義','宋','宋诗','song-poetry','','[]','爲眼不計脚，攀梯受微辛。',120,'全唐诗/poet.song.100000.json','["爲眼不計脚，攀梯受微辛。", "半天拍闌干，驚倒地上人。", "風從萬里來，老夫方岸巾。", "荒荒春浮木，浩浩空納塵。", "夕陽差萬瓦，赤鯉欲動鱗。", "須臾暮煙合，青魴映奫淪。", "萬化本日馳，高處覺眼新。", "借問龕中仙，坐穩今幾辰。", "俗子書滿壁，澹然不生嗔。", "唯有太行山，修供獨殷勤。"]'),
('98dc6280-04bd-494a-9cdf-a0da0381e9b0','浴室觀雨以催詩走群龍爲韻得走字','陳與義','宋','宋诗','song-poetry','','[]','微雲生屋脊，欹枕看培塿。',144,'全唐诗/poet.song.100000.json','["微雲生屋脊，欹枕看培塿。", "崔嵬亂一瞬，泰華入搔首。", "須臾萬銀竹，壯觀驚戶牖。", "摧擊竟自碎，映空白煙走。", "餘飚送未了，日色在井口。", "去冬三寸雪，寒日澹相守。", "商量細細融，未覺經旬久。", "誰能料天工，辦此穎脫手。", "一凉滿天地，平分到庭柳。", "葉端嘯餘風，送我一杯酒。", "畫屏題細字，盡記同來友。", "俗眼之所遺，此事當不朽。"]'),
('767361b9-01f6-4167-9938-60d034ce5ef6','夏至日與太學同舍會葆真二首  其一','陳與義','宋','宋诗','song-poetry','','[]','微官有閥閱，三賦池上詩。',84,'全唐诗/poet.song.100000.json','["微官有閥閱，三賦池上詩。", "林密知夏深，仰看天離離。", "官忙負遠興，觴至及良時。", "荷氣夜來雨，百鳥清晝遲。", "微風不動蘋，坐看水色移。", "門前爭奪場，取歡不償悲。", "欲歸未得去，日暮多黄鸝。"]'),
('8b5b9a73-e318-4a28-9deb-d7c0a54e8e43','夏至日與太學同舍會葆真二首  其二','陳與義','宋','宋诗','song-poetry','','[]','明波影千柳，紺屋朝萬荷。',60,'全唐诗/poet.song.100000.json','["明波影千柳，紺屋朝萬荷。", "物新感節移，意定覺景多。", "遊魚聚亭影，鏡面散微渦。", "江湖豈在遠，所欠雨一蓑。", "忽看带箭禽，三嘆無奈何。"]'),
('e50261cd-1537-496f-8582-cbe8da975ee4','翁高郵挽詩','陳與義','宋','宋诗','song-poetry','','[]','萬里功名路，三生翰墨身。',48,'全唐诗/poet.song.100000.json','["萬里功名路，三生翰墨身。", "暮年銅虎重，浮世石羊新。", "天地慳豪傑，山川泣吏民。", "空傳四十誄，竟不識斯人。"]'),
('e8f2d4ee-a7a0-4bc9-984c-30bb82d65177','秋試院將出書所寓窗','陳與義','宋','宋诗','song-poetry','','[]','門前柿葉已堪書，弄鏡燒香聊自娛。',32,'全唐诗/poet.song.100000.json','["門前柿葉已堪書，弄鏡燒香聊自娛。", "百世窗明窗暗裏，題詩不用著工夫。"]'),
('e39ca4b2-e3d1-42e0-8138-b187898328aa','秋日','陳與義','宋','宋诗','song-poetry','','[]','琢句不成添鬢絲，且搘筇杖看雲移。',32,'全唐诗/poet.song.100000.json','["琢句不成添鬢絲，且搘筇杖看雲移。", "槐花落盡全林綠，光景渾如初夏時。"]'),
('377dc537-e763-4d6c-a6cf-dddcd1bf8ae9','夏日','陳與義','宋','宋诗','song-poetry','','[]','赤日可中庭，樹影歛不開。',120,'全唐诗/poet.song.100000.json','["赤日可中庭，樹影歛不開。", "燭龍未肯忙，一步九徘徊。", "夢中驚耳鳴，欲覺聞遠雷。", "屋山奇峰起，欹枕看雲來。", "變化信難料，轉頭失崔嵬。", "雖然不成雨，風起亦快哉。", "槐葉萬背白，少振十日埃。", "白團豈辦此，擲去羞薄才。", "蜻蜓泊牆陰，近人故多猜。", "牆西豈更熱，已去却飛迴。"]'),
('bd271364-f190-41f3-af9d-0a50253226c1','送王周士赴發運司屬官','陳與義','宋','宋诗','song-poetry','','[]','寧食三斗塵，有手不揖無詩人。',108,'全唐诗/poet.song.100000.json','["寧食三斗塵，有手不揖無詩人。", "寧飲三斗醋，有耳不聽無味句。", "牆東草深蘭發薰，君先夢我我夢君。", "小窗誦詩燈花喜，窗外北風怒未已。", "書生得句勝得官，風其少止盡人歡。", "五更月暈一千丈，明日君當泛淮浪。", "去去三十六策中，第一買酒鏖北風。"]'),
('592175aa-49f7-4727-99f4-431ba4449afc','試院春晴','陳與義','宋','宋诗','song-poetry','','[]','今日天氣佳，忽思賦新詩。',96,'全唐诗/poet.song.100000.json','["今日天氣佳，忽思賦新詩。", "春光挾晴色，併上桃花枝。", "白雲浩浩去，天色青陸離。", "餘霏遇晚日，彩翠紛新奇。", "天公出變化，驚倒癡絕兒。", "逶迤或耐久，美好固暫時。", "平生一枝筇，穩處念力衰。", "澹然意已足，却赴青燈期。"]'),
('fdb42c0f-c674-4273-a9f5-e47d179cbacb','試院書懷','陳與義','宋','宋诗','song-poetry','','[]','細讀平安字，愁邊失歲華。',48,'全唐诗/poet.song.100000.json','["細讀平安字，愁邊失歲華。", "疏疏一簾雨，淡淡滿枝花。", "投老詩成癖，經春夢到家。", "茫然十年事，倚杖數栖鴉。"]'),
('b435259d-aa95-4829-8b2d-02c5c6177ad9','次韻何文縝題顔持約畫水墨梅花二首  其一','陳與義','宋','宋诗','song-poetry','','[]','窗間光影晚來新，半幅溪藤萬里春。',32,'全唐诗/poet.song.100000.json','["窗間光影晚來新，半幅溪藤萬里春。", "從此不貪江路好，剩拚心力喚真真。"]'),
('76e45d0c-e6cb-4513-92cd-7a4396761f80','次韻何文縝題顔持約畫水墨梅花二首  其二','陳與義','宋','宋诗','song-poetry','','[]','奪得斜枝不放歸，倚窗承月看熹微。',32,'全唐诗/poet.song.100000.json','["奪得斜枝不放歸，倚窗承月看熹微。", "墨池雪嶺春俱好，付與詩人說是非。"]'),
('ea553ee4-9837-43f3-924c-20693534afa4','又六言','陳與義','宋','宋诗','song-poetry','','[]','未央宮裏紅杏，羯鼓三聲打開。',28,'全唐诗/poet.song.100000.json','["未央宮裏紅杏，羯鼓三聲打開。", "大庾嶺頭梅萼，管城呼上屏來。"]'),
('c7704c59-f78a-40cb-a350-5d25709ee817','題持約畫軸','陳與義','宋','宋诗','song-poetry','','[]','日落川更闊，煙生山欲浮。',24,'全唐诗/poet.song.100000.json','["日落川更闊，煙生山欲浮。", "舟中有閑地，載我得同遊。"]'),
('088dd560-48b4-453a-8e94-2555c8d09cc5','爲陳介然題持約畫','陳與義','宋','宋诗','song-poetry','','[]','層層水落白灘生，萬里征鴻小作程。',32,'全唐诗/poet.song.100000.json','["層層水落白灘生，萬里征鴻小作程。", "日暮微風過荷葉，陂南陂北聽秋聲。"]'),
('1b1c3910-fab7-4833-9d9a-f6539b447ec8','寄題兖州孫大夫絕塵亭二首  其一','陳與義','宋','宋诗','song-poetry','','[]','不讀遠遊賦，放懷茲地宜。',60,'全唐诗/poet.song.100000.json','["不讀遠遊賦，放懷茲地宜。", "雲山繞窗戶，萬態爭紛披。", "世故日已遠，風水方逶迤。", "倚杖夜來雨，東山煙散遲。", "人間許長史，不與此心期。"]'),
('b7a9295a-c45f-4ffa-9113-577644ad2c7a','寄題兖州孫大夫絕塵亭二首  其二','陳與義','宋','宋诗','song-poetry','','[]','境空納浩蕩，日暮生泬寥。',60,'全唐诗/poet.song.100000.json','["境空納浩蕩，日暮生泬寥。", "竹聲池邊起，欲斷還蕭蕭。", "丈人方微吟，萬象各動摇。", "林間光景异，月出東山椒。", "門前誰剝啄，已逝不須邀。"]'),
('39841348-6de7-4d53-a056-34a0b38405a7','梅花兩絕句  其一','陳與義','宋','宋诗','song-poetry','','[]','客行滿山雪，香處是梅花。',24,'全唐诗/poet.song.100000.json','["客行滿山雪，香處是梅花。", "丁寧明月夜，認取影橫斜。"]'),
('4e0dea20-0024-41fa-b792-bbebe8e2f841','梅花兩絕句  其二','陳與義','宋','宋诗','song-poetry','','[]','曉天青脈脈，玉面立疏籬。',24,'全唐诗/poet.song.100000.json','["曉天青脈脈，玉面立疏籬。", "山中爾許樹，獨自費人詩。"]'),
('58d73501-ed0d-4c2f-9102-315b5334bda3','送善相僧超然歸廬山','陳與義','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','九疊峰前遠法師，長安塵染坐禪衣。',64,'全唐诗/poet.song.100000.json','["九疊峰前遠法師，長安塵染坐禪衣。", "十年依舊雙瞳碧，萬里今持一笑歸。", "鼠目向來吾自了，龜腸從與世相違。", "酒酣更欲煩公說，黄葉漫山錫杖飛。"]'),
('71e47051-f937-4d1e-8adf-f8f4a0541732','休日早起','陳與義','宋','宋诗','song-poetry','','[]','曨曨窗影來，稍稍禽聲集。',72,'全唐诗/poet.song.100000.json','["曨曨窗影來，稍稍禽聲集。", "開門知有雨，老樹半身濕。", "劇談了無味，遠遊非所急。", "蒲團著身寬，安取萬戶邑。", "開鏡白雲渡，捲簾秋光入。", "飽受今日閑，明朝復羈縶。"]'),
('8bc233fb-a8b9-49df-bb90-8558d10718b7','夏夜','陳與義','宋','宋诗','song-poetry','','[]','幽窗報夕霽，微月在屋橑。',72,'全唐诗/poet.song.100000.json','["幽窗報夕霽，微月在屋橑。", "手中白羽扇，共此夜寥寥。", "六月天正碧，三更樹微摇。", "緬懷山中景，茲夕感路遥。", "長嘯送行雲，可望不可招。", "夜闌林光發，白露濡青條。"]'),
('e5bf8553-e269-4466-9511-a011934f09cd','棋','陳與義','宋','宋诗','song-poetry','','[]','長日無公事，閑圍李遠棋。',48,'全唐诗/poet.song.100000.json','["長日無公事，閑圍李遠棋。", "傍觀真一笑，互勝不移時。", "幸未逢重霸，何妨著獻之。", "晴天散飛雹，驚動隔牆兒。"]'),
('a647c7a1-9d19-4295-97cf-9df757b56d91','與伯順飯于文緯大光出宋漢傑畫秋山','陳與義','宋','宋诗','song-poetry','','[]','焚香消午睡，開畫逢秋山。',120,'全唐诗/poet.song.100000.json','["焚香消午睡，開畫逢秋山。", "皇都馬聲中，有此四士閑。", "離離南國樹，閃閃湘水灣。", "悠悠孤鳥去，澹澹晨輝還。", "屐上十年蠟，未散腰脚頑。", "不如一詣君，坐此巖石間。", "遠峰如修眉，近峰如墮鬟。", "書生飽作祟，眼亂紛斕斑。", "一笑遺世人，聊破千載顔。", "詩成即畫記，可益不可刪。"]'),
('7a65ac6d-ee6a-4dcf-9505-47d482c548e3','九日宜春苑午憩幕中聽大光誦朱迪功詩','陳與義','宋','宋诗','song-poetry','','[]','酒酣耳熱不能歌，奈此一川黄菊何。',32,'全唐诗/poet.song.100000.json','["酒酣耳熱不能歌，奈此一川黄菊何。", "卧聽西風吹好句，老夫無恨幕生波。"]'),
('b969deec-2aff-4ba0-a17a-8b346d9fa682','冬至二首  其一','陳與義','宋','宋诗','song-poetry','','[]','少年多意氣，老去一分無。',72,'全唐诗/poet.song.100000.json','["少年多意氣，老去一分無。", "閉戶了冬至，日長添數珠。", "北風不貸節，鴻雁天南驅。", "烏帽亦何幸，七日守屋廬。", "石爐深炷火，撩亂一榻書。", "只可自怡悅，不堪寄張扶。"]'),
('ac89c3ab-f1c7-42b6-8c60-79ab36292a73','冬至二首  其二','陳與義','宋','宋诗','song-poetry','','[]','人生本是客，杜叟顧未知。',72,'全唐诗/poet.song.100000.json','["人生本是客，杜叟顧未知。", "今年我聞道，悲樂兩脫遺。", "日色如昨日，未覺墉陰遲。", "不須行年記，異代尋吾詩。", "東家窈窕娘，融蠟幻梅枝。", "但恐負時節，那知有愁時。"]'),
('a508e57e-9974-406a-ad6d-3893d5101805','西省酴醾架上殘雪可愛戲同王元忠席大光賦詩','陳與義','宋','宋诗','song-poetry','','[]','酴醾花底當年事，夜雪模糊照酒闌。',32,'全唐诗/poet.song.100000.json','["酴醾花底當年事，夜雪模糊照酒闌。", "北省今朝枝上雪，還揩病眼作花看。"]'),
('db24411a-1189-45f2-a9be-9dfc3b7903cc','對酒','陳與義','宋','宋诗','song-poetry','','[]','新詩滿眼不能裁，鳥度雲移落酒杯。',64,'全唐诗/poet.song.100000.json','["新詩滿眼不能裁，鳥度雲移落酒杯。", "官裏簿書無日了，樓頭風雨見秋來。", "是非衮衮書生老，歲月匆匆燕子回。", "笑撫江南竹根枕，一樽呼起鼻中雷。"]'),
('dbcb153a-e29e-486e-b827-dd72ae69d7e6','後三日再賦','陳與義','宋','宋诗','song-poetry','','[]','天生癭木不須栽，說與兒童是酒杯。',64,'全唐诗/poet.song.100000.json','["天生癭木不須栽，說與兒童是酒杯。", "落日留霞知我醉，長風吹月送詩來。", "一官擾擾身增病，萬事悠悠首獨回。", "不奈長安小車得，睡鄉深處作奔雷。"]'),
('43f2dfd7-98a2-4a4a-b4b1-c3480a567162','將赴陳留寄心老','陳與義','宋','宋诗','song-poetry','','[]','今日忽不樂，圖書從糾紛。',120,'全唐诗/poet.song.100000.json','["今日忽不樂，圖書從糾紛。", "不見汝州師，但見西來雲。", "長安豈無樹，憶師堂前柳。", "世路九折多，遊子百事醜。", "三年成一夢，夢破說夢中。", "來時西門雨，去日東門風。", "書到及師閑，爲我點枯筆。", "畫作謫官圖，羸驂带寒日。", "他時取歸路，千里作一程。", "飽喫殘年飯，就師聽竹聲。"]'),
('370589d7-d8ab-46af-93ff-afd4e01ce352','赴陳留二首  其一','陳與義','宋','宋诗','song-poetry','','[]','草草一夢闌，行止本難期。',120,'全唐诗/poet.song.100000.json','["草草一夢闌，行止本難期。", "歲晚陳留路，老馬三振鬐。", "自看鞭袖影，曠野日落遲。", "柳林行不盡，想見春風時。", "點點羊散村，陣陣鴻投陂。", "城中那有此，觸處皆新詩。", "舉手謝路人，醉語勿瑕疵。", "我行有官事，去作三年癡。", "遥聞辟穀仙，閱世河水湄。", "時從玩木影，政爾不憂饑。"]'),
('49244b34-d291-42f4-9b12-63a68ca9619f','赴陳留二首  其二','陳與義','宋','宋诗','song-poetry','','[]','馬上摩挲眼，出門光景新。',48,'全唐诗/poet.song.100000.json','["馬上摩挲眼，出門光景新。", "鴉鳴半陂雪，路轉一林春。", "舊歲有三日，全家無十人。", "平生鸚鵡盞，今夕最關身。"]'),
('2f2cd477-e73f-4902-a848-5c87a292124c','至陳留','陳與義','宋','宋诗','song-poetry','','[]','煙際亭亭塔，招人可得回。',48,'全唐诗/poet.song.100000.json','["煙際亭亭塔，招人可得回。", "等閑爲夢了，聞健出關來。", "日落河冰壯，天長鴻雁哀。", "平生遠遊意，隨處一徘徊。"]'),
('c941ddac-9f0c-4dbe-834a-6bd07b20c430','客裏','陳與義','宋','宋诗','song-poetry','','[]','客裏東風起，逢人只四愁。',48,'全唐诗/poet.song.100000.json','["客裏東風起，逢人只四愁。", "悠悠雜唯唯，莫莫更休休。", "窗影鳥雙度，水聲船逆流。", "一官成一集，盡付古河頭。"]'),
('377102c1-6822-4ddd-82a4-3fa43bd7b52e','初至陳留南鎮夙興赴縣','陳與義','宋','宋诗','song-poetry','','[]','五更風摇白竹扉，整冠上馬不可遲。',144,'全唐诗/poet.song.100000.json','["五更風摇白竹扉，整冠上馬不可遲。", "三家陂口雞喔喔，早於昨日朝天時。", "行雲弄月翳復吐，林間明滅光景奇。", "川原四望鬰高下，蕩摇蒼茫森陸離。", "客心忽動羣鳥起，馬影漸薄村墟移。", "須臾東方雲錦發，向來所見今難追。", "兩眼聊隨萬象轉，一官已判三年癡。", "只將乘除了吾事，推去木枕收此詩。", "寫我新篇作畫障，不須更覓丹青師。"]'),
('1a3db3aa-9669-4621-8b6c-fabac855b0db','遊八關寺後池上','陳與義','宋','宋诗','song-poetry','','[]','落日生春色，微瀾動古池。',48,'全唐诗/poet.song.100000.json','["落日生春色，微瀾動古池。", "柳林橫絕野，藜杖去尋詩。", "不有今年謫，爭成此段奇。", "殷勤雪顱老，隨客轉荒陂。"]'),
('66c95609-64f7-4e18-b72d-d9953bb83e04','種竹','陳與義','宋','宋诗','song-poetry','','[]','種竹不必高，摇綠當我楹。',120,'全唐诗/poet.song.100000.json','["種竹不必高，摇綠當我楹。", "向來三家墅，無此笙簫聲。", "皇天有老眼，爲閟十日晴。", "護我蕭蕭碧，偉事鄰翁驚。", "同林偶落此，相向意甚平。", "何須俟迷日，可笑世俗情。", "明年萬夭矯，穿地聽雷鳴。", "但恨種竹人，南山合歸耕。", "佗時夢中路，留眼記所更。", "蒼雲屯十里，不見陳留城。"]'),
('1f5218b6-d7f9-4b9b-bb1c-2a38b3124105','對酒','陳與義','宋','宋诗','song-poetry','','[]','陳留春色撩詩思，一日搜腸一百迴。',64,'全唐诗/poet.song.100000.json','["陳留春色撩詩思，一日搜腸一百迴。", "燕子初歸風不定，桃花欲動雨頻來。", "人間多待須微祿，夢裏相逢記此杯。", "白竹扉前容醉舞，煙村渺渺欠高臺。"]'),
('1128d94d-297a-43bd-a84d-32274d4f70e9','寒食','陳與義','宋','宋诗','song-poetry','','[]','草草隨時事，蕭蕭傍水門。',48,'全唐诗/poet.song.100000.json','["草草隨時事，蕭蕭傍水門。", "濃陰花照野，寒食柳圍村。", "客袂空佳節，鶯聲忽故園。", "不知何處笛，吹恨滿清尊。"]'),
('db862c64-587d-4460-ac81-2014e39fde89','再遊八關','陳與義','宋','宋诗','song-poetry','','[]','古鎮易爲客，了身一籃輿。',108,'全唐诗/poet.song.100000.json','["古鎮易爲客，了身一籃輿。", "貪遊八關寺，忘却子公書。", "青青天氣肅，澹澹春意初。", "東風經古池，滿面生紆餘。", "卯申縛壯士，人世信少娛。", "時來照茲水，點檢鬢與鬚。", "日暮登古原，微白見遠墟。", "念我遂初賦，徘徊月生裾。", "悠悠不同抱，悄悄就歸途。"]'),
('d7c25b77-ac35-4bb4-a982-098b855e2adb','感懷','陳與義','宋','宋诗','song-poetry','','[]','少日爭名翰墨場，只今扶杖送斜陽。',64,'全唐诗/poet.song.100000.json','["少日爭名翰墨場，只今扶杖送斜陽。", "青青草木浮元氣，渺渺山河接故鄉。", "作吏不妨三折臂，搜詩空費九迴腸。", "子房與我同羈旅，世事千般酒一觴。"]'),
('8c47fb3a-649a-4eed-b398-d63beb1212b0','竇園醉中前後五絕句  其一','陳與義','宋','宋诗','song-poetry','','[]','東風吹雨小寒生，楊柳飛花亂晚晴。',32,'全唐诗/poet.song.100000.json','["東風吹雨小寒生，楊柳飛花亂晚晴。", "客子從今無可恨，竇家園裏有鶯聲。"]'),
('a82c60b6-3c31-4225-acf6-34c134261399','竇園醉中前後五絕句  其二','陳與義','宋','宋诗','song-poetry','','[]','海棠脈脈要詩催，日暮紫綿無數開。',32,'全唐诗/poet.song.100000.json','["海棠脈脈要詩催，日暮紫綿無數開。", "欲識此花奇絕處，明朝有雨試重來。"]'),
('e8679da7-ee66-4f64-b30b-36c207eab810','竇園醉中前後五絕句  其三','陳與義','宋','宋诗','song-poetry','','[]','不見海棠相似人，空題詩句滿花身。',32,'全唐诗/poet.song.100000.json','["不見海棠相似人，空題詩句滿花身。", "酒闌却度荒陂去，驅使風光又一春。"]'),
('e152436b-cc47-419e-8c26-78e46eea52b1','竇園醉中前後五絕句  其四','陳與義','宋','宋诗','song-poetry','','[]','三月碧桃驚動人，滿園光景一時新。',32,'全唐诗/poet.song.100000.json','["三月碧桃驚動人，滿園光景一時新。", "剩傾老子樽中玉，折盡殘枝不要春。"]'),
('2a780b3c-cdee-4f05-904c-d8468e3034c7','竇園醉中前後五絕句  其五','陳與義','宋','宋诗','song-poetry','','[]','一樽相屬莫辭空，報答今朝吹面風。',32,'全唐诗/poet.song.100000.json','["一樽相屬莫辭空，報答今朝吹面風。", "自唱新詩與明月，碧桃開盡曲聲中。"]'),
('124ce066-a95e-4a42-a4f0-8b8b3d2eb7b5','雨','陳與義','宋','宋诗','song-poetry','','[]','沙岸殘春雨，茅檐古鎮官。',48,'全唐诗/poet.song.100000.json','["沙岸殘春雨，茅檐古鎮官。", "一時花带淚，萬里客憑欄。", "日晚薔薇重，樓高燕子寒。", "惜無陶謝手，盡力破憂端。"]'),
('8ca52703-ce1e-47a6-80ae-063af97bbce9','食筍','陳與義','宋','宋诗','song-poetry','','[]','竹君家多材，楚楚皆席珍。',96,'全唐诗/poet.song.100000.json','["竹君家多材，楚楚皆席珍。", "成行著錦袍，玉色映市人。", "惠然集吾宇，老眼檐光新。", "麯生亦稅駕，共慰藜藿貧。", "不待月與影，三人宛相親。", "可憐管城子，頭禿事苦辛。", "按譜雖同宗，聞道隔幾塵。", "詩成聊使寫，一笑驚比鄰。"]'),
('d2372d04-2322-4cc2-b229-264a2e40a2f2','初夏遊八關寺','陳與義','宋','宋诗','song-poetry','','[]','閉門睡過春，出門綠滿城。',72,'全唐诗/poet.song.100000.json','["閉門睡過春，出門綠滿城。", "八關池上柳，絮罷但藏鶯。", "世故劇千蝟，今朝此閑行。", "草木隨時好，客恨終難平。", "寺有石壁勝，詩無康樂聲。", "扶鞍不得上，新月水中生。"]'),
('3c2bc2df-3c9f-4156-b35f-512c6f805b83','題酒務壁','陳與義','宋','宋诗','song-poetry','','[]','野馬本不羈，無奈卯與申。',84,'全唐诗/poet.song.100000.json','["野馬本不羈，無奈卯與申。", "當時彭澤令，定是英雄人。", "客來兩繩床，客去一欠伸。", "市聲自雜沓，爐煙自輪囷。", "鶯聲時節改，杏葉雨氣新。", "佳句忽墮前，追摹已難真。", "自題西軒壁，不雜徐庾塵。"]'),
('2698f881-4179-42b2-8c0f-213067585914','秋夜詠月','陳與義','宋','宋诗','song-poetry','','[]','庭樹日日疏，稍覺夜月添。',96,'全唐诗/poet.song.100000.json','["庭樹日日疏，稍覺夜月添。", "推愁了此段，卷我三間簾。", "黄花牆陰遠，白髮露氣嚴。", "平生六尺影，隨我送凉炎。", "踏破千憂地，投老乃自嫌。", "尚想采石江，宮錦映霜蟾。", "夜半賦詩成，起舞魚龍兼。", "辦此詎難事，取快端宜廉。"]'),
('a87ce2f1-a478-4a4a-a1b0-84cfe60f7bc5','入城','陳與義','宋','宋诗','song-poetry','','[]','竹輿聲伊鴉，路轉登古原。',72,'全唐诗/poet.song.100000.json','["竹輿聲伊鴉，路轉登古原。", "孟冬郊澤曠，細水鳴蘆根。", "霧收浮屠立，天闊鴻雁奔。", "平生厭喧鬧，快意三家村。", "思生長林內，故園歸不存。", "欲爲唐衢哭，聲出且復吞。"]'),
('417a0683-e488-4c5c-a9be-42f1b5406192','夜步隄上三首  其一','陳與義','宋','宋诗','song-poetry','','[]','世故生白髮，意行無與期。',60,'全唐诗/poet.song.100000.json','["世故生白髮，意行無與期。", "平生木上座，臨老始相知。", "月中沙岸永，歲暮河流遲。", "留侯廟前柳，葉盡空離離。", "百年信難料，剩賦奇絕詩。"]'),
('9ac5d78a-852a-40a0-b226-1af0a095f68b','夜步隄上三首  其二','陳與義','宋','宋诗','song-poetry','','[]','人間睡聲起，幽子方獨步。',60,'全唐诗/poet.song.100000.json','["人間睡聲起，幽子方獨步。", "倚杖看白雲，亭亭水中度。", "十月雁背高，三更河流去。", "物生各擾擾，念此煎百慮。", "聊將憂世心，數遍橋西樹。"]'),
('750ebb73-de9e-4a21-aa58-244d2d5675c9','夜步隄上三首  其三','陳與義','宋','宋诗','song-poetry','','[]','旋買青芒鞋，去踏沙頭月。',60,'全唐诗/poet.song.100000.json','["旋買青芒鞋，去踏沙頭月。", "爭教冠蓋地，著此影突兀。", "樹寒栖鳥動，風轉孤管發。", "月色夜夜佳，人生事如髮。", "夢中續清遊，濃露濕銀闕。"]'),
('7747e251-5f59-4aab-9060-d73193cd4908','早起','陳與義','宋','宋诗','song-poetry','','[]','竟夜聞落木，雨歇窗如新。',96,'全唐诗/poet.song.100000.json','["竟夜聞落木，雨歇窗如新。", "披衣有忙事，檐前看歸雲。", "初陽上林端，鴉背明紛紛。", "我亦迫經課，日計在一晨。", "再燒結願香，稍洗三生勤。", "羣公持世故，白髮到幽人。", "幸不識奇字，門絕車馬塵。", "誰能共此窗，竹影可與分。"]'),
('ad1a17f0-a108-4913-a04f-8d1a31e92c17','晚步','陳與義','宋','宋诗','song-poetry','','[]','手把古人書，閑讀下廣庭。',84,'全唐诗/poet.song.100000.json','["手把古人書，閑讀下廣庭。", "荒村無車馬，日落雙檜青。", "曠然神慮靜，濁俗非所寧。", "逍遥出荆扉，竚立瞻郊坰。", "須臾暮色至，野水皆晶熒。", "却步面空林，遠意更杳冥。", "停雲甚可愛，重疊如沙汀。"]'),
('a45645d4-ac84-4746-89c2-159ae7baa089','同楊運幹黄秀才村西買山藥','陳與義','宋','宋诗','song-poetry','','[]','潦縮田路寬，委蛇散腰脚。',96,'全唐诗/poet.song.100000.json','["潦縮田路寬，委蛇散腰脚。", "勝日三枝杖，村西買山藥。", "崗巒相吞去，遠木互前却。", "天陰野水明，歲暮竹籬薄。", "田翁領客意，發筐堆磊落。", "玉質緗色裘，用世乃見縛。", "屠門幾許快，夜語尋幽約。", "石鼎看雲翻，門前北風惡。"]'),
('3bc03635-abb3-4838-a264-0b129d50c11e','同二子觀取魚於竇家池以錢得數斗置驛','陳與義','宋','宋诗','song-poetry','','[]','閉戶讀書生白髮，閑向村東看魚穴。',64,'全唐诗/poet.song.100000.json','["閉戶讀書生白髮，閑向村東看魚穴。", "曾隨樹影數圓波，鐵面漁師肝肺別。", "向來癡腹負此翁，只可買放蓮溏中。", "萬事成虧等閑裏，佗年此地費雷風。"]'),
('875defa4-f54f-4758-925f-f0e0b0fb5469','早起','陳與義','宋','宋诗','song-poetry','','[]','曉寒生木枕，窗白夢難續。',96,'全唐诗/poet.song.100000.json','["曉寒生木枕，窗白夢難續。", "自起開柴扉，空庭立喬木。", "濛濛井氣上，澹澹天容肅。", "塵心忽昭曠，何異居澗谷。", "學道審不遥，忍饑差已熟。", "皇天賜豐年，菜本如白玉。", "一簡了百事，狡獪嗤顔歜。", "幽鳥行屋山，悠然寄吾目。"]'),
('c931881b-65f3-4e23-a3cc-d5c3969f7852','招張仲宗','陳與義','宋','宋诗','song-poetry','','[]','北風日日吹茅屋，幽子朝朝只地爐。',64,'全唐诗/poet.song.100000.json','["北風日日吹茅屋，幽子朝朝只地爐。", "客裏賴詩增意氣，老來唯懶是工夫。", "空庭喬木無時事，殘雪疏籬當畫圖。", "亦有張侯能共此，焚香相待莫徐驅。"]'),
('f588a35a-2dda-4b19-8e09-5c4638a0ecb8','宴坐之地籧篨覆之名曰蓬齋','陳與義','宋','宋诗','song-poetry','','[]','不須杯勺了三冬，旋作蓬齋待朔風。',32,'全唐诗/poet.song.100000.json','["不須杯勺了三冬，旋作蓬齋待朔風。", "會有打窗風雪夜，地爐孤坐策奇功。"]'),
('0d1d78c9-3a0a-4552-93b1-d51380ab9ca4','寓居劉倉廨中晚步過鄭倉臺上','陳與義','宋','宋诗','song-poetry','','[]','紗巾竹杖過荒陂，滿面東風二月時。',64,'全唐诗/poet.song.100000.json','["紗巾竹杖過荒陂，滿面東風二月時。", "世事紛紛人老易，春陰漠漠絮飛遲。", "士衡去國三間屋，子美登臺七字詩。", "草遶天西青不盡，故園歸計入支頤。"]'),
('f01e56e2-e4cd-4c2e-8f73-454e6b6c4423','八關僧房遇雨','陳與義','宋','宋诗','song-poetry','','[]','脫履坐明窗，偶至晴更適。',48,'全唐诗/poet.song.100000.json','["脫履坐明窗，偶至晴更適。", "池上風忽來，斜雨滿高壁。", "深松含歲暮，幽鳥立晝寂。", "世故方未闌，焚香破今夕。"]'),
('d41fe3f3-bfad-4a6e-9213-bb61e4181c77','贈黄家阿莘','陳與義','宋','宋诗','song-poetry','','[]','君家阿莘如白玉，呼出燈前語錄續。',64,'全唐诗/poet.song.100000.json','["君家阿莘如白玉，呼出燈前語錄續。", "可憐郎罷窮一生，只今有汝照茅屋。", "豬生十子豚復豚，阿莘明年可當門。", "階庭一笑不外索，萬事紛紛何足論。"]'),
('e3b82ba7-5b2b-4e94-989e-f57096034e62','發商水道中','陳與義','宋','宋诗','song-poetry','','[]','商水西門語，東風動柳枝。',48,'全唐诗/poet.song.100000.json','["商水西門語，東風動柳枝。", "年華入危涕，世事本前期。", "草草檀公策，茫茫杜老詩。", "山川馬前闊，不敢計歸時。"]'),
('adf0c00f-9d3b-43a4-82db-f0931191b79c','次舞陽','陳與義','宋','宋诗','song-poetry','','[]','客子寒亦行，正月固多陰。',96,'全唐诗/poet.song.100000.json','["客子寒亦行，正月固多陰。", "馬頭東風起，綠色日夜深。", "大道不敢驅，山徑費推尋。", "丈夫不逢此，何以知嶇嶔。", "行投舞陽縣，薄暮森衆林。", "古城何年缺，跋馬望日沉。", "憂世力不逮，有淚盈衣襟。", "嵯峩西北雲，想像折寸心。"]'),
('afe2bcd8-7c71-4928-8000-c2698989bc54','次南陽','陳與義','宋','宋诗','song-poetry','','[]','今日東北雲，景氣何佳哉。',96,'全唐诗/poet.song.100000.json','["今日東北雲，景氣何佳哉。", "我馬且勿驅，當有吉語來。", "春寒欺客子，滿意旗下杯。", "百年耳頻熱，萬事首不回。", "卧龍今何之，有冢今半摧。", "空餘喬木地，薄暮鴉徘徊。", "懷古視落日，愧我非長才。", "却凭破鞍去，風林生七哀。"]'),
('ff283fa8-a230-4c19-98d9-32e5917533d0','西軒寓居','陳與義','宋','宋诗','song-poetry','','[]','牢落西軒客，巡檐費獨吟。',48,'全唐诗/poet.song.100000.json','["牢落西軒客，巡檐費獨吟。", "桃花明薄暮，燕子鬧微陰。", "辛苦元吾事，淹留更此心。", "小窗隨意寫，蛇蚓起相尋。"]'),
('634ea10b-a66b-4e94-a3b3-94783510e89b','鄧州西軒書事十首  其一','陳與義','宋','宋诗','song-poetry','','[]','小儒避賊南征日，皇帝行天第一春。',32,'全唐诗/poet.song.100000.json','["小儒避賊南征日，皇帝行天第一春。", "走到鄧州無脚力，桃花初動雨留人。"]'),
('c254ab4e-7c7e-49ce-915d-0de7b332271f','鄧州西軒書事十首  其二','陳與義','宋','宋诗','song-poetry','','[]','千里空携一影來，白頭更著亂蟬催。',32,'全唐诗/poet.song.100000.json','["千里空携一影來，白頭更著亂蟬催。", "書生身世今如此，倚遍周家十二槐。"]'),
('d2258de1-4ff8-4676-8be6-54333962e708','鄧州西軒書事十首  其三','陳與義','宋','宋诗','song-poetry','','[]','瓦屋三間寬有餘，可憐小陸不同居。',32,'全唐诗/poet.song.100000.json','["瓦屋三間寬有餘，可憐小陸不同居。", "易求蘇子六國印，難覓河橋一字書。"]'),
('a8ae7da7-194f-4dc2-a2c4-d4f315ca7630','鄧州西軒書事十首  其四','陳與義','宋','宋诗','song-poetry','','[]','莫嫌啖蔗佳境遠，橄欖甜苦亦相并。',32,'全唐诗/poet.song.100000.json','["莫嫌啖蔗佳境遠，橄欖甜苦亦相并。", "都將壯節供辛苦，準擬殘年看太平。"]'),
('14a8706a-0ca9-4285-a038-8a7683c8bb6a','鄧州西軒書事十首  其五','陳與義','宋','宋诗','song-poetry','','[]','皇家卜年過周曆，變故未必非天仁。',32,'全唐诗/poet.song.100000.json','["皇家卜年過周曆，變故未必非天仁。", "東南鬼火成何事，終待胡鋒作爭臣。"]'),
('820f0b32-7f4c-4a41-8380-8beeaaada326','鄧州西軒書事十首  其六','陳與義','宋','宋诗','song-poetry','','[]','楊劉相傾建中亂，不待白首今同歸。',32,'全唐诗/poet.song.100000.json','["楊劉相傾建中亂，不待白首今同歸。", "只今將相須廉藺，五月并門未解圍。"]'),
('aaf54df5-679e-42d9-8e03-1b4b679bc17a','鄧州西軒書事十首  其七','陳與義','宋','宋诗','song-poetry','','[]','不須夜夜看太白，天地景氣今如斯。',32,'全唐诗/poet.song.100000.json','["不須夜夜看太白，天地景氣今如斯。", "始行夷狄相攻策，可惜中原見事遲。"]'),
('ed85e7f7-a71e-4f44-a7be-6b22d95fc267','鄧州西軒書事十首  其八','陳與義','宋','宋诗','song-poetry','','[]','詔書憂民十六事，父老祝君一萬年。',32,'全唐诗/poet.song.100000.json','["詔書憂民十六事，父老祝君一萬年。", "白髮書生喜無寐，從今不仕可歸田。"]'),
('7e943077-1b3a-459d-8088-c2c99829e523','鄧州西軒書事十首  其九','陳與義','宋','宋诗','song-poetry','','[]','范公深憂天下日，仁祖愛民全盛年。',32,'全唐诗/poet.song.100000.json','["范公深憂天下日，仁祖愛民全盛年。", "遺廟只今香火冷，時時風葉一騷然。"]'),
('c2500ed6-5034-4a00-b8c3-1b3439c0eb40','鄧州西軒書事十首  其一○','陳與義','宋','宋诗','song-poetry','','[]','諸葛經行有夕風，千秋天地幾英雄。',32,'全唐诗/poet.song.100000.json','["諸葛經行有夕風，千秋天地幾英雄。", "弔古不須多感慨，人生半夢半醒中。"]'),
('19acc0f8-1cb3-489d-9f42-181906e46f73','晚步順陽門外','陳與義','宋','宋诗','song-poetry','','[]','六尺枯藜了此生，順陽門外看新晴。',64,'全唐诗/poet.song.100000.json','["六尺枯藜了此生，順陽門外看新晴。", "樹連翠篠圍春晝，水泛青天入古城。", "夢裏偶來那計日，人間多事更聞兵。", "只應千載溪橋路，欠我媻姍勃窣行。"]'),
('469f819d-04c3-4181-bc0f-61059ea14386','縱步至董氏園亭三首  其一','陳與義','宋','宋诗','song-poetry','','[]','池光修竹裏，筇杖季春頭。',48,'全唐诗/poet.song.100000.json','["池光修竹裏，筇杖季春頭。", "客子愁無奈，桃花笑不休。", "百年今日勝，萬里此生浮。", "莽莽樽前事，題詩記獨遊。"]'),
('9a160796-08ca-4ba2-9f01-73a262b0ab56','縱步至董氏園亭三首  其二','陳與義','宋','宋诗','song-poetry','','[]','槐樹層層新綠生，客懷依舊不能平。',32,'全唐诗/poet.song.100000.json','["槐樹層層新綠生，客懷依舊不能平。", "自移一榻西窗下，要近叢篁聽雨聲。"]'),
('dd8474c9-9566-4af5-a101-c51cca5dc36b','縱步至董氏園亭三首  其三','陳與義','宋','宋诗','song-poetry','','[]','客子今年駝褐寬，鄧州三月始春寒。',32,'全唐诗/poet.song.100000.json','["客子今年駝褐寬，鄧州三月始春寒。", "簾鈎掛盡蒲團穩，十丈虛庭借雨看。"]'),
('606146da-be16-498f-8d71-0bdb7dd86654','海棠','陳與義','宋','宋诗','song-poetry','','[]','春雨夜有聲，連林杏花落。',72,'全唐诗/poet.song.100000.json','["春雨夜有聲，連林杏花落。", "海棠已復動，寒食豈寂寞。", "人間有此麗，赴我隔年約。", "花葉兩分明，春陰耿簾幙。", "東風吹不斷，日暮臙脂薄。", "何可無我吟，三叫恨詩惡。"]'),
('7ba6567b-8851-43e6-9597-7aa74ba9ebe5','雨中觀秉仲家月桂','陳與義','宋','宋诗','song-poetry','','[]','月桂花上雨，春歸一憑欄。',48,'全唐诗/poet.song.100000.json','["月桂花上雨，春歸一憑欄。", "東西南北客，更得幾回看。", "紅衿映肉色，薄暮無乃寒。", "園中如許樹，獨覺賦詩難。"]'),
('1e6b3f72-48c8-4798-80a1-f289ee4d3c19','香林四首  其一','陳與義','宋','宋诗','song-poetry','','[]','絕愛公家花氣新，一林清露百般春。',32,'全唐诗/poet.song.100000.json','["絕愛公家花氣新，一林清露百般春。", "是中宴坐應容我，只恐微風喚起人。"]'),
('66e51621-3b54-4479-86f6-6b8f95461b88','香林四首  其二','陳與義','宋','宋诗','song-poetry','','[]','丈人延客非俗物，百和香中進一杯。',32,'全唐诗/poet.song.100000.json','["丈人延客非俗物，百和香中進一杯。", "乞取齊奴錦步障，與春遮斷曉風來。"]'),
('17a4ec18-32e8-45cb-89b5-3f5659bd3e55','香林四首  其三','陳與義','宋','宋诗','song-poetry','','[]','誰見繁香度牖時，碧天殘月映花枝。',32,'全唐诗/poet.song.100000.json','["誰見繁香度牖時，碧天殘月映花枝。", "固應撩我題新句，壓倒韋郎宴寢詩。"]'),
('4ed2c477-65db-4047-be1f-6e5752b4fbd7','香林四首  其四','陳與義','宋','宋诗','song-poetry','','[]','簡齋居士不飲酒，一入香林更不醒。',32,'全唐诗/poet.song.100000.json','["簡齋居士不飲酒，一入香林更不醒。", "驅使小詩酬曉露，絕勝辛苦廣騷經。"]'),
('c585b72e-835c-4782-96fc-b93d80ae16f9','題簡齋','陳與義','宋','宋诗','song-poetry','','[]','我窗三尺餘，可以閱晦明。',96,'全唐诗/poet.song.100000.json','["我窗三尺餘，可以閱晦明。", "北省雖巨麗，無此風竹聲。", "不著散花女，而况使鬼兄。", "世間多歧路，居士繩床平。", "未知阮遥集，幾屐了平生。", "領軍一屋鞋，千載笑絕纓。", "槐陰自入戶，知我喜新晴。", "覓句方未了，簡齋真虛名。"]'),
('c07fd678-e6e1-44b5-a9c9-0baf90e072bf','印老索鈍庵詩','陳與義','宋','宋诗','song-poetry','','[]','人言融公懶，床上揖賓客。',96,'全唐诗/poet.song.100000.json','["人言融公懶，床上揖賓客。", "我來兩忘揖，團團一庵白。", "戲談鄧州禪，分食天寧麥。", "竹風亦喜我，蕭瑟至日夕。", "出家丈夫事，軒裳本兒劇。", "願香驚餘烟，世故感陳迹。", "固應師未鈍，使我不安席。", "時求一滴水，爲洗三生石。"]'),
('1c315e03-1dff-4783-87d5-8a02d9536019','春雨','陳與義','宋','宋诗','song-poetry','','[]','花盡春猶冷，羈心只自驚。',48,'全唐诗/poet.song.100000.json','["花盡春猶冷，羈心只自驚。", "孤鶯啼永晝，細雨濕高城。", "擾擾成何事，悠悠送此生。", "蛛絲閃夕霽，隨處有詩情。"]'),
('7c3b20c3-882c-4891-ad85-a5f84a545252','難老堂周元翁家','陳與義','宋','宋诗','song-poetry','','[]','城南烏聲和且都，我識丈人屋上烏。',96,'全唐诗/poet.song.100000.json','["城南烏聲和且都，我識丈人屋上烏。", "難老堂中一樽酒，不教霜雪上髭鬚。", "樊侯種梓用莫竭，丈人向來亦種德。", "挽回萬事入繩床，花竹相看有佳色。", "人生知足一飽多，當時恨我棄漁簑。", "題詩素壁蛇蚓集，五百年後公摩挲。"]'),
('363ead8b-fb12-4b35-abcf-df4b63062305','登城樓','陳與義','宋','宋诗','song-poetry','','[]','去年夢陳留，今年夢鄧州。',96,'全唐诗/poet.song.100000.json','["去年夢陳留，今年夢鄧州。", "幾夢即了我，一笑城西樓。", "新晴草木麗，落日淡欲收。", "遠川如動摇，景氣明田疇。", "百年幾憑欄，亦有似我不。", "城陰坐來失，白水光不流。", "丈夫貴快意，少住寬千憂。", "歸嫌簡齋陋，局促生白頭。"]'),
('e0ce7992-02eb-4952-b01b-618c45715124','雨','陳與義','宋','宋诗','song-poetry','','[]','忽忽忘年老，悠悠負日長。',48,'全唐诗/poet.song.100000.json','["忽忽忘年老，悠悠負日長。", "小詩妨學道，微雨好燒香。", "檐鵲移時立，庭梧滿意凉。", "此身南復北，彷佛是它鄉。"]'),
('00558e94-0bb2-4259-93e7-36563d2d1849','遊董園','陳與義','宋','宋诗','song-poetry','','[]','西園可散髮，何必賦遠遊。',120,'全唐诗/poet.song.100000.json','["西園可散髮，何必賦遠遊。", "地曠多雄風，葉聲無時休。", "幸有濟勝具，枯藜支白頭。", "平生會心處，未覺身淹留。", "散坐青石床，松意淡欲秋。", "薄雨青衆卉，深林耿微流。", "一凉天地德，物我俱夷猶。", "東北方用武，六月事戈矛。", "甲裳無乃重，腐儒故多憂。", "珍禽叫高樹，且復寄悠悠。"]'),
('a611db44-0cd3-46ad-b095-e6288e61e0ce','夏雨','陳與義','宋','宋诗','song-poetry','','[]','三伏過幾日，坐數令人癭。',72,'全唐诗/poet.song.100000.json','["三伏過幾日，坐數令人癭。", "片雲忽西行，庭樹生光景。", "須臾萬銀竹，壯觀發異境。", "天公終老手，一笑破日永。", "龍公勿憚煩，事了亦俄頃。", "修竹恬變化，依然半窗影。"]'),
('121de978-d63c-49d9-be54-345e7e841fdf','夏夜  其一','陳與義','宋','宋诗','song-poetry','','[]','閑弄玉如意，天河白練橫。',48,'全唐诗/poet.song.100000.json','["閑弄玉如意，天河白練橫。", "時無李供奉，誰識謝宣城。", "兩鶴翻明月，孤松立快晴。", "南陽半年客，此夜滿懷清。"]'),
('29ae4cf5-c792-460f-9bbc-841cf807dd58','夏夜  其二','陳與義','宋','宋诗','song-poetry','','[]','虛庭散策晚凉生，斟酌星河亦喜晴。',32,'全唐诗/poet.song.100000.json','["虛庭散策晚凉生，斟酌星河亦喜晴。", "不記牆西有修竹，夜風還作雨來聲。"]'),
('8600ea44-d89a-4352-ae24-87e344aafe3d','夏夜  其三','陳與義','宋','宋诗','song-poetry','','[]','待到天公放月時，東家喬柏兩虯枝。',32,'全唐诗/poet.song.100000.json','["待到天公放月時，東家喬柏兩虯枝。", "懸知滿地疏陰處，不及遥看突兀奇。"]'),
('e91aff89-e15f-486d-88d1-729e5c4b55e4','積雨喜霽','陳與義','宋','宋诗','song-poetry','','[]','積雨得一晴，開窗送吾目。',96,'全唐诗/poet.song.100000.json','["積雨得一晴，開窗送吾目。", "疊雲带餘憤，遠樹增新綠。", "天公信難料，變化雜神速。", "夕霞盡意紅，詰朝固難卜。", "西軒一杯酒，未負將軍腹。", "竹林懷微風，餘韻久回復。", "熱官豈辨此，何必思爛熟。", "曳杖出門行，栖鴉息枯木。"]'),
('bd4e9b6e-ef9f-4f56-887a-9b8e8e1c0792','鄧州城樓','陳與義','宋','宋诗','song-poetry','','[]','鄧州城樓高百尺，楚岫秦雲不相隔。',64,'全唐诗/poet.song.100000.json','["鄧州城樓高百尺，楚岫秦雲不相隔。", "傍城積水晚更明，照見綸巾倚樓客。", "李白上天不可呼，陰晴變化還須臾。", "獨撫欄干詠奇句，滿樓風月不枝梧。"]'),
('1123eb52-51e9-443b-bb72-a4044c221557','北征','陳與義','宋','宋诗','song-poetry','','[]','世故信有力，挽我復北馳。',96,'全唐诗/poet.song.100000.json','["世故信有力，挽我復北馳。", "獨衝七月暑，行此無盡陂。", "百卉共山澤，各自有四時。", "華實相後先，盛過當同衰。", "亦復觀我生，白髮忽及期。", "夕雲已不征，客子今何之。", "願傳飛仙術，一洗局促悲。", "被襟閬風觀，濯髮扶桑池。"]'),
('7b99f19f-8a9c-4a16-ab4f-326ad0299953','秋日客思','陳與義','宋','宋诗','song-poetry','','[]','南北東西俱我鄉，聊從地主借繩床。',64,'全唐诗/poet.song.100000.json','["南北東西俱我鄉，聊從地主借繩床。", "諸公共得何侯力，遠客新抄陸氏方。", "老去事多藜杖在，夜來秋到葉聲長。", "蓬萊可託無因至，試覓人間千仞崗。"]'),
('93176c31-48fc-4502-9b43-73b9359bac2b','道中書事','陳與義','宋','宋诗','song-poetry','','[]','臨老傷行役，籃輿歲月奔。',72,'全唐诗/poet.song.100000.json','["臨老傷行役，籃輿歲月奔。", "客愁無處避，世事不堪論。", "白道含秋色，青山带雨痕。", "壞梁斜鬬水，喬木密藏村。", "易破還家夢，難招去國魂。", "一身從白首，隨意答乾坤。"]'),
('855644f8-b160-4875-922f-0a6419a61681','將次葉城道中','陳與義','宋','宋诗','song-poetry','','[]','荒野少人去，竹輿伊軋聲。',48,'全唐诗/poet.song.100000.json','["荒野少人去，竹輿伊軋聲。", "晴雲秋更白，野水暮還明。", "寂寞信吾道，淹留諳世情。", "王喬有餘舄，借我一東征。"]'),
('1dbd6abc-1a17-473d-8e20-004e1a62b085','至葉城','陳與義','宋','宋诗','song-poetry','','[]','蘇武初逢雁，王喬欲借鳧。',48,'全唐诗/poet.song.100000.json','["蘇武初逢雁，王喬欲借鳧。", "深知念行李，爲報了長途。", "難穩三更枕，遥憐五歲雛。", "却思正月事，不敢恨榛蕪。"]'),
('4af0ed22-bb93-4019-b1ba-d79c3fca6f25','曉發葉城','陳與義','宋','宋诗','song-poetry','','[]','竹輿開兩牖，秋色爲橫分。',48,'全唐诗/poet.song.100000.json','["竹輿開兩牖，秋色爲橫分。", "左送廉纖月，右揖離披雲。", "詩情滿行色，何地著世紛。", "欲語王縣令，三叫不能聞。"]'),
('759ce7cb-14a1-4faa-b8d6-6b525a31b1c7','方城陪諸兄坐心遠亭','陳與義','宋','宋诗','song-poetry','','[]','客中日食三斗塵，北去南來了今歲。',64,'全唐诗/poet.song.100000.json','["客中日食三斗塵，北去南來了今歲。", "暫時亭中一杯酒，與兄同宗復同味。", "博山雲氣終日留，竹君蕭蕭不負秋。", "世路明年儻無故，却携藜杖更來遊。"]'),
('7bf10e25-83dc-461d-9774-4e3c3f668c63','美哉亭','陳與義','宋','宋诗','song-poetry','','[]','西出城皋關，土谷僅容駝。',96,'全唐诗/poet.song.100000.json','["西出城皋關，土谷僅容駝。", "天掛一疋練，雙崖鬬嵯峩。", "忽然五丈缺，亭構如危窠。", "青山麗中原，白日照大河。", "下視萬里川，草木何其多。", "臨高一吐氣，却奈雄風何。", "辛苦生一快，造物巧揣摩。", "險易終不償，翻身下殘坡。"]'),
('608db9c5-dc77-47f8-a4d1-cbe6c3821503','山路曉行','陳與義','宋','宋诗','song-poetry','','[]','兩崖夾曉月，萬壑分秋風。',96,'全唐诗/poet.song.100000.json','["兩崖夾曉月，萬壑分秋風。", "今朝定何朝，孤賞莫與同。", "石路抱巖轉，雲氣青濛濛。", "籃輿拂露枝，亂點驚僕童。", "微泉不知處，玉佩鳴深叢。", "平生慕李愿，得此行旅中。", "居人輕佳境，過客意無窮。", "山木好題詩，恨我行匆匆。"]'),
('022e12f2-8f45-4c84-97ce-8ed4ef48ffd3','題董宗禹園先志亭宗禹之父早失母萬方求得之此其晚節色養之地也','陳與義','宋','宋诗','song-poetry','','[]','作客古南陽，問俗仁孝敦。',96,'全唐诗/poet.song.100000.json','["作客古南陽，問俗仁孝敦。", "坐讀杜羔傳，起訪城西園。", "偉哉是家事，作傳堪千言。", "當年懷橘處，華屋澹曉暾。", "大松蔭後楹，小松羅前軒。", "風露所沐浴，千載當連根。", "我已廢蓼莪，感茲淚河翻。", "葉聲含三嘆，送我出園門。"]'),
('d21625cf-65d8-4b16-b202-20f522fc58fb','同繼祖民瞻遊賦詩亭二首  其一','陳與義','宋','宋诗','song-poetry','','[]','邂逅今朝一段奇，從來華屋不關詩。',32,'全唐诗/poet.song.100000.json','["邂逅今朝一段奇，從來華屋不關詩。", "諸君且作留連意，正是微風到竹時。"]'),
('302704d6-57b0-476c-bf99-c8335e0d25fa','同繼祖民瞻遊賦詩亭二首  其二','陳與義','宋','宋诗','song-poetry','','[]','浩浩白雲溪一色，冥冥青竹鳥三呼。',32,'全唐诗/poet.song.100000.json','["浩浩白雲溪一色，冥冥青竹鳥三呼。", "只今那得王摩詰，畫我憑欄覓句圖。"]'),
('8fa44cf8-ec8a-4d47-8051-db50e82432b3','題崇山','陳與義','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','短蓬如鳧鷖，載我萬斛愁。',120,'全唐诗/poet.song.100000.json','["短蓬如鳧鷖，載我萬斛愁。", "試登山上亭，却望沙際舟。", "世故莽相急，長江去悠悠。", "西南浸山影，晦明分中流。", "蕩摇寶鑑面，翠髻千螺浮。", "去程雖云阻，茲地固堪留。", "客路惜勝日，臨風搔白頭。", "衆色忽已晚，川光抱巖幽。", "三老呼不置，我興方未收。", "下山事復多，題詩記曾遊。"]'),
('c739cfff-00b7-4e6d-823a-637a99ec5498','與季申信道自光化復入鄧書事  其一','陳與義','宋','宋诗','song-poetry','','[]','孫子白木杖，富子黑油笠。',48,'全唐诗/poet.song.100000.json','["孫子白木杖，富子黑油笠。", "我獨白竹籃，差池復相及。", "夕陽橋邊畫，岸幘歸雲急。", "勿語城中人，從渠慎出入。"]'),
('f21c2e25-1605-468c-9924-0eb012966b26','與季申信道自光化復入鄧書事  其二','陳與義','宋','宋诗','song-poetry','','[]','賣舟作歸計，竹籃穩如舟。',48,'全唐诗/poet.song.100000.json','["賣舟作歸計，竹籃穩如舟。", "霧收青皋濕，行路當春遊。", "老馬不自知，意欲踏九州。", "依然還故櫪，寂寞壯心休。"]'),
('cc1b6b44-66c4-4441-bc9d-0e7d727fc9cd','與季申信道自光化復入鄧書事  其三','陳與義','宋','宋诗','song-poetry','','[]','再來生白髮，重見鄧州春。',48,'全唐诗/poet.song.100000.json','["再來生白髮，重見鄧州春。", "依舊城西路，桃花不記人。", "卜居得窮巷，日色滿窗新。", "微吟驚市卒，獨鶴語城闉。"]'),
('3b75fd64-ae31-421f-a762-a50b02343772','與季申信道自光化復入鄧書事  其四','陳與義','宋','宋诗','song-poetry','','[]','城西望城南，十日九相隔。',48,'全唐诗/poet.song.100000.json','["城西望城南，十日九相隔。", "何如三枝杖，共踏江上石。", "門前流水過，春意滿渠碧。", "遥知千頃江，如今好顔色。"]'),
('734e1c30-06fc-4e9b-bc8f-6f03b27b16e8','寄季申','陳與義','宋','宋诗','song-poetry','','[]','雨歇城南泥未乾，遥知獨立整衣冠。',64,'全唐诗/poet.song.100000.json','["雨歇城南泥未乾，遥知獨立整衣冠。", "舊時鄴下劉公幹，今日遼東管幼安。", "綠陰展盡身猶遠，黄鳥飛來節已闌。", "安得一樽生耳熱，暫時相對說悲歡。"]'),
('76281915-aab6-4293-9ce5-e3ea93014746','題繼祖蟠室三首  其一','陳與義','宋','宋诗','song-poetry','','[]','雲起爐山久未移，功名不恨十年遲。',32,'全唐诗/poet.song.100000.json','["雲起爐山久未移，功名不恨十年遲。", "日斜疏竹可窗影，正是幽人睡足時。"]'),
('c2bb8530-e9a6-4778-a8a8-3f465e07a3d3','題繼祖蟠室三首  其二','陳與義','宋','宋诗','song-poetry','','[]','萬卷吾今一字無，打包隨處野僧如。',32,'全唐诗/poet.song.100000.json','["萬卷吾今一字無，打包隨處野僧如。", "短檠未盡殘年債，欲問班生試借書。"]'),
('37ae380a-2f69-4dde-8a66-73fab90e0942','題繼祖蟠室三首  其三','陳與義','宋','宋诗','song-poetry','','[]','中興天子要人才，當使生擒頡利來。',32,'全唐诗/poet.song.100000.json','["中興天子要人才，當使生擒頡利來。", "正待吾曹紅抹額，不須辛苦學顔回。"]'),
('501acfb3-3d32-4dae-875c-dc7c80a77693','述懷','陳與義','宋','宋诗','song-poetry','','[]','閉戶生白髮，逍遥步城隅。',72,'全唐诗/poet.song.100000.json','["閉戶生白髮，逍遥步城隅。", "野外晴林滿，天末暮雲孤。", "水容澹春歸，草色带雨濡。", "物態紛如昨，世事再嗚呼。", "京洛了在眼，山川一何迂。", "乘槎莽未辦，且復小踟躕。"]'),
('53635ed2-9db5-4127-97e6-0b0b01528bfd','寄題趙景溫筠居軒','陳與義','宋','宋诗','song-poetry','','[]','相逢漢江邊，盜起方如雲。',96,'全唐诗/poet.song.100000.json','["相逢漢江邊，盜起方如雲。", "當時蒼黄意，亦可無此君。", "俗士固鮮歡，王孫終逸羣。", "清秋不可負，牖壁看修筠。", "碧幹立疏雨，叢梢冒斜曛。", "引君著勝地，世事從紛紛。", "何時微月夕，胡床與予分。", "高吟呼天風，夜半笙簫聞。"]'),
('e8a41260-ec24-4778-b330-b7d0dbe33cdd','重陽','陳與義','宋','宋诗','song-poetry','','[]','去歲重陽已百憂，今年依舊歎羈遊。',64,'全唐诗/poet.song.100000.json','["去歲重陽已百憂，今年依舊歎羈遊。", "籬底菊花唯解笑，鏡中頭髮不禁秋。", "凉風又落宮南木，老雁孤鳴漢北州。", "如許行年那可記，謾排詩句寫新愁。"]'),
('53aa1bce-1953-4ab1-995a-6fc70f5e16ab','有感再賦','陳與義','宋','宋诗','song-poetry','','[]','憶昔甲辰重九日，天恩曾與宴城東。',32,'全唐诗/poet.song.100000.json','["憶昔甲辰重九日，天恩曾與宴城東。", "龍沙此日西風冷，誰折黄花壽兩宮。"]'),
('aa9d1f2c-4a7f-40a7-abd3-64f3ca0bb483','感事','陳與義','宋','宋诗','song-poetry','','[]','喪亂那堪說，干戈竟未休。',72,'全唐诗/poet.song.100000.json','["喪亂那堪說，干戈竟未休。", "公卿危左衽，江漢故東流。", "風斷黄龍府，雲移白鷺洲。", "云何舒國步，持底副君憂。", "世事非難料，吾生本自浮。", "菊花紛四野，作意爲誰秋。"]'),
('37771bd8-114b-4147-9f7e-56a72ff90774','送客出城西','陳與義','宋','宋诗','song-poetry','','[]','鄧州誰亦解丹青，畫我羸驂晚出城。',64,'全唐诗/poet.song.100000.json','["鄧州誰亦解丹青，畫我羸驂晚出城。", "殘年政爾供愁了，末路那堪送客行。", "寒日滿川分衆色，暮林無葉寄秋聲。", "垂鞭歸去重回首，意落西南計未成。"]'),
('7bcd73f7-2a31-4824-a96e-2b4e368e1cc7','得席大光書因以詩迓之','陳與義','宋','宋诗','song-poetry','','[]','十月高風客子悲，故人書到暫開眉。',64,'全唐诗/poet.song.100000.json','["十月高風客子悲，故人書到暫開眉。", "也知廊廟當推轂，無奈江山好賦詩。", "萬事莫論兵動後，一杯當及菊殘時。", "喜心翻倒相迎地，不怕荒林十里陂。"]'),
('91bb1fae-e6bf-49db-80df-cc02690145e5','送大光赴石城','陳與義','宋','宋诗','song-poetry','','[]','石城高嵽嵲，城下是江波。',88,'全唐诗/poet.song.100000.json','["石城高嵽嵲，城下是江波。", "莫愁織綺地，年來戰馬過。", "秀眉使君醫國手，却把江頭無事酒。", "山川勃鬰不平處，澆以三杯一搔首。", "半江樓影白逶迤，想見春流二月時。", "待予去掃仲宣賦，走馬還朝亦未遲。"]'),
('4e8c2349-6e58-4236-a29b-8b97c850b1b3','夢中送僧覺而忘第三聯戲足之','陳與義','宋','宋诗','song-poetry','','[]','兩鴻同一天，羽翼不相及。',48,'全唐诗/poet.song.100000.json','["兩鴻同一天，羽翼不相及。", "偶然一識面，別意已超忽。", "去程秋光好，萬里無斷絕。", "雖無仁人言，贈子以明月。"]'),
('f0f09e4c-0577-448d-a05c-50bc1f738f77','無題','陳與義','宋','宋诗','song-poetry','','[]','六經在天如日月，萬事隨時更故新。',64,'全唐诗/poet.song.100000.json','["六經在天如日月，萬事隨時更故新。", "江南丞相浮雲壞，洛下先生宰木春。", "孟喜何妨改師法，京房底處有門人。", "舊喜讀書今懶讀，焚香閱世了閑身。"]'),
('5f652ee7-f24b-40dc-a22a-7400b86679d6','正月十二日自房州城遇虜至奔入南山十五日抵回谷張家','陳與義','宋','宋诗','song-poetry','','[]','久謂事當爾，豈意身及之。',192,'全唐诗/poet.song.100000.json','["久謂事當爾，豈意身及之。", "避虜連三年，行半天四維。", "我非洛豪士，不畏窮谷饑。", "但恨平生意，輕了少陵詩。", "今年奔房州，鐵馬背後馳。", "造物亦惡劇，脫命真毫釐。", "南山四程雲，布襪傲險巇。", "籬間老炙背，無意管安危。", "知我是朝士，亦復顰其眉。", "呼酒軟客脚，菜本濯玉肌。", "窮途士易德，歡喜不復辭。", "向來貪讀書，閉戶生白髭。", "豈知九州內，有山如此奇。", "自寬實不情，老人亦解頤。", "投宿恍世外，青燈耿茅茨。", "夜半不能眼，澗水鳴聲悲。"]'),
('4c63efcc-64bc-4486-b24c-d707576ceb4d','正月十六日夜二絕  其一','陳與義','宋','宋诗','song-poetry','','[]','正月十六夜，竹籬田父家。',24,'全唐诗/poet.song.100000.json','["正月十六夜，竹籬田父家。", "明月照樹影，滿山如龍蛇。"]'),
('cff7f6d0-5faa-44d0-a33d-4f234c156f59','正月十六日夜二絕  其二','陳與義','宋','宋诗','song-poetry','','[]','二更風薄竹，悲吟連夜分。',24,'全唐诗/poet.song.100000.json','["二更風薄竹，悲吟連夜分。", "村西遞餘韻，應勝此間聞。"]'),
('7f377c15-3bf6-49eb-a9f3-f9bb4134d087','坐澗邊石上','陳與義','宋','宋诗','song-poetry','','[]','三面青山圍竹籬，人間無路訪安危。',32,'全唐诗/poet.song.100000.json','["三面青山圍竹籬，人間無路訪安危。", "扶筇共坐槎牙石，澗水悲鳴無歇時。"]'),
('e055fa3e-1a17-4aff-90c4-d7bf2c7379c5','十七日夜詠月','陳與義','宋','宋诗','song-poetry','','[]','月輪隱東峯，奇彩在南嶺。',96,'全唐诗/poet.song.100000.json','["月輪隱東峯，奇彩在南嶺。", "北崖草木多，蒼茫映光景。", "玉盤忽微露，銀浪瀉千頃。", "巖谷散陸離，萬象雜形影。", "不辭三更露，冒此白髮頂。", "老筇無前遊，危處有新警。", "澗光如翻鶴，變態發遥境。", "回首房州城，山中夜何永。"]'),
('18a849d8-d2d3-4a8f-b2b8-f6c937712a5f','獨立','陳與義','宋','宋诗','song-poetry','','[]','籬門一徙倚，今夜天星繁。',48,'全唐诗/poet.song.100000.json','["籬門一徙倚，今夜天星繁。", "獨立人世外，唯聞澗水喧。", "叢薄凝露氣，羣峯带春昏。", "偷生亦聊爾，難與衆人言。"]'),
('e54ef745-495c-47a4-879f-b478409b1a81','採菖蒲','陳與義','宋','宋诗','song-poetry','','[]','閑行澗底採菖蒲，千歲龍蛇抱石𦡱。',32,'全唐诗/poet.song.100000.json','["閑行澗底採菖蒲，千歲龍蛇抱石𦡱。", "明朝却覓房州路，飛下山顛不要扶。"]'),
('64ac82ad-d690-4c66-8c3a-d4673a0645b6','與信道遊澗邊','陳與義','宋','宋诗','song-poetry','','[]','斜陽照亂石，顛崖下雙筇。',72,'全唐诗/poet.song.100000.json','["斜陽照亂石，顛崖下雙筇。", "試從絕壑底，仰視最奇峯。", "迴碕發澗怒，高靄生樹容。", "半巖菖蒲根，翠葆森伏龍。", "豈無避世士，於此儻相逢。", "客心忽悄愴，歸路迷行蹤。"]'),
('22fa1616-5e53-4549-a664-cb21e48199eb','詠西嶺梅花','陳與義','宋','宋诗','song-poetry','','[]','雨後衆崖碧，白處紛寒梅。',60,'全唐诗/poet.song.100000.json','["雨後衆崖碧，白處紛寒梅。", "遥遥迎客意，欲下山坡來。", "窮村受春晚，邂逅今日開。", "絳領承玉面，臨風一低回。", "折歸無可贈，孤賞心悠哉。"]'),
('3d46d87c-0e21-464a-a72b-d53e90754697','遊南嶂同孫信道','陳與義','宋','宋诗','song-poetry','','[]','遥瞻南嶂深復深，雙崖與天藏太陰。',144,'全唐诗/poet.song.100000.json','["遥瞻南嶂深復深，雙崖與天藏太陰。", "青鞋濟勝不能懶，踏破積雪窮崎嶔。", "空中朽樹抱孤篠，無竅蒼壁生橫林。", "孤禽三叫危石裂，欲返未返神蕭森。", "磴迴忽然何處所，當面煙如翠蛟舞。", "石門泄風無晝夜，古木截道藏雷雨。", "丹丘赤城去幾許，下視人間足塵土。", "放身天地不自知，導以龍蛇翼熊虎。", "山中異事記今晨，杖藜得道孫與陳。"]'),
('40e19cb3-cc69-4716-97ab-42130c23ec9d','遊東巖','陳與義','宋','宋诗','song-poetry','','[]','散策東巖路，夢中曾記經。',96,'全唐诗/poet.song.100000.json','["散策東巖路，夢中曾記經。", "斜暉射殘雪，巖谷遍晶熒。", "鴉鳴山寂寂，意迥川冥冥。", "乘興欲窮討，會心還少停。", "新晴遠村白，薄暮群峯青。", "危途通仙境，勝日行畫屏。", "豈獨凈一念，將期朝百靈。", "不同南澗詠，悲慨滿中扃。"]'),
('4e4012a7-8ba9-4d28-b924-6ee8bd70a614','晚望信道立竹林邊','陳與義','宋','宋诗','song-poetry','','[]','修竹林邊煙過遲，幅巾藜杖立疏籬。',32,'全唐诗/poet.song.100000.json','["修竹林邊煙過遲，幅巾藜杖立疏籬。", "恨無顧陸同携手，寫取孫郎覓句詩。"]'),
('f518830f-3429-485c-ba0b-c8254d95a627','雨晴徐步','陳與義','宋','宋诗','song-poetry','','[]','百年幾晴朝，徐步山徑濕。',48,'全唐诗/poet.song.100000.json','["百年幾晴朝，徐步山徑濕。", "忽悟春已深，鳴禽飛相及。", "雪消衆綠凈，霧罷群峯立。", "澗邊千嵁巖，今日何復集。"]'),
('6f4952f1-ce21-48a9-9032-473c0f052b5e','同信道晚登古原','陳與義','宋','宋诗','song-poetry','','[]','幽懷忽牢落，起望登古原。',48,'全唐诗/poet.song.100000.json','["幽懷忽牢落，起望登古原。", "微吹度修竹，半林白翻翻。", "日暮紛物態，山空銷客魂。", "惜無一樽酒，與子醉中言。"]'),
('8ea8fafb-f1a9-494f-9a90-5bef0a310b42','岸幘','陳與義','宋','宋诗','song-poetry','','[]','岸幘立清曉，山頭生薄陰。',48,'全唐诗/poet.song.100000.json','["岸幘立清曉，山頭生薄陰。", "亂雲交翠壁，細雨濕青林。", "時改客心動，鳥鳴春意深。", "窮鄉百不理，時得一閑吟。"]'),
('3ac5b0d9-0709-49a2-84fc-632ea7833216','雨','陳與義','宋','宋诗','song-poetry','','[]','雲起谷全暗，雨時山復明。',48,'全唐诗/poet.song.100000.json','["雲起谷全暗，雨時山復明。", "青春望中色，白澗晚來聲。", "遠樹鳥群集，高原人獨耕。", "老夫逃世日，堅坐聽陰晴。"]'),
('02722465-9cc9-4679-8928-c538178d4f03','醉中至西徑梅花下已盛開','陳與義','宋','宋诗','song-poetry','','[]','梅花亂發雨晴時，褪盡紅綃見玉肌。',32,'全唐诗/poet.song.100000.json','["梅花亂發雨晴時，褪盡紅綃見玉肌。", "醉中忘却頭邊雪，橫插繁枝歸竹籬。"]'),
('651556e9-3e61-414d-95cd-1e5d1863684a','出山二首  其一','陳與義','宋','宋诗','song-poetry','','[]','陰巖不知晴，路轉見朝日。',24,'全唐诗/poet.song.100000.json','["陰巖不知晴，路轉見朝日。", "獨行修竹盡，石崖千丈碧。"]'),
('cb68b0a6-7f45-4c3f-b4b0-b822020fc6a6','出山二首  其二','陳與義','宋','宋诗','song-poetry','','[]','山空樵斧響，隔嶺有人家。',24,'全唐诗/poet.song.100000.json','["山空樵斧響，隔嶺有人家。", "日落潭照樹，川明風動花。"]'),
('2babea40-114e-40a8-b209-98a346563b7e','入山二首  其一','陳與義','宋','宋诗','song-poetry','','[]','出山復入山，路隨溪水轉。',24,'全唐诗/poet.song.100000.json','["出山復入山，路隨溪水轉。", "東風不惜花，一暮都開遍。"]'),
('a289a8d6-40be-4dd1-88c0-57a51d62056b','入山二首  其二','陳與義','宋','宋诗','song-poetry','','[]','都迷去時景，策杖煙漫漫。',24,'全唐诗/poet.song.100000.json','["都迷去時景，策杖煙漫漫。", "微雨洗春色，諸峯生晚寒。"]'),
('348f8f98-e4be-408a-b189-16a8cf398287','寒食','陳與義','宋','宋诗','song-poetry','','[]','竹籬寒食節，微雨澹春意。',48,'全唐诗/poet.song.100000.json','["竹籬寒食節，微雨澹春意。", "喧譁少所便，寂寞今有味。", "空山花動摇，亂石水經緯。", "倚杖忽已晚，人生本何冀。"]'),
('a1f27b59-6b74-4369-8810-12b0acc0c66e','清明','陳與義','宋','宋诗','song-poetry','','[]','雨晴閑步澗邊沙，行入荒林聞亂鴉。',64,'全唐诗/poet.song.100000.json','["雨晴閑步澗邊沙，行入荒林聞亂鴉。", "寒食清明驚客意，暖風遲日醉梨花。", "書生投老王官谷，壯士偷生漂母家。", "不用鞦韆與蹴遊，只將詩句答年華。"]'),
('621d69c8-a0b8-4ce8-9268-cff698a3dd4e','與夏致宏孫信道張巨山同集澗邊以散髮巖岫爲韻賦四小詩  其一','陳與義','宋','宋诗','song-poetry','','[]','哦詩谷虛響，散髮下巖半。',24,'全唐诗/poet.song.100000.json','["哦詩谷虛響，散髮下巖半。", "披叢澗影摇，集鳥紛然散。"]'),
('cbbb48df-e9d2-4203-8211-8b55682b46a5','與夏致宏孫信道張巨山同集澗邊以散髮巖岫爲韻賦四小詩  其二','陳與義','宋','宋诗','song-poetry','','[]','亂石披淺流，水紋如紺髮。',24,'全唐诗/poet.song.100000.json','["亂石披淺流，水紋如紺髮。", "馳暉忽西沒，林光相映發。"]'),
('1ca96a53-4be6-4202-bf86-bb08bc97600b','與夏致宏孫信道張巨山同集澗邊以散髮巖岫爲韻賦四小詩  其三','陳與義','宋','宋诗','song-poetry','','[]','舉頭山圍天，濯足樹映潭。',24,'全唐诗/poet.song.100000.json','["舉頭山圍天，濯足樹映潭。", "山中記今日，四士集空巖。"]'),
('d0e2b293-f506-4701-883e-1c65d97ae15d','與夏致宏孫信道張巨山同集澗邊以散髮巖岫爲韻賦四小詩  其四','陳與義','宋','宋诗','song-poetry','','[]','張子卧石榻，夏子理泉竇。',24,'全唐诗/poet.song.100000.json','["張子卧石榻，夏子理泉竇。", "孫子獨不言，搘頤數煙岫。"]'),
('ca349d13-a188-4aa4-be66-cf10f95b1a77','出山宿向翁家','陳與義','宋','宋诗','song-poetry','','[]','紙坊山絕頂，直下夕陽斜。',48,'全唐诗/poet.song.100000.json','["紙坊山絕頂，直下夕陽斜。", "却看來路處，南北兩巖花。", "田翁邀客宿，笑指林下家。", "問我出山意，無乃貴喧譁。"]'),
('ad82c0ba-c151-4dcf-a8b9-6df0ed251003','出山道中','陳與義','宋','宋诗','song-poetry','','[]','雨歇澹春曉，雲氣山腰流。',72,'全唐诗/poet.song.100000.json','["雨歇澹春曉，雲氣山腰流。", "高崖落絳葉，恍如人世秋。", "避地時忽忽，出山意悠悠。", "溪急竹陰動，谷虛禽響幽。", "同行得快士，勝處頻淹留。", "乘除了身世，未恨落房州。"]'),
('23849b7e-e2bd-4c34-93b4-a428893851a4','詠青溪石壁','陳與義','宋','宋诗','song-poetry','','[]','青溪宜曉日，曲處千丈晦。',96,'全唐诗/poet.song.100000.json','["青溪宜曉日，曲處千丈晦。", "天開蒼石屏，影落西村外。", "虛無元氣立，明滅河漢對。", "人行崢嶸下，鳥急浩蕩內。", "向來千萬峯，瑣細等蓬塊。", "老夫倚杖久，三嘆造物大。", "惜哉太史公，意短遺此快。", "更欲訪野人，窮探視其背。"]'),
('63c2d0b1-73b0-4d3c-97a9-a058e316f60e','聞王道濟陷虜','陳與義','宋','宋诗','song-poetry','','[]','海內堂堂友，如今在賊圍。',48,'全唐诗/poet.song.100000.json','["海內堂堂友，如今在賊圍。", "虛傳袁盎脫，不見華元歸。", "浮世身難料，危途計易非。", "雲孤馬息嶺，老淚不勝揮。"]'),
('bf99abad-4297-45e1-808d-a003d62b1954','均陽官舍有安榴數株著花絕稀更增妍麗','陳與義','宋','宋诗','song-poetry','','[]','庭際安榴樹，花稀更可憐。',48,'全唐诗/poet.song.100000.json','["庭際安榴樹，花稀更可憐。", "青旌擁絳節，伴我作神仙。", "遲日耿不暮，微陰眩彌鮮。", "一樽兼百慮，心賞竟悠然。"]'),
('547effd5-7634-4b97-9481-f74b1f833ded','和王東卿絕句四首  其一','陳與義','宋','宋诗','song-poetry','','[]','少年走馬洛陽城，今作江邊瓶錫僧。',32,'全唐诗/poet.song.100000.json','["少年走馬洛陽城，今作江邊瓶錫僧。", "說與虎頭須畫我，三更月裏影崚嶒。"]'),
('c0185fd5-bace-4551-8e07-570e785741c4','和王東卿絕句四首  其二','陳與義','宋','宋诗','song-poetry','','[]','來日安榴花尚稀，壓牆丹實已垂垂。',32,'全唐诗/poet.song.100000.json','["來日安榴花尚稀，壓牆丹實已垂垂。", "何時著我扁舟尾，滿袖西風信所之。"]'),
('7ed4a674-6e61-45db-b264-fee0188c1f10','和王東卿絕句四首  其三','陳與義','宋','宋诗','song-poetry','','[]','只今當代功名手，不數平生粥飯僧。',32,'全唐诗/poet.song.100000.json','["只今當代功名手，不數平生粥飯僧。", "獨立江風吹短髮，暮雲千里倚崚嶒。"]'),
('200936dc-3585-491d-9eca-f5655ca403d6','和王東卿絕句四首  其四','陳與義','宋','宋诗','song-poetry','','[]','平生不得吟詩力，空使秋霜入鬢垂。',32,'全唐诗/poet.song.100000.json','["平生不得吟詩力，空使秋霜入鬢垂。", "太岳峯前滿尊月，爲君聊復一中之。"]'),
('0bad2fd2-e5e4-4c30-8413-2d8df59d5878','觀江漲','陳與義','宋','宋诗','song-poetry','','[]','漲江臨眺足消憂，倚杖江邊地欲浮。',64,'全唐诗/poet.song.100000.json','["漲江臨眺足消憂，倚杖江邊地欲浮。", "疊浪併翻孤日去，兩津橫卷半天流。", "黿鼉雜怒爭新穴，鷗鷺驚飛失故洲。", "可爲一官妨快意，眼中唯覺欠扁舟。"]'),
('e72ab2c9-db66-4b0d-a50c-756ed1cfbe1d','同左通老用陶潜還舊居韻','陳與義','宋','宋诗','song-poetry','','[]','故園非無路，今已不念歸。',96,'全唐诗/poet.song.100000.json','["故園非無路，今已不念歸。", "秋入漢水白，葉脫行人悲。", "東西與南北，欲往還覺非。", "勿云去年事，兵火偶脫遺。", "可憐竛竮影，殘歲聊相依。", "天涯一尊酒，細酌君勿催。", "持觴望江山，路永悲身衰。", "百感醉中起，清淚對君揮。"]'),
('f55181d0-43cb-49c5-b248-a0e99b7f00f5','同通老用淵明獨酌韻','陳與義','宋','宋诗','song-poetry','','[]','紛紛吏民散，遺我以兀然。',96,'全唐诗/poet.song.100000.json','["紛紛吏民散，遺我以兀然。", "悄悄今夕意，鳥影馳隙間。", "向來房州谷，採藥危得仙。", "忽駕太守車，出處寧非天。", "何妨暫閱世，謀行要當先。", "西齋一壺酒，微雨新秋還。", "蛛網閃明晦，葉聲餞歲年。", "呼兒具紙筆，錄我醉中言。"]'),
('090f2892-c088-4d48-803b-4adf2d55a85d','欲離均陽而雨不止書八句寄何子應','陳與義','宋','宋诗','song-poetry','','[]','江城八月楓葉凋，城頭哦詩江動摇。',64,'全唐诗/poet.song.100000.json','["江城八月楓葉凋，城頭哦詩江動摇。", "秋雨留人意戀戀，水風泛樹聲蕭蕭。", "綸巾老子無遠策，長作東西南北客。", "不如何遜在揚州，坐待梅花映粧額。"]'),
('61b04916-056d-439e-8ed5-cf403498760e','均陽舟中夜賦','陳與義','宋','宋诗','song-poetry','','[]','遊子不能寐，船頭語輕波。',72,'全唐诗/poet.song.100000.json','["遊子不能寐，船頭語輕波。", "開窗望兩津，煙樹何其多。", "晴江涵萬象，夜半光蕩摩。", "客愁彌世路，秋氣入天河。", "汝洛塵未銷，幾人不負戈。", "長吟宇宙內，激烈悲蹉跎。"]'),
('fdc0a180-0eb3-46e8-8071-442fe6de5b9c','舟次高舍書事','陳與義','宋','宋诗','song-poetry','','[]','漲水東流滿眼黄，泊舟高舍更情傷。',64,'全唐诗/poet.song.100000.json','["漲水東流滿眼黄，泊舟高舍更情傷。", "一川木葉明秋序，兩岸人家共夕陽。", "亂後江山元歷歷，世間歧路極茫茫。", "遥指長沙非謫去，古今出處兩凄凉。"]'),
('e16d7520-a192-412a-aab9-456b7ac4f277','石城夜賦','陳與義','宋','宋诗','song-poetry','','[]','初月光滿江，斷處知急流。',48,'全唐诗/poet.song.100000.json','["初月光滿江，斷處知急流。", "沉沉石城夜，漠漠西漢秋。", "爲客寐常晚，臨風意難收。", "三更柁樓底，身世入搔頭。"]'),
('128f1fa5-5613-4ed4-812e-d05f58118536','登岳陽樓  其一','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','洞庭之東江水西，簾旌不動夕陽遲。',64,'全唐诗/poet.song.100000.json','["洞庭之東江水西，簾旌不動夕陽遲。", "登臨吳蜀橫分地，徙倚湖山欲暮時。", "萬里來遊還望遠，三年多難更憑危。", "白頭吊古風霜裏，老木滄波無恨悲。"]'),
('854b5c57-a49e-4ae5-aa4a-0e8a84ae47d2','登岳陽樓  其二','陳與義','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','天入平湖晴不風，夕帆和雁正浮空。',64,'全唐诗/poet.song.100000.json','["天入平湖晴不風，夕帆和雁正浮空。", "樓頭客子杪秋後，日落君山元氣中。", "北望可堪回白首，南遊聊得看丹楓。", "翰林物色分留少，詩到巴陵還未工。"]'),
('91b6d61f-2ad1-496f-8705-722ce0b883e6','巴丘書事','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','三分書裏識巴丘，臨老避胡初一遊。',64,'全唐诗/poet.song.100000.json','["三分書裏識巴丘，臨老避胡初一遊。", "晚木聲酣洞庭野，晴天影抱岳陽樓。", "四年風露侵遊子，十月江湖吐亂洲。", "未必上流須魯蕭，腐儒空白九分頭。"]'),
('e9d603d4-7077-4189-bd86-1dd8a2a9b17a','晚步湖邊','陳與義','宋','宋诗','song-poetry','','[]','客間無勝日，世故可暫逃。',96,'全唐诗/poet.song.100000.json','["客間無勝日，世故可暫逃。", "杖藜迎落照，寒彩遍平皋。", "夕湖光景麗，晴鸛聲音豪。", "天長蒹葭響，水落城堞高。", "萬象各摇動，慰此老不遭。", "楚纍經行地，處處餘離騷。", "幸無大夫責，得伴諸子遨。", "終然動懷抱，白髮風中搔。"]'),
('f04ecec4-ecad-45f1-b795-a3d18baf9408','再登岳陽樓感慨賦詩','陳與義','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','岳陽壯觀天下傳，樓陰背日堤綿綿。',64,'全唐诗/poet.song.100000.json','["岳陽壯觀天下傳，樓陰背日堤綿綿。", "草木相連南服內，江湖異態欄干前。", "乾坤萬事集雙鬢，臣子一謫今五年。", "欲題文字弔古昔，風壯浪湧心茫然。"]'),
('330793bd-7e0e-49bc-b970-4dd65001248a','里翁行','陳與義','宋','宋诗','song-poetry','','[]','里翁無人支緩急，天雨牆壞百憂集。',67,'全唐诗/poet.song.100000.json','["里翁無人支緩急，天雨牆壞百憂集。", "賣衣雇人築得牆，不慮偷兒披戶入。", "夜寒干陬不經過，偷兒若來知奈何。", "君不見巴丘古城如培塿，魯肅當年萬人守。"]'),
('2c51514e-2153-442f-955a-77e65bc41d07','居夷行','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','遭亂始知承平樂，居夷更覺中原好。',144,'全唐诗/poet.song.100000.json','["遭亂始知承平樂，居夷更覺中原好。", "巴陵十月江不平，萬里北風吹客倒。", "洞庭葉稀秋聲歇，黄帝樂罷川杲杲。", "君山偃蹇橫歲暮，天映湖南白如掃。", "人世多違壯士悲，干戈未定書生老。", "揚州雲氣鬰不動，白首頻回費私禱。", "后勝誤齊已莫追，范蠡圖越當若爲。", "皇天豈無悔禍意，君子慎惜經綸時。", "願聞羣公張王室，臣也安眠送餘日。"]'),
('b9a8e729-8546-4d0c-9fd6-7d8b9108669e','又登岳陽樓','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','岳陽樓前丹葉飛，欄干留我不須歸。',32,'全唐诗/poet.song.100000.json','["岳陽樓前丹葉飛，欄干留我不須歸。", "洞庭鏡面平千里，却要君山相發揮。"]'),
('57d4fee1-74a2-4445-8f78-0f86d7fee586','除夜二首  其一','陳與義','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','城中爆竹已殘更，朔吹翻江意未平。',64,'全唐诗/poet.song.100000.json','["城中爆竹已殘更，朔吹翻江意未平。", "多事鬢毛隨節換，盡情燈火向人明。", "比量舊歲聊堪喜，流轉殊方又可驚。", "明日岳陽樓上去，島煙湖霧看春生。"]'),
('10f410ec-27e7-4634-9a38-7f2bb42fb322','除夜二首  其二','陳與義','宋','宋诗','song-poetry','','[]','萬里江湖憔悴身，鼕鼕街鼓不饒人。',32,'全唐诗/poet.song.100000.json','["萬里江湖憔悴身，鼕鼕街鼓不饒人。", "只愁一夜梅花老，看到天明付與春。"]'),
('670e1bc8-f0a3-4e58-88da-cb38b772db2f','火後問舍至城南有感','陳與義','宋','宋诗','song-poetry','','[]','魂傷瓦礫舊曾遊，尚想奔煙萬馬遒。',64,'全唐诗/poet.song.100000.json','["魂傷瓦礫舊曾遊，尚想奔煙萬馬遒。", "遂替胡兒作正月，絕知回祿相巴丘。", "書生性命驚頻試，客子茅茨費屢謀。", "唯有君山故窈窕，一眉晴綠向人浮。"]'),
('859675c8-6442-4c34-8fab-57999931b491','曉登燕公樓','陳與義','宋','宋诗','song-poetry','','[]','欄干納清曉，拄杖追黄鵠。',48,'全唐诗/poet.song.100000.json','["欄干納清曉，拄杖追黄鵠。", "燕公不相待，使我立於獨。", "霧收天落川，日動春浮木。", "舉手謝時人，微風吹野服。"]'),
('bf154ff7-0d58-42ab-b865-f32a33a3ac34','火後借居君子亭書事四絕呈粹翁  其一','陳與義','宋','宋诗','song-poetry','','[]','天公惡劇逐番新，賴是今年有主人。',32,'全唐诗/poet.song.100000.json','["天公惡劇逐番新，賴是今年有主人。", "君子亭中眠白晝，燕公樓上眺青春。"]'),
('4c46f630-dd50-471d-9cae-ef0d40afbb5e','火後借居君子亭書事四絕呈粹翁  其二','陳與義','宋','宋诗','song-poetry','','[]','祝融回祿意佳哉，挽我梅花樹下來。',32,'全唐诗/poet.song.100000.json','["祝融回祿意佳哉，挽我梅花樹下來。", "一夜東風不知惜，月明滿樹十分開。"]'),
('76d38cf5-a3bd-4fff-955d-cc7dc2bcfdde','火後借居君子亭書事四絕呈粹翁  其三','陳與義','宋','宋诗','song-poetry','','[]','斫竹和梢編作籬，微風如在竹林時。',32,'全唐诗/poet.song.100000.json','["斫竹和梢編作籬，微風如在竹林時。", "無人來訪龐居士，晚日疏陰光陸離。"]'),
('7cad2acb-f01f-415c-a9c6-caf67e42aaa2','火後借居君子亭書事四絕呈粹翁  其四','陳與義','宋','宋诗','song-poetry','','[]','入山從此不須深，君子亭中人不尋。',32,'全唐诗/poet.song.100000.json','["入山從此不須深，君子亭中人不尋。", "青竹短籬圍晝靜，梅花兩樹照春陰。"]'),
('be4f3b0c-99e9-4361-9874-df2336de4dbe','再賦  其一','陳與義','宋','宋诗','song-poetry','','[]','西園芳氣雨餘新，喚起亭中入定人。',32,'全唐诗/poet.song.100000.json','["西園芳氣雨餘新，喚起亭中入定人。", "爲報使君多釀酒，梅花落盡不關春。"]'),
('578d683e-1119-4ef8-a18f-7177db48e6d2','再賦  其二','陳與義','宋','宋诗','song-poetry','','[]','揚州雲氣鬰佳哉，百慮方橫吉語來。',32,'全唐诗/poet.song.100000.json','["揚州雲氣鬰佳哉，百慮方橫吉語來。", "却看詩書安隱在，竹籬陰裏得時開。"]'),
('fdef2f21-2e24-49e3-abee-b07093916326','再賦  其三','陳與義','宋','宋诗','song-poetry','','[]','危樓只隔一重籬，誰見扶筇獨上時。',32,'全唐诗/poet.song.100000.json','["危樓只隔一重籬，誰見扶筇獨上時。", "如許江山懶搜句，燕公應笑我支籬。"]'),
('3f3eba85-16f1-4b92-856e-751e15386fee','再賦  其四','陳與義','宋','宋诗','song-poetry','','[]','欲識道人門徑深，水仙多處試來尋。',32,'全唐诗/poet.song.100000.json','["欲識道人門徑深，水仙多處試來尋。", "青裳素面天應惜，乞與西園十日陰。"]'),
('3b64bcab-2432-4101-8348-8d5d6b4f0d47','二十一日風甚明日梅花無在者獨紅萼留枝間甚可愛也','陳與義','宋','宋诗','song-poetry','','[]','昨日梅花猶可攀，今朝殘萼便斕班。',32,'全唐诗/poet.song.100000.json','["昨日梅花猶可攀，今朝殘萼便斕班。", "群仙已御東風去，總脫絳袂留林間。"]'),
('06b07c42-1a68-4ba6-939c-a304ddc7117d','詠水仙花五韻','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','仙人緗色裘，縞衣以裼之。',60,'全唐诗/poet.song.100000.json','["仙人緗色裘，縞衣以裼之。", "青帨紛委地，獨立東風時。", "吹香洞庭暖，弄影清晝遲。", "寂寂籬落陰，亭亭與予期。", "誰知園中客，能賦會真詩。"]'),
('bcc73f66-84ac-4040-8c77-db48c6bdd8cb','望燕公樓下李花','陳與義','宋','宋诗','song-poetry','','[]','燕公樓下繁華樹，一日遥看一百回。',64,'全唐诗/poet.song.100000.json','["燕公樓下繁華樹，一日遥看一百回。", "羽蓋夢餘當晝立，縞衣風急過牆來。", "洛陽路不容春到，南國花應爲客開。", "今日豈堪簪短髮，感時傷舊意難裁。"]'),
('1092060e-a726-4c01-a236-b42412351246','陪粹翁舉酒於君子亭下海棠方開','陳與義','宋','宋诗','song-poetry','','[]','世故驅人殊未央，聊從地主借繩床。',64,'全唐诗/poet.song.100000.json','["世故驅人殊未央，聊從地主借繩床。", "春風浩浩吹遊子，暮雨霏霏濕海棠。", "去國衣冠無態度，隔簾花葉有輝光。", "使君禮數能寬否，酒味撩人我欲狂。"]'),
('278a33d0-5dc2-452a-bdec-8ea2f5418b6b','春夜感懷寄席大光','陳與義','宋','宋诗','song-poetry','','[]','管寧白帽且蹁躚，孤鶴歸期難計年。',64,'全唐诗/poet.song.100000.json','["管寧白帽且蹁躚，孤鶴歸期難計年。", "倚杖東南觀北變，傷心雲霧隔三川。", "江湖氣動春還冷，鴻雁聲迴人不眠。", "苦憶西州老太守，何時相伴一燈前。"]'),
('e802293c-2429-4a94-8df6-2419424e59a3','夜賦寄友','陳與義','宋','宋诗','song-poetry','','[]','賣藥韓康伯，談經管幼安。',48,'全唐诗/poet.song.100000.json','["賣藥韓康伯，談經管幼安。", "向來甘寂寞，不是爲艱難。", "微月扶疏樹，空園浩蕩寒。", "細題今夕景，持與故人看。"]'),
('a532bd67-7ad3-4279-a51a-883b55f83dec','陰風','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','陰風三日吹南極，二月巴陵寒裂石。',67,'全唐诗/poet.song.100000.json','["陰風三日吹南極，二月巴陵寒裂石。", "長林巨木受軒輊，洞庭倒流瀟湘黑。", "君不見古廬竹扉聲策策，中有竛竮落南客。", "曾經破膽向炎官，敢不修容待風伯。"]'),
('16296a08-7f8e-4bdb-8d7c-51497001e90a','雨','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','霏霏三日雨，藹藹一園青。',48,'全唐诗/poet.song.100000.json','["霏霏三日雨，藹藹一園青。", "霧澤含元氣，風花過洞庭。", "地偏寒浩蕩，春半客竛竮。", "多少人間事，天涯醉又醒。"]'),
('7ab0a7da-fa8f-4257-8dd3-5fe12424aad1','春寒','陳與義','宋','宋诗','song-poetry','','["\u548f\u7269\u8bd7", "\u6292\u6000", "\u54c1\u683c", "\u548f\u7269", "\u6d77\u68e0"]','二月巴陵日日風，春寒未了怯園公。',32,'全唐诗/poet.song.100000.json','["二月巴陵日日風，春寒未了怯園公。", "海棠不惜臙脂色，獨立濛濛細雨中。"]'),
('4905ce3e-b88a-4fdc-9e33-b1b66fea8e8e','次韻傅子文絕句','陳與義','宋','宋诗','song-poetry','','[]','風雨門前十日泥，荒街相伴只筇枝。',32,'全唐诗/poet.song.100000.json','["風雨門前十日泥，荒街相伴只筇枝。", "從今老子都無事，落盡園花不賦詩。"]'),
('1be2df91-2c54-4f5d-91cc-605d6b024b15','周尹潛雪中過門不我顧遂登西樓作詩見寄次韻謝之三首  其一','陳與義','宋','宋诗','song-poetry','','[]','曉窗飛雪愜幽聽，起覓新詩自啟扃。',32,'全唐诗/poet.song.100000.json','["曉窗飛雪愜幽聽，起覓新詩自啟扃。", "不覺高軒牆外過，貪看萬鶴舞中庭。"]'),
('db7842c7-039e-4c2a-874e-65434c8173ed','周尹潛雪中過門不我顧遂登西樓作詩見寄次韻謝之三首  其二','陳與義','宋','宋诗','song-poetry','','[]','堪笑臞仙也耐寒，飛花端合上樓看。',32,'全唐诗/poet.song.100000.json','["堪笑臞仙也耐寒，飛花端合上樓看。", "深知壯觀增詩律，洗盡元和到建安。"]'),
('91ecb44b-dec9-4000-b5c6-591bf00976cb','周尹潛雪中過門不我顧遂登西樓作詩見寄次韻謝之三首  其三','陳與義','宋','宋诗','song-poetry','','[]','敲門俗子令我病，面有三寸康衢埃。',32,'全唐诗/poet.song.100000.json','["敲門俗子令我病，面有三寸康衢埃。", "風饕雪虐君馳去，蓬戶那無酒一杯。"]'),
('368786b7-156e-475b-9e12-1c1e066a67f3','城上晚思','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','獨憑危堞望蒼梧，落日君山如畫圖。',32,'全唐诗/poet.song.100000.json','["獨憑危堞望蒼梧，落日君山如畫圖。", "無數柳花飛滿岸，晚風吹過洞庭湖。"]'),
('c7fbc740-03ab-4723-8c85-eefd040ab71b','雨中對酒庭下海棠經雨不謝','陳與義','宋','宋诗','song-poetry','','[]','巴陵二月客添衣，草草杯觴恨醉遲。',64,'全唐诗/poet.song.100000.json','["巴陵二月客添衣，草草杯觴恨醉遲。", "燕子不禁連夜雨，海棠猶待老夫詩。", "天翻地覆傷春色，齒豁頭童祝聖時。", "白竹籬前湖海闊，茫茫身世兩堪悲。"]'),
('f6421e54-378c-4d25-a717-35404dd00439','尋詩兩絕句  其一','陳與義','宋','宋诗','song-poetry','','[]','楚酒困人三日醉，園花經雨百般紅。',32,'全唐诗/poet.song.100000.json','["楚酒困人三日醉，園花經雨百般紅。", "無人畫出陳居士，亭角尋詩滿袖風。"]'),
('9be5f566-6eb3-4844-a284-a5c6e9e747e6','尋詩兩絕句  其二','陳與義','宋','宋诗','song-poetry','','[]','愛把山瓢莫笑儂，愁時引睡有奇功。',32,'全唐诗/poet.song.100000.json','["愛把山瓢莫笑儂，愁時引睡有奇功。", "醒來推戶尋詩去，喬木崢嶸明月中。"]'),
('2e4b2fba-7b2b-443b-9ba9-eabae33bdb57','寒食日遊百花亭','陳與義','宋','宋诗','song-poetry','','[]','晴氣已復濁，虛館可淹留。',96,'全唐诗/poet.song.100000.json','["晴氣已復濁，虛館可淹留。", "微花耿寒食，始覺在他州。", "自聞鼙鼓聒，不恨歲月流。", "亂代有今夕，茲園况堪遊。", "雲移樹陰失，風定川華收。", "曳杖新城下，日暮禽語幽。", "群行意易分，獨賞興難周。", "永嘯以自暢，片月生城頭。"]'),
('59e0e530-45ba-4338-9a7e-0755b34e81d1','王應仲欲附張恭甫舟過湖南久不决今日忽聞遂登舟作詩送之并簡恭甫','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我身如孤雲，隨風墮湖邊。',120,'全唐诗/poet.song.100000.json','["我身如孤雲，隨風墮湖邊。", "牆東木陰好，初識避世賢。", "從來有名士，不用無名錢。", "披君三逕草，分我一味禪。", "胡爲黄鵠舉，忽上湖南船。", "竟隨文若去，聊伴元禮仙。", "洞庭煙發渚，瀟湘雨鳴川。", "三老好看客，天高柁樓前。", "子魚獨留滯，坐送管邴遷。", "作詩相棹謳，寄恨餘酸然。"]'),
('8a07487a-cbc4-4290-883b-3f31f7783b48','周尹潜以僕有郢州之命作詩見贈有橫槊之句次韻謝之','陳與義','宋','宋诗','song-poetry','','[]','一歲憂兵四閱時，偷生不恨隙駒馳。',64,'全唐诗/poet.song.100000.json','["一歲憂兵四閱時，偷生不恨隙駒馳。", "如何南紀持竿手，却把西州破賊旗。", "儻有青油盛快士，何妨畫戟入新詩。", "因君調我還增氣，男子平生政要奇。"]'),
('86b39349-1dde-49ef-bc8c-433f598c1021','次韻尹潜感懷','陳與義','宋','宋诗','song-poetry','','[]','胡兒又看繞淮春，嘆息猶爲國有人。',64,'全唐诗/poet.song.100000.json','["胡兒又看繞淮春，嘆息猶爲國有人。", "可使翠華周宇縣，誰持白羽靜風塵。", "五年天地無窮事，萬里江湖見在身。", "共說金陵龍虎氣，放臣迷路感煙津。"]'),
('46ecd82d-31ba-4d0f-9a85-8f96662e4f6f','五月二日避貴寇入洞庭湖絕句','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','鼓發嘉魚千面雷，亂帆和雨向湖開。',32,'全唐诗/poet.song.100000.json','["鼓發嘉魚千面雷，亂帆和雨向湖開。", "何妨南北東西客，一聽湘妃瑶瑟來。"]'),
('2b5d35ce-feae-4d6a-a958-457ceb6c861b','過君山不獲登覽','陳與義','宋','宋诗','song-poetry','','[]','我夢君山好，萬里來南州。',132,'全唐诗/poet.song.100000.json','["我夢君山好，萬里來南州。", "青眉橫玉鏡，色照城中樓。", "勝日空倚眺，經年未成遊。", "今朝過山下，賊急不敢留。", "嵌空浪吞吐，薈蔚風颼飀。", "龍吟雜虎嘯，九夏含三秋。", "了與遥賞異，况乃行岩幽。", "蚍蜉何當掃，延佇回我舟。", "擲去九節筇，褰裳走林丘。", "會逢湘君降，翠氣衣上浮。", "山椒望蒼梧，寄恨舒冥搜。"]'),
('a5727dbd-69ee-45a7-b3e2-f5bffe4249c4','細雨','陳與義','宋','宋诗','song-poetry','','[]','避寇煩三老，那知是勝遊。',48,'全唐诗/poet.song.100000.json','["避寇煩三老，那知是勝遊。", "平湖受細雨，遠岸送輕舟。", "天地悲深阻，山川慰久留。", "參差發鄰舫，未覺壯心休。"]'),
('617a1664-c0b2-47ff-8a80-99503af9b35c','泊宋田遇厲風作','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','逐隊避狂寇，湖中可盤嬉。',108,'全唐诗/poet.song.100000.json','["逐隊避狂寇，湖中可盤嬉。", "泊舟宋田港，俯仰看雲移。", "造物猶不借，顛風忽橫吹。", "洞庭何其大，浪挾雷車馳。", "可憐岸上竹，翻倒不自持。", "老夫元耐事，淹速本無期。", "會有天風定，見汝亭亭時。", "五月念貂裘，竟生薄暮悲。", "蕭蕭不自暢，耿耿獨題詩。"]'),
('bcd52143-b3d3-4dd5-9d11-f4a48d3f408d','二十二日自北沙移舟作是日聞賊革面','陳與義','宋','宋诗','song-poetry','','[]','宛宛轉湖灘，遥遥隔城邑。',132,'全唐诗/poet.song.100000.json','["宛宛轉湖灘，遥遥隔城邑。", "是時雨初霽，衆綠带餘濕。", "曉澤澹不波，菰浦覺風入。", "我生莽未定，世故紛相襲。", "靦然賀蘭面，安視一坐泣。", "豈知虎與狼，義感功反集。", "堯俗可盡封，嗚呼吾何及。", "氣蘇巨浸內，未恨乏供給。", "日曆會有窮，吾行豈須急。", "近樹背人去，遠樹久凝立。", "聊以憂世心，寄茲忘怏悒。"]'),
('e3eb815a-0e55-4f49-8d60-582dd7dd1084','贈傅子文','陳與義','宋','宋诗','song-poetry','','[]','漁子牧兒談笑新，先生勝日步湖滣。',64,'全唐诗/poet.song.100000.json','["漁子牧兒談笑新，先生勝日步湖滣。", "沙邊忽見長身士，頭上仍欹折角巾。", "豺虎不能寬遠俗，山川終要識詩人。", "蘆叢如畫斜陽裏，拄杖相尋無雜賓。"]'),
('769f12df-e774-4ee1-82ad-77c1c8325802','晚晴野望','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭微雨後，凉氣入綸巾。',72,'全唐诗/poet.song.100000.json','["洞庭微雨後，凉氣入綸巾。", "水底歸雲亂，蘆藂返照新。", "遥汀橫薄暮，獨鳥度長津。", "兵甲無歸日，江湖送老身。", "悠悠只倚杖，悄悄自傷神。", "天意蒼茫裏，村醪亦醉人。"]'),
('6f86b9b7-2ac4-4fb6-b77e-702ed441cee4','雨中','陳與義','宋','宋诗','song-poetry','','[]','雨打船蓬聲百般，白頭當夏不禁寒。',32,'全唐诗/poet.song.100000.json','["雨打船蓬聲百般，白頭當夏不禁寒。", "五湖七澤經行遍，終憶吾鄉八節灘。"]'),
('731abf00-7f03-463a-aaa7-98b375ab42af','舟抵華容縣','陳與義','宋','宋诗','song-poetry','','[]','篙舟入華容，白水繞城堞。',48,'全唐诗/poet.song.100000.json','["篙舟入華容，白水繞城堞。", "夾津列茂樹，倒影青相接。", "遠色分村塢，微凉動蘆葉。", "天地困腐儒，江湖託孤檝。"]'),
('64482661-0672-430d-b922-f1032b583b11','夜賦','陳與義','宋','宋诗','song-poetry','','[]','泊舟華容縣，湖水終夜明。',96,'全唐诗/poet.song.100000.json','["泊舟華容縣，湖水終夜明。", "凄然不能寐，左右菰蒲聲。", "窮途事多違，勝處亦心驚。", "三更螢火鬧，萬里天河橫。", "阿瞞狼狽地，山澤空崢嶸。", "强弱與興衰，今古莽難評。", "腐儒憂平世，况復值甲兵。", "終然無寸策，白髮滿頭生。"]'),
('0771efe1-ac50-4047-9a41-9a40c5d4c7f0','月夜','陳與義','宋','宋诗','song-poetry','','[]','獨立夜轇轕，蘆聲泛遥津。',96,'全唐诗/poet.song.100000.json','["獨立夜轇轕，蘆聲泛遥津。", "月下風起波，莽莽白龍鱗。", "陰彩凝草木，暑氣森星辰。", "天地塵未消，江湖氣聊伸。", "人生幾今夕，亂代偶此身。", "胡爲不少樂，况乃迹易陳。", "三更大魚舞，悄愴驚心神。", "永懷騎鯨士，發興煙中新。"]'),
('b999ef55-a3bb-497a-b0fa-cd14ae5e169f','晚晴','陳與義','宋','宋诗','song-poetry','','[]','幽卧不知晴，檣梢見斜日。',144,'全唐诗/poet.song.100000.json','["幽卧不知晴，檣梢見斜日。", "披衣起四望，天際山爭出。", "光輝渚蒲凈，意氣沙鷗逸。", "避盜半九圍，兩脚不遺力。", "川陵各異態，艱險常一律。", "胡爲作弧矢，前聖意莫詰。", "豈知百代後，反使姦宄密。", "腐儒徒嘆嗟，救弊知無術。", "人生如歸雲，空行雜徐疾。", "薄暮俱到山，各不見蹤跡。", "念此百年內，可復受憂戚。", "林木方翳然，放懷陶茲夕。"]'),
('a3d90039-66bc-4078-9f9e-aba058919a69','寥落','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','寥落洞庭野，微風泛客裾。',48,'全唐诗/poet.song.100000.json','["寥落洞庭野，微風泛客裾。", "袁宏詠史罷，孫登清嘯餘。", "月明流水去，夜靜芙蓉舒。", "城郭方多事，野興一蕭疏。"]'),
('a8d0074a-3081-4679-9f45-2a13e94d84b9','自五月二日避寇轉徙湖中復從華容道烏沙還郡七月十六日夜半出小江口宿焉徙倚柁樓書事十二句','陳與義','宋','宋诗','song-poetry','','[]','回環三百里，行盡力都窮。',72,'全唐诗/poet.song.100000.json','["回環三百里，行盡力都窮。", "巴丘左移右，章華西轉東。", "江聲摇斗柄，秋色彌葭叢。", "羣木立波上，芙蕖披月中。", "鏡湖應足比，剡溪那可同。", "世將非識事，孤嘯聊延風。"]'),
('f1a62de3-5a57-40b4-bcd4-931d556c0bdf','閏八月十二日過奇父共坐翠竇軒賞木犀花玲瓏滿枝光氣動人念風日不貸此花無五日香矣而王使君未之知作小詩報之','陳與義','宋','宋诗','song-poetry','','[]','清露香浮黄玉枝，使君未到意低迷。',32,'全唐诗/poet.song.100000.json','["清露香浮黄玉枝，使君未到意低迷。", "極知有日交銅虎，可使無情向木犀。"]'),
('82386d11-ee50-4899-a04a-2c3426ee6dbb','再賦二首呈奇父  其一','陳與義','宋','宋诗','song-poetry','','[]','國香薰坐先生醉，秋葉藏花客子迷。',32,'全唐诗/poet.song.100000.json','["國香薰坐先生醉，秋葉藏花客子迷。", "驅使晚風同勝地，東軒不用鎮帷犀。"]'),
('1a9290b9-2335-44fe-89cb-27b76775307e','再賦二首呈奇父  其二','陳與義','宋','宋诗','song-poetry','','[]','香遍東園花一枝，尋花覓路忽成迷。',32,'全唐诗/poet.song.100000.json','["香遍東園花一枝，尋花覓路忽成迷。", "先生莫道心如鐵，喜氣朝來橫角犀。"]'),
('bf3caec4-08c0-4478-b4b4-5e445663afe7','十三日再賦二首其一以贊使君是日對花賦此韻詩筆落縱橫而郡中修水戰之具方大閱於燕公樓下也其一自敘所感憶年十五在杭州始識此花皆三丈高木嘗賦詩焉  其一','陳與義','宋','宋诗','song-poetry','','[]','我丈風流元祐枝，晴軒雨雹筆端迷。',32,'全唐诗/poet.song.100000.json','["我丈風流元祐枝，晴軒雨雹筆端迷。", "從容文武一時了，賦罷木犀觀水犀。"]'),
('559fead7-6067-4cd7-9050-7fc626ca3fde','十三日再賦二首其一以贊使君是日對花賦此韻詩筆落縱橫而郡中修水戰之具方大閱於燕公樓下也其一自敘所感憶年十五在杭州始識此花皆三丈高木嘗賦詩焉  其二','陳與義','宋','宋诗','song-poetry','','[]','武林曾識最高枝，百感重逢歲月迷。',32,'全唐诗/poet.song.100000.json','["武林曾識最高枝，百感重逢歲月迷。", "向日擘牋須彩鳳，如今執楯要文犀。"]'),
('09f3607b-6675-48f2-b623-51e373f8e962','九月八日登高作重九奇父賦三十韻與義拾餘意亦賦十二韻  其一','陳與義','宋','宋诗','song-poetry','','[]','九月風景好，節意滿天涯。',84,'全唐诗/poet.song.100000.json','["九月風景好，節意滿天涯。", "書生尊所聞，登高亂城鴉。", "雖無後乘麗，前驅載黄花。", "兩樓壓波壯，衆澤分夭斜。", "居夷驚有苗，訪古悲章華。", "蕭條湖海事，勝日一笑譁。", "興移三里亭，木影雜蛟蛇。"]'),
('f680f904-30b6-413a-adfc-8e58ef1fa87a','九月八日登高作重九奇父賦三十韻與義拾餘意亦賦十二韻  其二','陳與義','宋','宋诗','song-poetry','','[]','二士醉藜杖，兩禪風袈裟。',60,'全唐诗/poet.song.100000.json','["二士醉藜杖，兩禪風袈裟。", "奇哉古無有，未覺欠孟嘉。", "天公亦喜我，催詩出微霞。", "賦罷迹已陳，憂樂如轉車。", "却後五百歲，遠俗增雄誇。"]'),
('a1b4ecaf-fd44-4ae3-9d24-13fefa62fcbb','兩絕句  其一','陳與義','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','西風吹日弄晴陰，酒罷三巡湖海深。',32,'全唐诗/poet.song.100000.json','["西風吹日弄晴陰，酒罷三巡湖海深。", "岳陽樓上登高節，不負南來萬里心。"]'),
('b54eb0f0-e81f-4d29-afc9-442b4760373e','兩絕句  其二','陳與義','宋','宋诗','song-poetry','','[]','二士相隨風滿巾，兩禪同隊景彌新。',32,'全唐诗/poet.song.100000.json','["二士相隨風滿巾，兩禪同隊景彌新。", "但得黄花不牢落，莫嫌驚倒岳州人。"]'),
('1a0c6533-3bdc-4137-8bd4-5455b9359f80','粹翁用奇父韻賦九日與義同賦兼呈奇父','陳與義','宋','宋诗','song-poetry','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','安隱輕節序，艱難惜歡娛。',288,'全唐诗/poet.song.100000.json','["安隱輕節序，艱難惜歡娛。", "先生守苜蓿，朝士誇茱萸。", "前年鄧州城，風雨傾客居。", "何嘗疏麯生，麯生自我疏。", "豈無登高地，送目與雲俱。", "門生及兒子，勸我升籃輿。", "出門復入門，戈旆填街衢。", "去年郢州岸，孤檝對壞郛。", "莫招大夫魂，誰攬使君鬚。", "獨題懷古句，枯硯生明珠。", "亦復躋荒戍，日暮野踟躕。", "白衣終不至，眇眇空愁予。", "今年洞庭上，九折餘崎嶇。", "時憑岳陽樓，山川看縈紆。", "孫兄語蟬連，王丈色敷腴。", "不用踏筵舞，秋風摇菊株。", "樂哉未曾有，是夢其非歟。", "丈夫各堂堂，坐受世故驅。", "會須明年節，醉倒還相扶。", "此花期復對，勿令墮空虛。", "明日風景佳，南翔先一鳧。", "可言知機早，政爾因鱸魚。", "分襟肺肝熱，撫事歲月迂。", "歸家問瓶錫，生理何必餘。"]'),
('284a192f-8fcd-4b17-bd14-7edfacd70078','送王因叔赴試','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','楓落南紀明，秋高洞庭白。',56,'全唐诗/poet.song.100000.json','["楓落南紀明，秋高洞庭白。", "自是天涯人，更送湖上客。", "人生險易乘除裏，富貴功名從此始。", "不須惜別作酸然，滿路新詩付吾子。"]'),
('9e95c63b-18be-4eae-ad98-b0a1efb4371d','己酉九月自巴丘過湖南別粹翁','陳與義','宋','宋诗','song-poetry','','[]','離合不可常，去處兩無策。',96,'全唐诗/poet.song.100000.json','["離合不可常，去處兩無策。", "眇眇孤飛雁，嚴霜欺羽翼。", "使君南道主，終歲好看客。", "江湖尊前深，日月夢中疾。", "世事不相貸，秋風撼瓶錫。", "南雲本同征，變化知無極。", "四年孤臣淚，萬里遊子色。", "臨別不得言，清愁漲胸臆。"]'),
('a4bf411b-ff9a-48cc-bdba-9e02e03ec1dd','留別康元質教授','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','腐儒身世已百憂，此去行年豈堪記。',64,'全唐诗/poet.song.100000.json','["腐儒身世已百憂，此去行年豈堪記。", "岳陽樓前一杯酒，與子同州復同味。", "洞庭秋氣連蒼梧，天高地遠魚龍呼。", "莫倚仲宣能作賦，不隨文若事征途。"]'),
('d620b012-1d90-4562-8da2-d8cbf4245560','留別天寧永慶乾明金鑾四老','陳與義','宋','宋诗','song-poetry','','[]','我生能幾何，兩脚疲世故。',96,'全唐诗/poet.song.100000.json','["我生能幾何，兩脚疲世故。", "忽破巴丘夢，還尋邵陽路。", "窮鄉得四老，足以慰遲暮。", "勝事遠公蓮，深心懶殘芋。", "本是羣山雲，蹔聚當別去。", "那知天風便，不得還相聚。", "凡情我未免，臨別吐幽句。", "慎勿過虎溪，曉霜侵杖屨。"]'),
('44c5840b-3f82-4428-996d-b7036610f9eb','別岳州','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','朝食三斗葱，暮飲三斗醋。',144,'全唐诗/poet.song.100000.json','["朝食三斗葱，暮飲三斗醋。", "寧受此酸辛，莫行歲晚路。", "丈夫少壯日，忍窮不自恕。", "乘除冀晚泰，乃復逢變故。", "經年岳陽樓，不見宮南樹。", "辭巢已萬里，兩脚未遑住。", "水落君山高，洞庭秋已素。", "浮雲易歸岫，遠客難回顧。", "飄然一瓶錫，未知所掛處。", "寂寞短歌行，蕭條遠遊賦。", "學道始恨晚，爲儒孰非腐。", "乾坤杳茫茫，三嘆出門去。"]'),
('188a743c-6954-43cd-aebb-22813796b7d8','奇父先至湘陰書來戒由祿唐路而僕以它故由南陽路來夾道皆松如行青羅步障中先寄奇父','陳與義','宋','宋诗','song-poetry','','[]','雲接湘陰百里松，肅肅穆穆湖南風。',64,'全唐诗/poet.song.100000.json','["雲接湘陰百里松，肅肅穆穆湖南風。", "隨時憂樂非人世，迎我笙簫起道中。", "竹輿兩面天明滅，秋令不到林西東。", "未必祿唐能辦此，題詩著畫寄興公。"]'),
('b00d3783-0e0c-4e6b-a517-262b23f6f1cb','初識茶花','陳與義','宋','宋诗','song-poetry','','[]','伊軋籃輿不受催，湖南秋色更佳哉。',32,'全唐诗/poet.song.100000.json','["伊軋籃輿不受催，湖南秋色更佳哉。", "青裙玉面初相識，九月茶花滿路開。"]'),
('576bf6b6-8dad-461c-864f-57705f86ac18','以玉剛卯爲向伯共生朝','陳與義','宋','宋诗','song-poetry','','[]','仲冬吉日，風穆氣休。',80,'全唐诗/poet.song.100000.json','["仲冬吉日，風穆氣休。", "我出剛卯，以壽元侯。", "祝融之玉，莫此離方。", "元侯佩之，如玉之剛。", "攘除厲凶，以迪明王。", "南門不鍵，有室則强。", "三肅元侯，既贈既禱。", "曷以報我，當以剛卯。"]'),
('e2421ec3-001b-4598-98b1-71d0c1fb1946','別伯共','陳與義','宋','宋诗','song-poetry','','[]','樽酒相逢地，江楓欲盡時。',48,'全唐诗/poet.song.100000.json','["樽酒相逢地，江楓欲盡時。", "猶能十日客，共出數年詩。", "供世無筋力，驚心有別離。", "好爲南極柱，深慰旅人悲。"]'),
('b12f7912-79b5-4983-9164-bdd01b02c803','再別','陳與義','宋','宋诗','song-poetry','','[]','多難還分手，江邊白髮新。',48,'全唐诗/poet.song.100000.json','["多難還分手，江邊白髮新。", "公爲九州督，我是半途人。", "政爾傾全節，終然却要身。", "平生第溫嶠，未必下張巡。"]'),
('5c04ea47-7ebd-487c-be46-da7ca83908ac','別孫信道','陳與義','宋','宋诗','song-poetry','','[]','萬里鷗仍去，千年鶴未歸。',48,'全唐诗/poet.song.100000.json','["萬里鷗仍去，千年鶴未歸。", "極知身有幾，不奈世相違。", "歲暮蒹葭響，天長鴻雁微。", "如君那可別，老淚欲霑衣。"]'),
('ffc916e7-cc1c-4706-b982-80473806e17d','遊道林嶽麓','陳與義','宋','宋诗','song-poetry','','["\u8861\u5c71"]','耽耽衡山麓，翠氣橫古今。',120,'全唐诗/poet.song.100000.json','["耽耽衡山麓，翠氣橫古今。", "濟勝得短筇，未怕山行深。", "路盤天開闔，風動龍噫吟。", "峯戀慘澹處，照以布地金。", "世尊諸天上，燕坐朝千林。", "向來修何行，不受安危侵。", "道人輕殊勝，來客費幽尋。", "恍然結願香，獨會三生心。", "山中日易晚，坐失羣木陰。", "勿唾此山地，後日重窺臨。"]'),
('af5850a3-55ca-4381-9d11-eacd4c6344f7','江行野宿寄大光','陳與義','宋','宋诗','song-poetry','','[]','檣烏送我入蠻鄉，天地無情白髮長。',64,'全唐诗/poet.song.100000.json','["檣烏送我入蠻鄉，天地無情白髮長。", "萬里回頭看北斗，三更不寐聽鳴榔。", "平生正出元子下，此去還經思曠傍。", "投老相逢難衮衮，共恢詩律撼瀟湘。"]'),
('f0cde49c-0bfd-4794-82c7-2a7e935d9253','寄信道','陳與義','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衡山未見意如飛，浩蕩風帆不可期。',64,'全唐诗/poet.song.100000.json','["衡山未見意如飛，浩蕩風帆不可期。", "却憶府中三語掾，空吟江上四愁詩。", "高灘落日光零亂，遠岸叢梅雪陸離。", "剩欲平分持寄子，白頭才盡只成悲。"]'),
('d00a8bd1-2215-4e30-824a-f83421f60e21','適遠','陳與義','宋','宋诗','song-poetry','','[]','處處非吾土，年年備虜兵。',48,'全唐诗/poet.song.100000.json','["處處非吾土，年年備虜兵。", "何妨更適遠，未免一傷情。", "石岸煙添色，風灘暮有聲。", "平生五字律，頭白不貪名。"]'),
('a25a526d-a67a-428e-8859-20cce6d96dcf','衡嶽道中  其一','陳與義','宋','宋诗','song-poetry','','[]','野客元耕崧嶽田，得遊衡岳亦前緣。',64,'全唐诗/poet.song.100000.json','["野客元耕崧嶽田，得遊衡岳亦前緣。", "避兵徑度吾豈忍，欲雨還休神所憐。", "世亂不妨松偃蹇，村空更覺水潺湲。", "非無拄杖終傷老，負此名山四十年。"]'),
('467eb8f8-4f51-40a6-9924-1977eca0dd2c','衡嶽道中  其二','陳與義','宋','宋诗','song-poetry','','[]','客子山行不覺風，龍吟虎嘯滿山松。',32,'全唐诗/poet.song.100000.json','["客子山行不覺風，龍吟虎嘯滿山松。", "綸巾一幅無人識，勝業門前聽午鍾。"]'),
('e2e030f7-19a3-4583-9975-5bee7c1cb79c','衡嶽道中  其三','陳與義','宋','宋诗','song-poetry','','["\u8861\u5c71"]','城中望衡山，浮雲作飛蓋。',24,'全唐诗/poet.song.100000.json','["城中望衡山，浮雲作飛蓋。", "朅來岩谷遊，却在浮雲外。"]'),
('ee565085-edd1-42cf-9c39-5abe7ec48498','衡嶽道中  其四','陳與義','宋','宋诗','song-poetry','','[]','危亭見上方，林壑带殘陽。',24,'全唐诗/poet.song.100000.json','["危亭見上方，林壑带殘陽。", "今日豈無恨，重遊却味長。"]'),
('a72b0a22-2781-46fb-94fa-5e5b02ac7e39','跋任才仲畫兩首  其一','陳與義','宋','宋诗','song-poetry','','[]','遠遊吾不恨，扁舟載幅巾。',48,'全唐诗/poet.song.100000.json','["遠遊吾不恨，扁舟載幅巾。", "山色暮暮改，林氣朝朝新。", "野客初逢句，薄暮欲生春。", "因知子任子，胸懷非世人。"]'),
('603abee7-a3be-4461-b63b-0f73f59345f3','跋任才仲畫兩首  其二','陳與義','宋','宋诗','song-poetry','','[]','前年與孫子，共作南山客。',48,'全唐诗/poet.song.100000.json','["前年與孫子，共作南山客。", "扶疏月下樹，偃蹇澗邊石。", "賦詩題古蘚，三叫風脫幘。", "任子不同遊，毫端有疇昔。"]'),
('6d9f8af2-bce5-4c3f-b626-e6f768ef1b40','跋江都王馬','陳與義','宋','宋诗','song-poetry','','[]','天上房星空不動，人間畫馬亦難逢。',32,'全唐诗/poet.song.100000.json','["天上房星空不動，人間畫馬亦難逢。", "當年筆下千金鹿，此日窗前八尺龍。"]'),
('efde72bc-d84d-481f-96ab-d930b164af0d','與王子煥席大光同遊廖園','陳與義','宋','宋诗','song-poetry','','[]','三枝筇竹興還新，王丈席兄俱可人。',32,'全唐诗/poet.song.100000.json','["三枝筇竹興還新，王丈席兄俱可人。", "僑立司州溪水上，吟詩把酒對青春。"]'),
('ee276631-ba67-464f-a4e9-a89531321c12','除夜次大光韻大光是夕婚','陳與義','宋','宋诗','song-poetry','','[]','一杯節酒莫留殘，坐看新年上鬢端。',32,'全唐诗/poet.song.100000.json','["一杯節酒莫留殘，坐看新年上鬢端。", "只恐梅花明日老，夜瓶相對不知寒。"]'),
('0212dc2b-90e8-4f11-a0c2-84171768c1f0','除夜不寐飲酒一杯明日示大光','陳與義','宋','宋诗','song-poetry','','[]','萬里鄉山路不通，年年佳節百憂中。',32,'全唐诗/poet.song.100000.json','["萬里鄉山路不通，年年佳節百憂中。", "催成客睡須春酒，老却梅花是曉風。"]'),
('7b4c9084-96b1-4baa-b9f2-550fcdd980e5','元日','陳與義','宋','宋诗','song-poetry','','[]','五年元日只流離，楚俗今年事事非。',64,'全唐诗/poet.song.100000.json','["五年元日只流離，楚俗今年事事非。", "後飲屠蘇驚已老，長乘舴艋竟安歸。", "携家作客真無策，學道刳心却自違。", "汀草岸花知節序，一身千恨獨霑衣。"]'),
('7e55fee0-4c9f-4879-9177-cab8cfd27884','別大光','陳與義','宋','宋诗','song-poetry','','["\u8861\u5c71"]','堂堂一年長，渺渺三秋闊。',120,'全唐诗/poet.song.100000.json','["堂堂一年長，渺渺三秋闊。", "恍然衡山前，相遇各白髮。", "歲窮窗欲霰，人老情難竭。", "君有杯中物，我有肝肺熱。", "飲盡不能起，交深忘事拙。", "乾坤日多虞，遊子屢驚骨。", "衡陽非不遥，雁意猶超忽。", "一生能幾回，百計易相奪。", "滔滔江受風，耿耿客孤發。", "他夕懷君子，巖間望明月。"]'),
('08a4f934-11e3-4cab-b4e0-993a220fa92a','道中','陳與義','宋','宋诗','song-poetry','','[]','雨子收還急，溪流直又斜。',48,'全唐诗/poet.song.100000.json','["雨子收還急，溪流直又斜。", "迢迢傍山路，漠漠滿林花。", "破水雙鷗影，掀泥百草芽。", "川原有高下，隨處著人家。"]'),
('4410bee9-d3ec-4569-a211-0ea96a51d8a7','金潭道中','陳與義','宋','宋诗','song-poetry','','[]','晴路籃輿穩，舉頭閑望賒。',48,'全唐诗/poet.song.100000.json','["晴路籃輿穩，舉頭閑望賒。", "前岡春泱漭，後嶺雪槎牙。", "海內兵猶壯，村邊歲自華。", "客行驚節序，回眼送桃花。"]'),
('edebbaa3-db3e-4cd5-b2ae-16134bdc96c4','絕句','陳與義','宋','宋诗','song-poetry','','[]','野鴨飛無數，桃花濕滿枝。',24,'全唐诗/poet.song.100000.json','["野鴨飛無數，桃花濕滿枝。", "竹輿鳴細雨，山客有新詩。"]'),
('bf301a2a-f3b6-4c41-a053-347e5c681505','甘棠道中','陳與義','宋','宋诗','song-poetry','','[]','笋輿礙石一悠然，正月微風意已便。',32,'全唐诗/poet.song.100000.json','["笋輿礙石一悠然，正月微風意已便。", "桃花向來渾不數，山中時見絕堪憐。"]'),
('e285a4eb-6868-491e-b636-a34817e68024','將至杉木鋪望野人居','陳與義','宋','宋诗','song-poetry','','[]','春風漠漠野人居，若使能詩我不如。',32,'全唐诗/poet.song.100000.json','["春風漠漠野人居，若使能詩我不如。", "數株蒼檜遮官道，一樹桃花映草廬。"]'),
('dabaa6e3-9ed4-4de8-8fb1-db96c8a1181f','曉發杉木','陳與義','宋','宋诗','song-poetry','','[]','古澤春光淡，高林露氣清。',48,'全唐诗/poet.song.100000.json','["古澤春光淡，高林露氣清。", "紛紛世上事，寂寂水邊行。", "客子凋雙鬢，田家自一生。", "有詩還忘記，無酒却思傾。"]'),
('e3a81824-34ec-49dc-85d6-b33f58dd56f9','先寄邢子友','陳與義','宋','宋诗','song-poetry','','[]','作客經年樂有餘，邵陽歧路不崎嶇。',64,'全唐诗/poet.song.100000.json','["作客經年樂有餘，邵陽歧路不崎嶇。", "山川好處欹紗帽，桃李香中度笋輿。", "欲見舊交驚歲月，剩排幽話說艱虞。", "人間書疏非吾事，一首新詩未可無。"]'),
('1eca6ac7-ed1a-479d-9407-7d4e249bab32','立春日雨','陳與義','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衡山縣下春日雨，遠映青山絲樣斜。',64,'全唐诗/poet.song.100000.json','["衡山縣下春日雨，遠映青山絲樣斜。", "容易江邊欺客袂，分明沙際濕年華。", "竹林路隔生新水，古渡船空集亂鴉。", "未暇獨憂巾一角，西溪當有續開花。"]'),
('ac45f129-3dd3-41c7-b864-c34ec3b85ee7','正月十二日至邵州十三日夜暴雨滂沱','陳與義','宋','宋诗','song-poetry','','[]','邵州正月風氣殊，鶉尾之南更山塢。',64,'全唐诗/poet.song.100000.json','["邵州正月風氣殊，鶉尾之南更山塢。", "昨日已見三月花，今夜還聞五更雨。", "牋與天公一破顔，走避北狄趨南蠻。", "夢到龍門聽澗水，覺來檐溜正潺潺。"]'),
('08fbb7be-686a-4769-af11-a3649cbbab5a','初至邵陽逢入桂林使作書問其地之安危','陳與義','宋','宋诗','song-poetry','','[]','湖北彌年所，長沙費月餘。',48,'全唐诗/poet.song.100000.json','["湖北彌年所，長沙費月餘。", "初爲邵陽夢，又作桂林書。", "老矣身安用，飄然計本疏。", "管寧遼海上，何得便端居。"]'),
('3c1761fb-def1-4f1c-a9bf-b6beaee001b7','舟泛邵江','陳與義','宋','宋诗','song-poetry','','[]','老去作新夢，邵江非舊聞。',48,'全唐诗/poet.song.100000.json','["老去作新夢，邵江非舊聞。", "灘前群鷺起，柁尾川華分。", "落花棲客鬢，孤舟遡歸雲。", "快然心自足，不獨避囂紛。"]'),
('e7b88829-14d8-4e94-a002-a78fe846c040','過孔雀灘贈周靜之','陳與義','宋','宋诗','song-poetry','','[]','海內無堅壘，天涯有近親。',48,'全唐诗/poet.song.100000.json','["海內無堅壘，天涯有近親。", "不辭供笑語，未慣得殷勤。", "舟楫深宜客，溪山各放春。", "高眠過灘浪，已寄百年身。"]'),
('64d97ec1-abee-4652-a8d6-ec596b858cde','江行晚興','陳與義','宋','宋诗','song-poetry','','[]','曾聽石樓水，今過邵州灘。',72,'全唐诗/poet.song.100000.json','["曾聽石樓水，今過邵州灘。", "一笑供舟子，五年經路難。", "雲間落日淡，山下東風寒。", "煙嶺叢花照，夕灣群鷺盤。", "生身後聖哲，隨俗了悲歡。", "淹旅非吾病，悠悠良足歎。"]'),
('40ebb252-f93b-4dbc-8ac5-16682ef0d620','夜抵貞牟','陳與義','宋','宋诗','song-poetry','','[]','野暝猶聞遠，川明不恨遲。',48,'全唐诗/poet.song.100000.json','["野暝猶聞遠，川明不恨遲。", "焚山隔岸火，及我繫船時。", "夜半青燈屋，籬前白水陂。", "殷勤謝地主，小築欲深期。"]'),
('daa2eb28-92fe-44ab-a405-40369e214a93','晚步','陳與義','宋','宋诗','song-poetry','','[]','畎畝意不釋，出門聊散憂。',48,'全唐诗/poet.song.100000.json','["畎畝意不釋，出門聊散憂。", "雨餘山欲近，春半水爭流。", "衆籟夕還作，孤懷行轉幽。", "溪西篁竹亂，微徑雜歸牛。"]'),
('9f4c8648-3ec2-49f0-b97f-1d396cc8cf69','雨','陳與義','宋','宋诗','song-poetry','','[]','雲物澹清曉，無風溪自閑。',48,'全唐诗/poet.song.100000.json','["雲物澹清曉，無風溪自閑。", "柴門對急雨，壯觀滿空山。", "春發蒼茫內，鳥鳴篁竹間。", "兒童笑老子，衣濕不知還。"]'),
('bb8c9a66-ec6b-465d-bf94-2079a4b0a3fc','今夕','陳與義','宋','宋诗','song-poetry','','[]','今夕定何夕，對此山蒼然。',48,'全唐诗/poet.song.100000.json','["今夕定何夕，對此山蒼然。", "偷生經五載，幽意獨已堅。", "微陰拱衆木，靜夜聞孤泉。", "唯應寂寞事，可以送餘年。"]'),
('a58659f5-f9c0-4deb-825b-b1e4e0b54eed','暝色','陳與義','宋','宋诗','song-poetry','','[]','殘輝度平野，列岫圍青春。',96,'全唐诗/poet.song.100000.json','["殘輝度平野，列岫圍青春。", "柴門一枝筇，日暮棲心神。", "暝色著川嶺，高低鬰輪囷。", "水光忽倒樹，山勢欲傍人。", "萬化元相尋，幽子意自新。", "肅肅夜將久，空明動邊垠。", "田鶴吟相應，我獨無荒鄰。", "短篇不可就，所寄聊一伸。"]'),
('b3f07a96-1c4e-464e-8ca2-d575c47d66db','貞牟書事','陳與義','宋','宋诗','song-poetry','','[]','留侯辟穀年，漢鼎無餘功。',108,'全唐诗/poet.song.100000.json','["留侯辟穀年，漢鼎無餘功。", "子真策不售，脫迹市門中。", "神仙非異人，由來本英雄。", "撫世獨餘事，用舍何必同。", "眷此貞牟野，息駕吾其終。", "蒼山雨中高，緣草溪上豐。", "仲春水木麗，禽鳴清晝風。", "禍福兩合繩，既解一身空。", "榮華信非貴，寂寞亦非窮。"]'),
('f3dd973e-0794-4f8f-a531-eebdf8376f88','山中','陳與義','宋','宋诗','song-poetry','','[]','當復入州寬作期，人間踏地有安危。',64,'全唐诗/poet.song.100000.json','["當復入州寬作期，人間踏地有安危。", "風流丘壑真吾事，籌策廟堂非所知。", "白水春陂天澹澹，蒼峯晴雪錦離離。", "恰逢居士身輕日，正是山中多景時。"]'),
('afa0aa97-2e1c-4ab2-b9d6-b008a0d49e37','入城','陳與義','宋','宋诗','song-poetry','','[]','舴艋泝溪來，款段踏山去。',72,'全唐诗/poet.song.100000.json','["舴艋泝溪來，款段踏山去。", "入城緣底事，要識崎嶇路。", "稻塍白縱橫，茅嶺青盤互。", "牧兒歌不休，孤客自多懼。", "士行猶運甓，文公亦習步。", "我敢忘艱難，衝煙問荒渡。"]'),
('8a776cc9-49d1-4ef1-801b-fbd9abbbe22c','謝主人','陳與義','宋','宋诗','song-poetry','','[]','春禽勸我歸，主人留我住。',56,'全唐诗/poet.song.100000.json','["春禽勸我歸，主人留我住。", "一笑謝主人，我自歸無處。", "擬借溪邊三畝春，結茅依樹不依鄰。", "伐薪政可煩名士，分米何須待故人。"]'),
('2fb24003-d6ef-43ac-95c8-a01a398817ca','羅江二絕  其一','陳與義','宋','宋诗','song-poetry','','[]','荒村終日水車鳴，陂北陂南共一聲。',32,'全唐诗/poet.song.100000.json','["荒村終日水車鳴，陂北陂南共一聲。", "灑面風吹作飛雨，老夫詩到此間成。"]'),
('c36dc718-998d-40fe-8683-43cef591849f','羅江二絕  其二','陳與義','宋','宋诗','song-poetry','','[]','山翁見客亦欣然，好語重重意不傳。',32,'全唐诗/poet.song.100000.json','["山翁見客亦欣然，好語重重意不傳。", "行過竹籬逢細雨，眼明雙鷺立青田。"]'),
('9a5e50a8-8278-4254-b515-79050c38067d','洛頭書事','陳與義','宋','宋诗','song-poetry','','[]','綸巾古鶴氅，日暮槲林間。',48,'全唐诗/poet.song.100000.json','["綸巾古鶴氅，日暮槲林間。", "誰使翁迎客，應聞屐響山。", "占年又得熟，勸我不須還。", "村酒困壯士，水風吹醉顔。"]'),
('d44d6239-deac-4672-a7c3-2a2898575779','三月二十日聞德音寄李德升席大光新有召命皆寓永州','陳與義','宋','宋诗','song-poetry','','[]','塵隔斗牛三月餘，德音再與萬方初。',64,'全唐诗/poet.song.100000.json','["塵隔斗牛三月餘，德音再與萬方初。", "又蒙天地寬今歲，且掃軒窗讀我書。", "自古安危關政事，隨時憂喜到樵漁。", "零陵併起扶顛手，九廟無歸計莫疏。"]'),
('f1fcebc7-85eb-47d1-ba57-df8794f6709b','夏夜','陳與義','宋','宋诗','song-poetry','','[]','遠遊萬事裂，獨立數峯青。',48,'全唐诗/poet.song.100000.json','["遠遊萬事裂，獨立數峯青。", "明月照山木，荒村饒夜螢。", "翻翻雲渡漢，歷歷水浮星。", "遥舍燈已盡，幽人門未扃。"]'),
('5d86dede-8835-47fb-9d04-f1de24026569','題東家壁','陳與義','宋','宋诗','song-poetry','','[]','斜陽步屧過東家，便置清樽不煮茶。',64,'全唐诗/poet.song.100000.json','["斜陽步屧過東家，便置清樽不煮茶。", "高柳光陰初罷絮，嫩鳧毛羽欲成花。", "群公天上分時棟，閑客江邊管物華。", "醉裏吟詩空跌宕，借君素壁落栖鴉。"]'),
('fd3d520d-1dbc-4fd4-9e2a-ca2fda05af3a','曳杖','陳與義','宋','宋诗','song-poetry','','[]','柳條一何長，我髮一何短。',72,'全唐诗/poet.song.100000.json','["柳條一何長，我髮一何短。", "餘日會有幾，經春卧荒疃。", "曳杖陂西去，悠然寄蕭散。", "田垅粲高低，白水一時滿。", "農夫暮猶作，愧我讀書懶。", "且復棄今茲，前峯青蹇嵼。"]'),
('3d5aba6b-b94c-4e43-a62d-ab2b4f841c2d','雷行雨庚戌歲聞赦作','陳與義','宋','宋诗','song-poetry','','[]','憶昨炎正中不融，元帥仗鉞臨山東。',211,'全唐诗/poet.song.100000.json','["憶昨炎正中不融，元帥仗鉞臨山東。", "萬方嗷嗷叫上帝，黄屋已照睢陽宮。", "嗚呼吾君天所立，豈料四載猶服戎。", "禹巡會稽不到海，未省駕舶觀民風。", "定知諫諍有張猛，不可危急無高共。", "自古美惡周必復，犬羊汝莫窮妖凶。", "吉語四奏元氣通，德音夜發春改容。", "雷雨一日遍天下，父老感泣霑其胸。", "臣少憂國今成翁，欲起荷戟傷疲癃。", "小遊太一未移次，大樹將軍莫振功。", "劉琨祖逖未足雄，晏球一戰腥臊空。", "諸君努力光竹素，天子可使塵常蒙。", "君不見夷門山頭虎復龍，向來佳氣元葱葱。"]'),
('39177900-2e6c-4943-be9d-16589cf9ac7a','開壁置窗命曰遠軒  其一','陳與義','宋','宋诗','song-poetry','','[]','鍾妖鳴吾旁，楊獠舞吾側。',144,'全唐诗/poet.song.100000.json','["鍾妖鳴吾旁，楊獠舞吾側。", "東西俱有礙，群盜何時息。", "丈夫堂堂軀，坐受世褊迫。", "仙人千仞崗，下視笑予厄。", "誰能久鬰鬰，持斧破南壁。", "窗開三尺明，空納萬里碧。", "巖霏雜川靄，奇變供几席。", "誰見老書生，軒中岸玄幘。", "蕩漾浮世裏，超遥送茲夕。", "倚楹發孤嘯，呼月出荒澤。", "天公亦粲然，林壑受珠璧。", "會有鶴駕賓，經過來見客。"]'),
('eb9dfb03-1571-4aa2-8b50-d69343fca504','開壁置窗命曰遠軒  其二','陳與義','宋','宋诗','song-poetry','','[]','清曉坐南軒，望山頭屢側。',144,'全唐诗/poet.song.100000.json','["清曉坐南軒，望山頭屢側。", "居士亦豈癡，飛雲方未息。", "樂哉此遠俗，亂世免怵迫。", "那知百戰禍，豈識三空厄。", "閉門美享睡，開門瞻翠壁。", "遠客謝主人，分此一窗碧。", "新晴鳥鳴檐，微暑風入席。", "蕭然此白首，豈更冒朝幘。", "誓將老茲地，不復數晨夕。", "但恨食無肉，臞仙出山澤。", "蟄雷轉空腸，吐句作圭璧。", "一笑示鄰家，向來無此客。"]'),
('87f803ed-ef47-4d04-9a3b-54819708e4a9','開壁置窗命曰遠軒  其三','陳與義','宋','宋诗','song-poetry','','["\u8861\u5c71"]','我昨在衡山，傷心衢路側。',144,'全唐诗/poet.song.100000.json','["我昨在衡山，傷心衢路側。", "豈知得此地，一坐數千息。", "易安生痛定，過美出饑迫。", "誓言如齊侯，常戒在莒厄。", "要將萬里身，獨面九年壁。", "如何不己奈，開窗玩霏碧。", "招呼面前山，浮翠落衾席。", "一笑等兒戲，都忘雪侵幘。", "人生何不娛，今夕定何夕。", "向來萬頃胸，餘地吞七澤。", "念此亦細事，未遽瑕生璧。", "聊使山中人，永記山下客。"]'),
('d8dbfff6-b18f-479b-a337-07adfceff62f','傷春','陳與義','宋','宋诗','song-poetry','','[]','廟堂無策可平戎，坐使甘泉照夕烽。',64,'全唐诗/poet.song.100000.json','["廟堂無策可平戎，坐使甘泉照夕烽。", "初怪上都聞戰馬，豈知窮海看飛龍。", "孤臣霜髮三千丈，每歲煙花一萬重。", "稍喜長沙向延閣，疲兵敢犯犬羊鋒。"]'),
('5a2e8bfb-22a1-4f81-8e6b-add4b238ddb2','題水西周三十三壁二首  其一','陳與義','宋','宋诗','song-poetry','','[]','不管先生巾欲摧，雨中艇子便撐開。',32,'全唐诗/poet.song.100000.json','["不管先生巾欲摧，雨中艇子便撐開。", "青山隔岸迎人去，白鷺衝煙送酒來。"]'),
('7fb0b0cc-07ba-42d9-a229-974bf85821e8','題水西周三十三壁二首  其二','陳與義','宋','宋诗','song-poetry','','[]','周子篘中早得春，喚人同渡一溪雲。',32,'全唐诗/poet.song.100000.json','["周子篘中早得春，喚人同渡一溪雲。", "貪看雨歇前峯變，不覺斟時已十分。"]'),
('d4cecd75-c4cc-433f-b757-29f1de7fb8e9','山齋  其一','陳與義','宋','宋诗','song-poetry','','[]','夏郊綠已遍，山齋晝自遲。',48,'全唐诗/poet.song.100000.json','["夏郊綠已遍，山齋晝自遲。", "雲物忽分散，餘碧暮逶迤。", "寒暑送萬古，榮枯各一時。", "世紛幸莫及，我麈得常持。"]'),
('d0fb32a8-a62b-4d11-bf8b-bbfc8edfbc67','山齋  其二','陳與義','宋','宋诗','song-poetry','','[]','雖愧荷鉏叟，朝來亦不閑。',48,'全唐诗/poet.song.100000.json','["雖愧荷鉏叟，朝來亦不閑。", "自剪牆角樹，盡納溪西山。", "經行天下半，送老此窗間。", "日暮煙生嶺，離離飛鳥還。"]'),
('97fd8830-c9b2-4c23-b118-7f4674804a10','散髮','陳與義','宋','宋诗','song-poetry','','[]','百年如寄亦何爲，散髮清狂未足非。',64,'全唐诗/poet.song.100000.json','["百年如寄亦何爲，散髮清狂未足非。", "南澗題詩風滿面，東橋行藥露霑衣。", "松花照夏山無暑，桂樹留人吾豈歸。", "藜杖不當軒蓋用，穩扶居士莫相違。"]'),
('f8e3ab57-9501-4bc3-8843-5a323c159121','六月六日夜','陳與義','宋','宋诗','song-poetry','','[]','藴隆豈不壞，凉氣亦徐還。',48,'全唐诗/poet.song.100000.json','["藴隆豈不壞，凉氣亦徐還。", "獨立清夜半，疏星蒼檜間。", "晦明莽相代，天地本長閑。", "四顧何寥落，微風時動關。"]'),
('7084dbae-14e5-4a39-a1ab-e801af2ba882','六月十七夜寄邢子友','陳與義','宋','宋诗','song-poetry','','[]','暑雨雖不足，凉風還有餘。',48,'全唐诗/poet.song.100000.json','["暑雨雖不足，凉風還有餘。", "樂此城陰夜，何殊山崦居。", "月明蒼檜立，露下芭蕉舒。", "試問澄虛閣，今夕復焉如。"]'),
('951844ab-09eb-481f-b447-dbcf5e58d20d','觀雨','陳與義','宋','宋诗','song-poetry','','[]','山客龍鍾不解耕，開軒危坐看陰晴。',64,'全唐诗/poet.song.100000.json','["山客龍鍾不解耕，開軒危坐看陰晴。", "前江後嶺通雲氣，萬壑千林送雨聲。", "海壓竹枝低復舉，風吹山角晦還明。", "不嫌屋漏無乾處，正要群龍洗甲兵。"]'),
('dfba270e-c149-4780-8d33-26b04ac9ba22','寄大光  其一','陳與義','宋','宋诗','song-poetry','','[]','心折零陵霜入鬢，更修短札問何如。',32,'全唐诗/poet.song.100000.json','["心折零陵霜入鬢，更修短札問何如。", "江湖不是無來雁，只慣平生作報書。"]'),
('7f0456dd-70ba-4f92-abde-55ea04bd1bf9','寄大光  其二','陳與義','宋','宋诗','song-poetry','','[]','芭蕉急雨三更鬧，客子殊方五月寒。',32,'全唐诗/poet.song.100000.json','["芭蕉急雨三更鬧，客子殊方五月寒。", "近得會稽消息否，稍傳荆渚路歧寬。"]'),
('8a6982ff-377d-48ad-b734-50ed7394d4ae','寄德升大光','陳與義','宋','宋诗','song-poetry','','[]','君王優詔起群公，也寘樵夫尺一中。',64,'全唐诗/poet.song.100000.json','["君王優詔起群公，也寘樵夫尺一中。", "易著青衫隨世事，難將白髮犯秋風。", "共談太極非無意，能繫蒼生本不同。", "却倚紫陽千丈嶺，遥瞻黄鵠九霄東。"]'),
('1dbe3ab7-75ee-4c71-b010-cc0d4f28495a','次韻謝邢九思','陳與義','宋','宋诗','song-poetry','','[]','平生不接里閭歡，豈料相逢虺蜮壇。',64,'全唐诗/poet.song.100000.json','["平生不接里閭歡，豈料相逢虺蜮壇。", "能賦君推三世事，倦遊我棄七年官。", "流傳惡語知誰好，勾引新篇得細看。", "六月山齋當暑令，風霜獨發卷中寒。"]'),
('06c02472-a009-49d2-b1c5-334033a7cca4','村景','陳與義','宋','宋诗','song-poetry','','[]','黄昏吹角聞呼鬼，清曉持竿看牧鵝。',32,'全唐诗/poet.song.100000.json','["黄昏吹角聞呼鬼，清曉持竿看牧鵝。", "蠶上樓時桑葉少，水鳴車處稻苗多。"]'),
('d3017e59-4268-44b8-bcc2-408ea4208a0d','次周漕示族人韻','陳與義','宋','宋诗','song-poetry','','[]','諫議遺蹤尚可望，曳裾不必效鄒陽。',32,'全唐诗/poet.song.100000.json','["諫議遺蹤尚可望，曳裾不必效鄒陽。", "但修天爵膺人爵，始信書堂有玉堂。"]'),
('ee1cdbdb-7db8-4a36-99a3-c602229c8822','水車','陳與義','宋','宋诗','song-poetry','','[]','江邊終日水車鳴，我自平生愛此聲。',32,'全唐诗/poet.song.100000.json','["江邊終日水車鳴，我自平生愛此聲。", "風月一時都屬客，杖藜聊復寄詩情。"]'),
('ca1ddd87-dd63-4aa1-93e2-06398469d21c','山居二首  其一','陳與義','宋','宋诗','song-poetry','','[]','點檢行年書閥閱，山中共賦幾篇詩。',32,'全唐诗/poet.song.100000.json','["點檢行年書閥閱，山中共賦幾篇詩。", "如今未有驚人句，更待秋風生桂枝。"]'),
('bb3b53a9-83e9-495d-9358-31f3ad2ab8fe','山居二首  其二','陳與義','宋','宋诗','song-poetry','','[]','宅圖不必煩丘令，已卜坡東澗水邊。',32,'全唐诗/poet.song.100000.json','["宅圖不必煩丘令，已卜坡東澗水邊。", "更與我爲燒藥竈，只愁君要買山錢。"]'),
('21b5e4bb-39ec-4980-8576-defaccf0d72f','拜詔','陳與義','宋','宋诗','song-poetry','','[]','紫陽山下聞皇牒，地藏階前拜詔書。',32,'全唐诗/poet.song.100000.json','["紫陽山下聞皇牒，地藏階前拜詔書。", "乍脫綠袍山色翠，新披紫綬佩金魚。"]'),
('1085ae59-6d77-45c1-9ed2-da95c88dae42','別諸周二首  其一','陳與義','宋','宋诗','song-poetry','','[]','風送孤篷不可遮，山中城裏總非家。',32,'全唐诗/poet.song.100000.json','["風送孤篷不可遮，山中城裏總非家。", "臨行有恨君知否，不見籬前稻著花。"]'),
('bc022abb-2625-4a85-8a14-7e7e36981e0f','別諸周二首  其二','陳與義','宋','宋诗','song-poetry','','[]','隴雲知我欲船開，飛過江東還復回。',32,'全唐诗/poet.song.100000.json','["隴雲知我欲船開，飛過江東還復回。", "不似周顒趨闕去，山靈應許却歸來。"]'),
('a1d3c772-a6e4-4e93-8e1e-938f196142b5','題向伯共過峽圖二首  其一','陳與義','宋','宋诗','song-poetry','','[]','旌旗翻日淮南道，興罷歸來雪一船。',32,'全唐诗/poet.song.100000.json','["旌旗翻日淮南道，興罷歸來雪一船。", "正有佛光無處著，獨將佳句了山川。"]'),
('99aeaca6-31dd-44ec-8d6e-2b2f0370d5f1','題向伯共過峽圖二首  其二','陳與義','宋','宋诗','song-poetry','','[]','過峽新圖世所傳，峽中猶說泛舟仙。',32,'全唐诗/poet.song.100000.json','["過峽新圖世所傳，峽中猶說泛舟仙。", "柱天勳業須君了，借我茅齋看十年。"]'),
('2a77c6e5-9970-4bb3-a871-89fd84ab12ae','題趙少隱青白堂三首  其一','陳與義','宋','宋诗','song-poetry','','[]','小謝爲州不廢詩，庭中草木有光輝。',32,'全唐诗/poet.song.100000.json','["小謝爲州不廢詩，庭中草木有光輝。", "一林風露非人世，更著梅花相發揮。"]'),
('03a71c0f-6c6f-4834-9259-70f13b7ebdb5','題趙少隱青白堂三首  其二','陳與義','宋','宋诗','song-poetry','','[]','使君堂上無俗客，白白青青兩勝流。',32,'全唐诗/poet.song.100000.json','["使君堂上無俗客，白白青青兩勝流。", "添得吟詩老居士，千年一笑澤南州。"]'),
('c95ebde1-a45b-432f-9e90-bde2bc07f356','題趙少隱青白堂三首  其三','陳與義','宋','宋诗','song-poetry','','[]','雪裏芭蕉摩詰畫，炎天梅蕊簡齋詩。',32,'全唐诗/poet.song.100000.json','["雪裏芭蕉摩詰畫，炎天梅蕊簡齋詩。", "它時相見非生客，看倚瑯玕一段奇。"]'),
('3f417625-9cb4-451e-a72c-5b264d472371','次韻邢九思','陳與義','宋','宋诗','song-poetry','','[]','百年鼎鼎雜悲歡，老去初依六祖壇。',64,'全唐诗/poet.song.100000.json','["百年鼎鼎雜悲歡，老去初依六祖壇。", "玄晏不堪長抱病，子真那復更爲官。", "山林未必容身得，顔面何宜與世看。", "白帝高尋最奇事，共君盟了不應寒。"]'),
('b474a47f-9f1e-40a9-8fb2-2d1953deabd5','遥碧軒作呈使君少隱時欲赴召','陳與義','宋','宋诗','song-poetry','','[]','我本山中人，尺一喚起趨埃塵。',108,'全唐诗/poet.song.100000.json','["我本山中人，尺一喚起趨埃塵。", "君爲邊城守，作意邀山入窗牖。", "朝來爽氣如有期，送我憑軒一杯酒。", "丈夫已忍猿鶴羞，欲去且復斯須留。", "西峯木脫亂鬟擁，東嶺煙破修眉浮。", "主人愛客山更好，醉裏一笑驚蠻州。", "丁寧雲雨莫作厄，明日青山當送客。"]'),
('4bea8a52-868d-4512-8684-519e08da9a45','石限病起','陳與義','宋','宋诗','song-poetry','','[]','幽人病起山深處，小院鴉鳴日午時。',32,'全唐诗/poet.song.100000.json','["幽人病起山深處，小院鴉鳴日午時。", "六尺屏風遮宴坐，一簾細雨獨題詩。"]'),
('a86491e6-98c5-4b8a-8901-718069bb2a3c','同范直愚單履遊浯溪','陳與義','宋','宋诗','song-poetry','','[]','瀟湘之流碧復碧，上有鐵立千尋壁。',96,'全唐诗/poet.song.100000.json','["瀟湘之流碧復碧，上有鐵立千尋壁。", "河朔功就人與能，湖南碑成江動色。", "文章得意易爲好，書雜矛劍天假力。", "四百年來如創見，雷公雨師知此石。", "小儒五載憂國淚，杖藜今日溪水側。", "欲搜奇句謝兩公，風作浪湧空心惻。"]'),
('87fcb027-1043-4bab-a5e9-54cd1daa7b3a','愚溪','陳與義','宋','宋诗','song-poetry','','[]','小閣當喬木，清溪抱竹林。',48,'全唐诗/poet.song.100000.json','["小閣當喬木，清溪抱竹林。", "寒聲日暮起，客思雨中深。", "行李妨幽事，欄干試獨臨。", "終然遊子意，非復昔人心。"]'),
('a54bbfc7-e904-4a1a-93d2-4e4803b9565e','己酉中秋之夕與任才仲醉於岳陽樓上明年十一月二十日南遊過道謁姜光彥出才仲畫軸則寫是夕事也剪燭觀之恍然一笑書八句以當畫記','陳與義','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','去年中秋洞庭野，寒瑶萬頃兼天瀉。',64,'全唐诗/poet.song.100000.json','["去年中秋洞庭野，寒瑶萬頃兼天瀉。", "岳陽樓上兩幅巾，月入欄干影瀟灑。", "世間此影誰能孤，狂如我友人所無。", "一夢經年無續處，道州還見倚樓圖。"]'),
('4f6228b8-01e0-4079-8083-32b40795c672','甘泉吳使君使畫史作簡齋居士像居士見之大笑如洞山過水睹影時也戲書三十二字','陳與義','宋','宋诗','song-poetry','','[]','兩眉軒然，意像無寄。',40,'全唐诗/poet.song.100000.json','["兩眉軒然，意像無寄。", "而服如此，又不離世。", "鑑中壁上，處處皆是。", "簡齋雖傳，文殊無二。"]'),
('4d09c5f2-d914-4b86-b3fb-d622aa149ab6','題甘泉書院','陳與義','宋','宋诗','song-poetry','','[]','甘泉坊裏林影黑，吳氏舍前書榜鮮。',64,'全唐诗/poet.song.100000.json','["甘泉坊裏林影黑，吳氏舍前書榜鮮。", "床座畧容摩詰借，桂枝應待小山傳。", "兵橫海內猶紛若，風到湖南還穆然。", "勉效周生述孔業，賦詩吾獨愧先賢。"]'),
('aecdefab-2d63-4057-bd6c-ebd9daa36b25','度嶺一首','陳與義','宋','宋诗','song-poetry','','[]','年律將窮天地溫，兩州風氣此橫分。',64,'全唐诗/poet.song.100000.json','["年律將窮天地溫，兩州風氣此橫分。", "已吟子美湖南句，更擬東坡嶺外文。", "隔水叢梅疑是雪，近人孤嶂欲生雲。", "不愁去路三千里，少住林間看夕曛。"]'),
('c32d42ea-0258-4e74-98d8-de728e0ad402','遊秦巖','陳與義','宋','宋诗','song-poetry','','[]','秦巖昧舊聞，勝會非復常。',240,'全唐诗/poet.song.100000.json','["秦巖昧舊聞，勝會非復常。", "異哉五里秘，發此一日狂。", "篝燈破大陰，拄杖入仙鄉。", "散途楊梅實，承磴菡萏房。", "石液白瑶墮，泉氣青霓翔。", "度危心欲動，逢衍興未央。", "眩人黝谷深，覆我翠極長。", "降登窮田垅，開闔到鞠場。", "龍遮側岸路，貓護高廩藏。", "力士倒履空，應真儼成行。", "碾缺神所吝，帳空仙莫量。", "水鳴泬寥內，柱立森羅傍。", "語聞受遠響，力極生微陽。", "夢中出小竇，立處忽大荒。", "塵緣信深重，仙事豈渺茫。", "靈武唐業開，湘濱耀文章。", "望夷秦政壞，嶺底畏禍殃。", "隱顯非士意，安危存國綱。", "且復置此事，更將適何方。", "賦詩意未愜，吾欲棲僧廊。"]'),
('2ccbe19d-8609-4812-8022-c971af84954d','戲大光送酒','陳與義','宋','宋诗','song-poetry','','[]','折得嶺頭如玉梅，對花那得欠清杯。',32,'全唐诗/poet.song.100000.json','["折得嶺頭如玉梅，對花那得欠清杯。", "不煩白水真人力，便有青州從事來。"]'),
('73a6fdce-2e1f-488b-94aa-ddc86b724a95','次韻謝呂居仁居仁時寓賀州','陳與義','宋','宋诗','song-poetry','','[]','別君不覺歲時荒，豈意相從魑魅鄉。',64,'全唐诗/poet.song.100000.json','["別君不覺歲時荒，豈意相從魑魅鄉。", "篋裏詩書總零落，天涯形貌各昂藏。", "江南今歲無胡虜，嶺表窮冬有雪霜。", "儻可卜鄰吾欲住，草茅爲蓋竹爲梁。"]'),
('7acaa323-9da2-4488-815b-7d6f203dfc6b','舟行遣興','陳與義','宋','宋诗','song-poetry','','[]','會稽尚隔三千里，臨賀初盤一百灘。',64,'全唐诗/poet.song.100000.json','["會稽尚隔三千里，臨賀初盤一百灘。", "殊俗問津言語異，長年爲客路歧難。", "背人山嶺重重去，照鷁梅花樹樹殘。", "酌酒柁樓今日意，題詩船壁後來看。"]'),
('235f602e-ab0a-4c9b-b5e9-44b86c0081fb','康州小舫與耿伯順李德升席大光鄭德象夜語以更長愛燭紅爲韻得更字','陳與義','宋','宋诗','song-poetry','','[]','萬里衣冠京國舊，一船風雨晉康城。',64,'全唐诗/poet.song.100000.json','["萬里衣冠京國舊，一船風雨晉康城。", "燈前顔面重相識，海內艱難各飽更。", "天闊路長吾欲老，夜闌酒盡意還傾。", "明朝古峽蒼煙道，都送新愁入櫓聲。"]'),
('933a248e-7e2b-491e-8f3b-caaa09734024','與大光同登封州小閣','陳與義','宋','宋诗','song-poetry','','[]','去程欲數莽難知，三日封州更作遲。',64,'全唐诗/poet.song.100000.json','["去程欲數莽難知，三日封州更作遲。", "青嶂足稽天下士，錦囊今有嶠南詩。", "共登小閣春風裏，回望中原夕靄時。", "萬本梅花爲我壽，一杯相屬未全癡。"]'),
('ccfe22a1-cef3-439d-92f1-a30141d168b2','登海山樓','陳與義','宋','宋诗','song-poetry','','[]','萬航如鳧鷖，一水如虛空。',96,'全唐诗/poet.song.100000.json','["萬航如鳧鷖，一水如虛空。", "此地接元氣，壓以樓觀雄。", "我來自中州，登臨眩沖融。", "白波動南極，蒼鬢承東風。", "人間路浩浩，海上春濛濛。", "遠遊爲兩眸，豈恤勞我躬。", "仙人欲吾語，薄暮山葱瓏。", "海清無蜃氣，彼固蓬萊宮。"]'),
('0f6ac5be-c047-4c18-a6a8-bc5627d10fa6','次韻大光五羊待耿伯順之作','陳與義','宋','宋诗','song-poetry','','[]','康州艇子來不急，過岸櫓聲空復長。',32,'全唐诗/poet.song.100000.json','["康州艇子來不急，過岸櫓聲空復長。", "百尺樓頭堪望遠，淡煙斜日晚荒荒。"]'),
('82aa5abb-4b8a-41d2-a2bd-bb5bb48f80a8','雨中再賦海山樓詩','陳與義','宋','宋诗','song-poetry','','[]','百尺闌干橫海立，一生襟抱與山開。',64,'全唐诗/poet.song.100000.json','["百尺闌干橫海立，一生襟抱與山開。", "岸邊天影隨潮入，樓上春容带雨來。", "慷慨賦詩還自恨，徘徊舒嘯却生哀。", "滅胡猛士今安有，非復當年單父臺。"]'),
('539f6b82-5f2c-4062-9b15-22e9fb666ba8','題長樂亭','陳與義','宋','宋诗','song-poetry','','[]','遠山雲迷顛，近山浄如沐。',96,'全唐诗/poet.song.100000.json','["遠山雲迷顛，近山浄如沐。", "客子曳竹輿，伊鴉過山麓。", "我行一何遲，時序一何速。", "東風所經過，林水一時綠。", "疏雨忽飛墜，聲在道邊木。", "淑氣自遠歸，光景變川陸。", "遥知存存子，明亦戒征軸。", "霽色雖宜詩，不見此清穆。"]'),
('4546d0b4-a9ef-4768-8dda-112f4dcbc994','和大光道中絕句  其一','陳與義','宋','宋诗','song-poetry','','[]','已費天工十日晴，今朝小雨送潮生。',32,'全唐诗/poet.song.100000.json','["已費天工十日晴，今朝小雨送潮生。", "轉頭雲日還如錦，一抹葱瓏畫不成。"]'),
('2d3b4e34-c75e-420b-be32-efefadfa1491','和大光道中絕句  其二','陳與義','宋','宋诗','song-poetry','','[]','寂寂孤村竹映沙，檳榔迎客當煎茶。',32,'全唐诗/poet.song.100000.json','["寂寂孤村竹映沙，檳榔迎客當煎茶。", "嶺南二月無桃李，夾路松開黄玉花。"]'),
('f0545f43-04dd-480e-a2b5-f4e2c765908f','題長岡亭呈德升大光','陳與義','宋','宋诗','song-poetry','','[]','久客不忘歸，如頭垢思沐。',96,'全唐诗/poet.song.100000.json','["久客不忘歸，如頭垢思沐。", "身行江海濱，夢繞嵩少麓。", "馬何預得失，鵩何了淹速。", "匣中三尺水，瘴雨生新綠。", "胡爲古驛中，坐聽風吟木。", "既非還吳張，亦異赴洛陸。", "兩公茂名實，自是宜鼎軸。", "發發不可遲，帝言頻郁穆。"]'),
('a5bdc111-552d-4d45-b4bf-142eb9c57927','甘棠驛懷李德升席大光','陳與義','宋','宋诗','song-poetry','','[]','破驛難並休，差池便薪水。',72,'全唐诗/poet.song.100000.json','["破驛難並休，差池便薪水。", "山川會心地，還思對君子。", "道邊千尺榕，午蔭清且美。", "極知非世用，我愛不能已。", "東風吹南服，莽莽綠萬里。", "此地亦可耕，胡爲繭予趾。"]'),
('cd770cb6-4487-4c77-bcca-11fb4710ce5c','贈漳州守綦叔厚','陳與義','宋','宋诗','song-poetry','','[]','過盡蠻荒興復新，漳州畫戟擁詩人。',64,'全唐诗/poet.song.100000.json','["過盡蠻荒興復新，漳州畫戟擁詩人。", "十年去國九行旅，萬里逢公一欠伸。", "王粲登樓還感慨，紀瞻赴召欲逡巡。", "繩床相對有今日，剩醉齋中軟脚春。"]'),
('47a9c0a8-579a-4901-8a27-961d2130eedf','宿資聖院閣','陳與義','宋','宋诗','song-poetry','','[]','暮投山崦寺，高處絕人羣。',48,'全唐诗/poet.song.100000.json','["暮投山崦寺，高處絕人羣。", "遠岫林間見，微泉舍後聞。", "閣虛雲亂入，江闊野橫分。", "欲與僧爲記，今年懶作文。"]'),
('143156dc-1d21-44fc-926a-a6094fbee4d9','題大龍湫','陳與義','宋','宋诗','song-poetry','','[]','曉行蒼壁中，窮處仍高崖。',96,'全唐诗/poet.song.100000.json','["曉行蒼壁中，窮處仍高崖。", "白龍三百丈，欲下層顛來。", "映日灑飛雨，繞山行怒雷。", "潭影納浩蕩，雲氣扶崔嵬。", "小儒嘆造化，辦此何雄哉。", "亦知天下絕，尊者所徘徊。", "三生清凈願，俗緣故難開。", "踐勝吾豈敢，稽首儻興哀。"]'),
('7f2c83f7-52ce-462e-90d8-599f8fa7deb6','雨中宿靈峰寺','陳與義','宋','宋诗','song-poetry','','[]','雁蕩山中逢晚雨，靈峯寺裏借繩床。',32,'全唐诗/poet.song.100000.json','["雁蕩山中逢晚雨，靈峯寺裏借繩床。", "只應護得綸巾角，還費高僧一炷香。"]'),
('1fa7e2eb-684e-46b5-b304-cdb7a3947865','自黄巖縣舟行入台州','陳與義','宋','宋诗','song-poetry','','[]','宴坐峯前衝雨急，黄巖縣裏借舟遲。',64,'全唐诗/poet.song.100000.json','["宴坐峯前衝雨急，黄巖縣裏借舟遲。", "百年癡黠不相補，萬事悲歡豈可期。", "莽莽滄波兼宿霧，紛紛白鷺落山陂。", "只應江海凄凉地，欠我臨風一賦詩。"]'),
('83f8afac-25fa-4727-ac72-41c48ead4c35','過下杯渡','陳與義','宋','宋诗','song-poetry','','[]','夜宿下杯館，朝鳴一棹東。',48,'全唐诗/poet.song.100000.json','["夜宿下杯館，朝鳴一棹東。", "湖平天盡落，峽斷海橫通。", "冉冉雲隨舸，茫茫鳥棄風。", "仙人蓬島上，遥見我乘空。"]'),
('34dfd567-3bcb-4b28-8364-239c043439b3','王孫嶺','陳與義','宋','宋诗','song-poetry','','[]','已過長溪嶺更危，伏龍莽莽向川垂。',32,'全唐诗/poet.song.100000.json','["已過長溪嶺更危，伏龍莽莽向川垂。", "斜陽照見林中石，記得南山隱去時。"]'),
('4f411fed-8eba-4bb7-ae92-76f7bd4a40ea','泛舟入前倉','陳與義','宋','宋诗','song-poetry','','[]','曾皷鹽田棹，前倉不足言。',48,'全唐诗/poet.song.100000.json','["曾皷鹽田棹，前倉不足言。", "盡行江左路，初過浙東村。", "春去花無迹，潮歸岸有痕。", "百年都幾日，聊復信乾坤。"]'),
('8f10187d-b940-48b1-8b2a-e574dc2d37c2','送熊博士赴瑞安令','陳與義','宋','宋诗','song-poetry','','[]','衣冠衮衮相逢地，草木蕭蕭未變時。',64,'全唐诗/poet.song.100000.json','["衣冠衮衮相逢地，草木蕭蕭未變時。", "聚散同驚一枕夢，悲歡各誦十年詩。", "山林有約吾當去，天地無情子亦饑。", "笑領銅章非失計，歲寒心事欲深期。"]'),
('fc506515-554a-4687-b193-e89c3e1f6ae2','夜賦','陳與義','宋','宋诗','song-poetry','','[]','抱病喜清夜，形羸心獨開。',48,'全唐诗/poet.song.100000.json','["抱病喜清夜，形羸心獨開。", "不知藥鼎沸，錯認雨聲來。", "歲晚燈燭麗，天長鴻雁哀。", "書生惜日月，欹枕意茫哉。"]'),
('f83f5c4a-73e7-4085-92e8-03156fa6a4ac','喜雨','陳與義','宋','宋诗','song-poetry','','[]','秦望山頭雲，昨日鸞鳳舉。',108,'全唐诗/poet.song.100000.json','["秦望山頭雲，昨日鸞鳳舉。", "冥冥萬里風，淅淅三更雨。", "小臣知君憂，起坐聽檐語。", "風力有去來，龍工雜文武。", "燈花識我意，一笑相媚嫵。", "泥翻早朝路，瀰瀰光欲吐。", "鬰然蒼龍闕，佳氣接南畝。", "千官次第來，豫色各眉宇。", "記事以短篇，不工還自許。"]'),
('57ff8944-ab80-41b8-afd8-3d8eb53e9fcc','醉中','陳與義','宋','宋诗','song-poetry','','[]','醉中今古興衰事，詩裏江湖摇落時。',64,'全唐诗/poet.song.100000.json','["醉中今古興衰事，詩裏江湖摇落時。", "兩手尚堪杯酒用，寸心唯是鬢毛知。", "稽山擁郭東西去，禹穴生雲朝暮奇。", "萬里南征無賦筆，茫茫遠望不勝悲。"]'),
('f5f57a8c-34f6-447c-9157-946f4fbf6cc1','不見梅花六言','陳與義','宋','宋诗','song-poetry','','[]','荆楚歲時經盡，今年不見梅花。',28,'全唐诗/poet.song.100000.json','["荆楚歲時經盡，今年不見梅花。", "想得蒼煙玉立，都藏江上人家。"]'),
('7743ab54-761a-4e8d-b457-a3485385a000','梅花二首  其一','陳與義','宋','宋诗','song-poetry','','[]','鐵面蒼髯洛陽客，玉顔紅領會稽仙。',32,'全唐诗/poet.song.100000.json','["鐵面蒼髯洛陽客，玉顔紅領會稽仙。", "街頭相見如相識，恨滿東風意不傳。"]'),
('84b11ff6-75bd-4921-b9c9-51e434a58741','梅花二首  其二','陳與義','宋','宋诗','song-poetry','','[]','畫取維摩室中物，小瓶春色一枝斜。',32,'全唐诗/poet.song.100000.json','["畫取維摩室中物，小瓶春色一枝斜。", "夢回映月窗間見，不是桃花與李花。"]'),
('d9e0e34e-fe9d-46b6-9087-6134ddc380c2','雨','陳與義','宋','宋诗','song-poetry','','[]','聽雨披夜襟，衝雨踏晨鼓。',72,'全唐诗/poet.song.100000.json','["聽雨披夜襟，衝雨踏晨鼓。", "萬珠絡笋輿，詩中有新語。", "老龍經秋卧，歲暮始一舉。", "成功亦何遲，光采變蔬圃。", "道邊聞井溢，可笑遽如許。", "舊山百尺泉，不知旱與雨。"]'),
('5b6c5c29-e82d-4c33-98a0-0ad753f1454d','瓶中梅','陳與義','宋','宋诗','song-poetry','','[]','明窗凈棐几，玉立耿無鄰。',48,'全唐诗/poet.song.100000.json','["明窗凈棐几，玉立耿無鄰。", "紅綠兩重袂，殷勤滿面春。", "曾爲庾嶺客，本是洛陽人。", "老我何顔貌，東風處處新。"]'),
('7f6d0f4c-acec-49e9-a357-7df39ee14f5a','除夜','陳與義','宋','宋诗','song-poetry','','[]','疇昔追歡事，如今病不能。',48,'全唐诗/poet.song.100000.json','["疇昔追歡事，如今病不能。", "等閑生白髮，耐久是青燈。", "海內春還滿，江南硯不冰。", "題詩餞殘歲，鍾鼓報晨興。"]'),
('91d33a32-ff48-4110-b4f7-e04f5440ac18','雨中','陳與義','宋','宋诗','song-poetry','','[]','北客霜侵鬢，南州雨送年。',48,'全唐诗/poet.song.100000.json','["北客霜侵鬢，南州雨送年。", "未聞兵革定，從使歲時遷。", "古澤生春靄，高空落暮鳶。", "山川含萬古，鬰鬰在樽前。"]'),
('9ff8996c-5da0-4452-a99f-8afad2302b1f','渡江','陳與義','宋','宋诗','song-poetry','','[]','江南非不好，楚客自生哀。',48,'全唐诗/poet.song.100000.json','["江南非不好，楚客自生哀。", "摇檝天平渡，迎人樹欲來。", "雨餘吳岫立，日照海門開。", "雖異中原險，方隅亦壯哉。"]'),
('c05f7a68-47ae-4526-98ec-a19eb3bd7842','夙興','陳與義','宋','宋诗','song-poetry','','["\u897f\u6e56"]','美哉木枕與菅席，無耐當興戴朝幘。',128,'全唐诗/poet.song.100000.json','["美哉木枕與菅席，無耐當興戴朝幘。", "巷南巷北聞鍛聲，舍後舍前唯月色。", "事國無功端未去，竹輿伊鴉猶昨日。", "不見武林城裏事，繁華夢覺生荆棘。", "成壞由來幾古今，乾坤但可著山澤。", "西湖已無金碧麗，雨抹晴粧尚娛客。", "會當休日一訪之，摩挲蒼蘚慰崖石。", "只恐冷泉亭下水，發明白髮增嘆息。"]'),
('36feab42-a1f8-4ea9-a687-8a67179e4b2e','幽窗','陳與義','宋','宋诗','song-poetry','','[]','貧士工用短，壯夫溺於詩。',84,'全唐诗/poet.song.100000.json','["貧士工用短，壯夫溺於詩。", "破壁爲幽窗，我筆還得持。", "高鳥度遺影，風扉語移時。", "迨我休暇日，與物聊同嬉。", "古來賢哲人，畎畝策安危。", "一行或大謬，半隱良亦癡。", "寄言山中友，即歲以爲期。"]'),
('d4d7d4dc-bf1d-4190-9d71-d8826464bc0d','題伯時畫溫溪心等貢五馬','陳與義','宋','宋诗','song-poetry','','[]','漠漠河西塵幾重，年來畫馬亦難逢。',32,'全唐诗/poet.song.100000.json','["漠漠河西塵幾重，年來畫馬亦難逢。", "題詩記著今朝事，同看聯翩五匹龍。"]'),
('2d1a848a-848f-4aab-9882-87c7b5e43f29','休日馬上','陳與義','宋','宋诗','song-poetry','','[]','休日不自休，騎馬踏荒徑。',72,'全唐诗/poet.song.100000.json','["休日不自休，騎馬踏荒徑。", "却扇受景風，今朝我無病。", "春雲閟晨耀，羣綠澹相映。", "山川與朝市，一動自一靜。", "九衢行萬人，誰抱此懷勝。", "不得與之語，蕭蕭寄孤詠。"]'),
('c2c2f773-6fe1-4772-b137-6c97add40d68','題畫','陳與義','宋','宋诗','song-poetry','','[]','分明樓閣是龍門，亦有溪流曲抱村。',32,'全唐诗/poet.song.100000.json','["分明樓閣是龍門，亦有溪流曲抱村。", "萬里家山無路入，十年心事有誰論。"]'),
('e4d89f4d-39e5-4593-ac8a-bcb2e96c54eb','題崇蘭圖二首  其一','陳與義','宋','宋诗','song-poetry','','[]','兩公得我色敷腴，藜杖相將入畫圖。',32,'全唐诗/poet.song.100000.json','["兩公得我色敷腴，藜杖相將入畫圖。", "我已夢中都識路，秋風舉袂不踟躕。"]'),
('3b5344cf-864a-4cbf-b60f-a68c7060c4b3','題崇蘭圖二首  其二','陳與義','宋','宋诗','song-poetry','','[]','奕奕天風吹角巾，松聲水色一時新。',32,'全唐诗/poet.song.100000.json','["奕奕天風吹角巾，松聲水色一時新。", "山林從此不牢落，照影溪頭共六人。"]'),
('363eb96d-5129-47e5-9cf0-6f9e7d3e2376','秋夜獨酌','陳與義','宋','宋诗','song-poetry','','[]','凉秋佳夕天氛廓，河漢之涯秋漠漠。',96,'全唐诗/poet.song.100000.json','["凉秋佳夕天氛廓，河漢之涯秋漠漠。", "月出未出林彩變，幽人露坐方獨酌。", "自歌新詞酒如空，天星下飲觥船中。", "忽思李白不可見，夜半喬木摇西風。", "百年佳月幾今夕，憂樂相尋老來疾。", "瓊瑶滿地我影橫，添酒賦詩何可失。"]'),
('b8a3d298-c1d8-4e26-b022-628d3a79480a','九日示大圓洪智','陳與義','宋','宋诗','song-poetry','','[]','自得休心法，悠然不賦詩。',24,'全唐诗/poet.song.100000.json','["自得休心法，悠然不賦詩。", "忽逢重九日，無奈菊花枝。"]'),
('0a826fcb-1571-4bd2-bdf1-e0dd7c538f4c','劉大資挽詞二首  其一','陳與義','宋','宋诗','song-poetry','','[]','天柱欹傾日，堂堂墮虜圍。',48,'全唐诗/poet.song.100000.json','["天柱欹傾日，堂堂墮虜圍。", "遂聞王蠋死，不見華元歸。", "一代名超古，千年淚染衣。", "當時如有繼，猶足變危機。"]'),
('8cf6578c-c49e-48d4-9676-e395d7f36d65','劉大資挽詞二首  其二','陳與義','宋','宋诗','song-poetry','','[]','一死公餘事，由來虜亦人。',48,'全唐诗/poet.song.100000.json','["一死公餘事，由來虜亦人。", "使知臨難日，猶有不欺臣。", "河洛傾遺憤，英雄歎後塵。", "煌煌中興業，公合冠麒麟。"]'),
('2c1be914-28d2-48b5-ade9-3da49a4e8645','與智老天經夜坐','陳與義','宋','宋诗','song-poetry','','[]','殘年不復徙他邦，長與兩禪同夜缸。',32,'全唐诗/poet.song.100000.json','["殘年不復徙他邦，長與兩禪同夜缸。", "坐到更深都寂寂，雪花無數落窗前。"]'),
('5ae6986d-9420-4a79-be40-95ab3df2f12e','觀雪','陳與義','宋','宋诗','song-poetry','','[]','無住菴前境界新，瓊樓玉宇總無塵。',32,'全唐诗/poet.song.100000.json','["無住菴前境界新，瓊樓玉宇總無塵。", "開門倚杖移時立，我是人間富貴人。"]'),
('fa4e7425-bfb7-453d-89d1-51700d01481c','題江參山水橫軸畫俞秀才所藏二首  其一','陳與義','宋','宋诗','song-poetry','','[]','卷中衮衮溪山去，筆下明明開闢初。',32,'全唐诗/poet.song.100000.json','["卷中衮衮溪山去，筆下明明開闢初。", "不肯一褌爲婦計，俞郎作意未全疏。"]'),
('a59ad7d9-7f8b-45b8-b053-7545ffc0d75e','題江參山水橫軸畫俞秀才所藏二首  其二','陳與義','宋','宋诗','song-poetry','','[]','萬壑分煙高復低，人家隨處有柴扉。',32,'全唐诗/poet.song.100000.json','["萬壑分煙高復低，人家隨處有柴扉。", "此中只欠陳居士，千仞崗頭一振衣。"]'),
('3d889e33-fd23-4326-89a6-5eb4df2a3623','小閣晨起','陳與義','宋','宋诗','song-poetry','','[]','紙帳不知曉，鴉鳴吾當興。',120,'全唐诗/poet.song.100000.json','["紙帳不知曉，鴉鳴吾當興。", "開窗面老松，相對寒崚嶒。", "幸無公家責，欲懶還不能。", "汲井頮我面，銅盆旋敲冰。", "梳頭風入檻，紛散霜滿膺。", "四瞻郊澤間，蒼煙慘朝凝。", "却望塔顛日，光景舒層層。", "乾坤有奇事，變化忽相乘。", "客來無可語，語此不見應。", "今晨胡床冷，愧我無毾㲪。"]'),
('0bb49128-899c-4706-bec0-253bf68824be','小閣晚望','陳與義','宋','宋诗','song-poetry','','[]','澤國候易變，孟冬乃微和。',96,'全唐诗/poet.song.100000.json','["澤國候易變，孟冬乃微和。", "解襟凭小閣，日暮歸雲多。", "蒼蒼散草木，莽莽雜山河。", "荒野蟲亂鳴，長空鳥時過。", "萬象各無待，唯人顧紛羅。", "備物以養己，更用干與戈。", "天風吹我來，衣袂生微波。", "幽懷眇無寄，蕭瑟起悲歌。"]'),
('1343ae34-4468-4e2e-9005-d6f35c5c1551','梅花','陳與義','宋','宋诗','song-poetry','','[]','一枝斜映佛前燈，春入銅壺夜不冰。',32,'全唐诗/poet.song.100000.json','["一枝斜映佛前燈，春入銅壺夜不冰。", "昔歲曾遊大庾嶺，今年聊作小乘僧。"]'),
('ba5389db-d3bf-4164-bad9-fb5aff7a2eb5','得張正字詩','陳與義','宋','宋诗','song-poetry','','[]','送老茅屋底，天寒人迹稀。',48,'全唐诗/poet.song.100000.json','["送老茅屋底，天寒人迹稀。", "一觴猶有味，萬事已無機。", "歲暮塔孤立，風生鴉亂飛。", "此時張正字，書札到郊扉。"]'),
('d662a124-0926-42de-a092-1c07e53b715d','江梅','陳與義','宋','宋诗','song-poetry','','[]','風雪集歲暮，江梅開不遲。',48,'全唐诗/poet.song.100000.json','["風雪集歲暮，江梅開不遲。", "朝來幽窗底，明璫綴青枝。", "上天播淑氣，百卉分四時。", "寒村值西子，足以昌吾詩。"]'),
('61f39016-0f8c-4c5e-896c-92b8bdac8a81','雪','陳與義','宋','宋诗','song-poetry','','[]','窮臘見三白，江南無舊聞。',96,'全唐诗/poet.song.100000.json','["窮臘見三白，江南無舊聞。", "天上春已暮，盡日花繽紛。", "平生雖畏寒，遇雪心所欣。", "擁裘未敢出，投隙致殷勤。", "窗戶忽相照，川陵已難分。", "二儀有巨麗，老我不能文。", "高吟黄竹詩，薄暮心無垠。", "浮屠似玉筍，突兀倚重雲。"]'),
('16fdcc2e-51b1-475d-b7e6-03126d1f8789','小閣','陳與義','宋','宋诗','song-poetry','','["\u592a\u6e56"]','欄干橫歲暮，徙倚度陰晴。',48,'全唐诗/poet.song.100000.json','["欄干橫歲暮，徙倚度陰晴。", "木落太湖近，梅開南紀明。", "病餘仍愛酒，身後更須名。", "鸛鶴忽雙起，吾詩還欲成。"]'),
('eebec140-651b-4384-8cf9-7f8c4a933c36','元夜','陳與義','宋','宋诗','song-poetry','','[]','今夕天氣佳，上天何澄穆。',120,'全唐诗/poet.song.100000.json','["今夕天氣佳，上天何澄穆。", "列宿雨後明，流雲月邊速。", "空檐垂斗柄，微吹生叢竹。", "對此不能寐，步繞庭之曲。", "遥睇浮屠顛，數星紅煜煜。", "悟知燒燈夕，節意亦滿目。", "歷代能幾詩，遍賦雜珉玉。", "栖鴉亦未定，更鳴伴余獨。", "百年滔滔內，憂樂兩難復。", "唯應長似今，寂寞送寒燠。"]'),
('02256916-c04d-4c82-b693-fbf72e08ad99','懷天經智老因訪之','陳與義','宋','宋诗','song-poetry','','[]','今年二月凍初融，睡起苕溪綠向東。',64,'全唐诗/poet.song.100000.json','["今年二月凍初融，睡起苕溪綠向東。", "客子光陰詩卷裏，杏花消息雨聲中。", "西菴禪伯還多病，北柵儒先只固窮。", "忽憶輕舟尋二子，綸巾鶴氅試春風。"]'),
('cabe2f0d-5b82-456a-ae1a-62f6e907ce76','黄修職雨中送芍藥五枝','陳與義','宋','宋诗','song-poetry','','[]','微雨濕清曉，老夫門未開。',56,'全唐诗/poet.song.100000.json','["微雨濕清曉，老夫門未開。", "煌煌五仙子，並擁翠蕤來。", "烟脂洗盡不自惜，爲雨歸來更無力。", "老夫五十尚可癡，憑軒一賦會真詩。"]'),
('705e0ee1-b203-4d94-b2b7-935e2cdb3d1e','櫻桃','陳與義','宋','宋诗','song-poetry','','[]','四月江南黄鳥肥，櫻桃滿市粲朝暉。',32,'全唐诗/poet.song.100000.json','["四月江南黄鳥肥，櫻桃滿市粲朝暉。", "赤瑛盤裏雖殊遇，何似筠籠相發揮。"]'),
('9886cfcc-50ae-474d-80f0-8b8513829a7b','葉柟惠花','陳與義','宋','宋诗','song-poetry','','[]','無住菴中老居士，逢春入定不銜杯。',32,'全唐诗/poet.song.100000.json','["無住菴中老居士，逢春入定不銜杯。", "文殊罔明俱拱手，今日花枝喚得迴。"]'),
('744621f2-3d24-443a-b352-bb08b572c644','牡丹','陳與義','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u548f\u7269", "\u548f\u7269\u8bd7", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u601d\u4e61", "\u7261\u4e39"]','一自胡塵入漢關，十年伊洛路漫漫。',32,'全唐诗/poet.song.100000.json','["一自胡塵入漢關，十年伊洛路漫漫。", "青墩溪畔龍鍾客，獨立東風看牡丹。"]'),
('ef16dc1f-84fb-498f-b62b-9d5648821891','盆池','陳與義','宋','宋诗','song-poetry','','[]','三尺清池窗外開，茨菰葉底戲魚回。',32,'全唐诗/poet.song.100000.json','["三尺清池窗外開，茨菰葉底戲魚回。", "雨聲轉入浙江去，雲影還從震澤來。"]'),
('48d96d1e-085d-4d72-9ff1-ea79e373566e','松棚','陳與義','宋','宋诗','song-poetry','','[]','黯黯當窗雲不驅，不教風日到琴書。',32,'全唐诗/poet.song.100000.json','["黯黯當窗雲不驅，不教風日到琴書。", "只今老子風流地，何似茅山陶隱居。"]'),
('55159b6c-b21f-4a21-8ebd-268ec14bbe98','西軒','陳與義','宋','宋诗','song-poetry','','[]','平生江海志，歲暮僧廬中。',72,'全唐诗/poet.song.100000.json','["平生江海志，歲暮僧廬中。", "虛齋時獨步，遡此西窗風。", "初夏氣未變，幽居念方沖。", "三日無客來，門外生蒿蓬。", "輕陰映夕幌，窈窕瓶花紅。", "未知古今士，誰與此心同。"]'),
('92c5c927-ae66-47e9-8f3d-a038cd23fbba','玉堂儤直','陳與義','宋','宋诗','song-poetry','','[]','庭葉瓏瓏曉更青，斷雲吐日照寒廳。',32,'全唐诗/poet.song.100000.json','["庭葉瓏瓏曉更青，斷雲吐日照寒廳。", "只應未上歸田奏，貪誦楞伽四卷經。"]'),
('a51cf9eb-d194-4a7a-9aed-09df5d00121e','病骨','陳與義','宋','宋诗','song-poetry','','[]','病骨瘦始輕，清虛日來入。',48,'全唐诗/poet.song.100000.json','["病骨瘦始輕，清虛日來入。", "今朝僧閣上，超遥久風立。", "茂林榴萼紅，細雨離黄濕。", "物色乃可憐，所悲非故邑。"]'),
('97154abb-7678-44b0-9bd2-bf66b493c21f','晨起','陳與義','宋','宋诗','song-poetry','','[]','寂寂東軒晨起遲，蒙蘢草木暗疏籬。',32,'全唐诗/poet.song.100000.json','["寂寂東軒晨起遲，蒙蘢草木暗疏籬。", "風來衆綠一時動，正是先生睡足時。"]'),
('ec3be23b-ff15-4461-9bbb-a351b9d984ca','登閣','陳與義','宋','宋诗','song-poetry','','[]','今日天氣佳，登臨散腰脚。',48,'全唐诗/poet.song.100000.json','["今日天氣佳，登臨散腰脚。", "南方宜草木，九月未黄落。", "秋郊乃明麗，夕雲更蕭索。", "遠遊吾未能，歲暮依樓閣。"]'),
('10be99f6-decd-4aab-a59f-57017618b919','芙蓉','陳與義','宋','宋诗','song-poetry','','[]','白髮飄蕭一病翁，暮年身世藥瓢中。',32,'全唐诗/poet.song.100000.json','["白髮飄蕭一病翁，暮年身世藥瓢中。", "芙蓉牆外垂垂發，九月憑欄未怯風。"]'),
('1426b6d5-77db-4642-9d3d-18e2a81f330e','歲華','陳與義','宋','宋诗','song-poetry','','[]','歲華日已凋，飛葉鳴古瓦。',84,'全唐诗/poet.song.100000.json','["歲華日已凋，飛葉鳴古瓦。", "白頭倚危檻，高旻覆平野。", "遥瞻疏柳林，下有清溪瀉。", "三春既繁麗，九秋亦瀟灑。", "平生萬事過，所欠茅一把。", "山川鬰日夕，有抱無與寫。", "賦詩老不工，開篇詠風雅。"]'),
('b45a501c-2a4e-41d7-92c1-760ecfe94e4c','得長春兩株植之窗前','陳與義','宋','宋诗','song-poetry','','[]','鄉邑已無路，僧廬今是家。',48,'全唐诗/poet.song.100000.json','["鄉邑已無路，僧廬今是家。", "聊乘數點雨，自種兩叢花。", "籬落失秋序，風煙添歲華。", "衰翁病不飲，獨立到棲鴉。"]'),
('959062a7-446e-438e-9d7e-4ca8e086332f','九月八日戲作兩絕句示妻子  其一','陳與義','宋','宋诗','song-poetry','','[]','今夕知何夕，都如未病時。',24,'全唐诗/poet.song.100000.json','["今夕知何夕，都如未病時。", "重陽莫草草，剩作幾篇詩。"]'),
('ea7c7eaa-132d-4363-be97-27611d75e76a','九月八日戲作兩絕句示妻子  其二','陳與義','宋','宋诗','song-poetry','','[]','小甕今朝熟，無勞問酒家。',24,'全唐诗/poet.song.100000.json','["小甕今朝熟，無勞問酒家。", "重陽明日是，何處有黄花。"]'),
('3af81512-98f8-4ee7-bcbf-a3985d8ef9b4','拒霜','陳與義','宋','宋诗','song-poetry','','[]','拒霜花已吐，吾宇不悽凉。',48,'全唐诗/poet.song.100000.json','["拒霜花已吐，吾宇不悽凉。", "天地雖肅殺，草木有芬芳。", "道人宴坐處，侍女古時粧。", "濃露濕丹臉，西風吹綠裳。"]'),
('2d67c848-46ab-4415-81d0-46a254891167','微雨中賞月桂獨酌','陳與義','宋','宋诗','song-poetry','','[]','人間跌宕簡齋老，天下風流月桂花。',32,'全唐诗/poet.song.100000.json','["人間跌宕簡齋老，天下風流月桂花。", "一壺不覺叢邊盡，暮雨霏霏欲濕鴉。"]'),
('5402935b-ddbf-49be-b7cc-9fe739fa689d','畫梅','陳與義','宋','宋诗','song-poetry','','[]','娥眉淡淡自成粧，驛使還家空斷腸。',32,'全唐诗/poet.song.100000.json','["娥眉淡淡自成粧，驛使還家空斷腸。", "脂粉不施憔悴盡，失身未嫁易元光。"]'),
('249823ad-a6fd-4854-ac5d-7aac3557f80d','竹','陳與義','宋','宋诗','song-poetry','','[]','高枝已約風爲友，密葉能留雪作花。',32,'全唐诗/poet.song.100000.json','["高枝已約風爲友，密葉能留雪作花。", "昨夜常娥更瀟灑，又携疏影過窗紗。"]'),
('80672a2f-3657-459b-9666-4f29f6174034','心老久許爲作畫未果以詩督之','陳與義','宋','宋诗','song-poetry','','[]','布衲王摩詰，禪餘寄筆端。',48,'全唐诗/poet.song.100000.json','["布衲王摩詰，禪餘寄筆端。", "試將能事迫，肯作畫工難。", "秋入無聲句，山連欲雨寒。", "平生夢想處，奉乞小巑岏。"]'),
('c9eb109e-7c57-4d83-a54a-d15c6c435c78','偶成古調十六韻上呈判府兼贈劉興州','陳與義','宋','宋诗','song-poetry','','[]','稽首蘇耽仙，乘雲去無跡。',192,'全唐诗/poet.song.100000.json','["稽首蘇耽仙，乘雲去無跡。", "尚留橘井在，與世除狂疾。", "誰能不飲此，識味亦可錄。", "坐令鄭玄牛，亦抱荆山玉。", "偉哉稚川裔，神交接朝夕。", "游戲及小道，造化入大筆。", "優爲吳詩父，雅命楚騷僕。", "豈其橘井助，本自同仙籙。", "坐中子劉子，知是當日客。", "書懸元和脚，語經建康力。", "先我登公門，不數鷙鳥百。", "曾挹兩仙袖，自然生羽翼。", "嗟我無長才，學架屋下屋。", "詩雖兩牛腰，事亦幾蛇足。", "已窮猶不悔，政荷師友德。", "文盟儻許予，幸不疑籍湜。"]'),
('4a556536-c001-46e0-a768-356c24ffc235','再用迹字韻成一首呈判府','陳與義','宋','宋诗','song-poetry','','[]','風雨一葉過，黄花已陳迹。',192,'全唐诗/poet.song.100000.json','["風雨一葉過，黄花已陳迹。", "人貧交舊疏，歲暮日月疾。", "貪人積胡椒，智不到鬼錄。", "那知庾郎菜，地瘦飽金玉。", "不如學服氣，清座了晨夕。", "尚餘煙月債，驅使入吟筆。", "晚逢葛先生，憐我出無僕。", "借車得時詣，謬窺文字籙。", "談詩不知疲，或作夜半客。", "揮毫寫珠玉，治郡蓋餘力。", "不羨江千萬，不慕李八百。", "願傳公句法，容我附風翼。", "城東劉子政，著書方滿屋。", "昨示一篇詩，三日歎未足。", "仍聞供筆硯，家有樊通德。", "但恐裴公門，從此近捨湜。"]'),
('80bdb189-6838-4a41-91b4-a861cdb05b95','蒙示黄礀佳詩三讀欽羨輒繼韻仰報嘉賜','陳與義','宋','宋诗','song-poetry','','[]','癡兒了官事，官事那可訖。',108,'全唐诗/poet.song.100000.json','["癡兒了官事，官事那可訖。", "豈知公偷閑，臨水照纓紱。", "雖微八川雄，暴怒常至沸。", "儻或似山陰，清流可共祓。", "貪德實以濟，行地不鬰鬰。", "趙洛與陶丘，相比亦彷彿。", "解后逢公賞，一洗伏流屈。", "可愛不可唾，衆議那可咈。", "彼是公餘波，本來非俗物。"]'),
('4850fa77-75dc-47d3-9f9d-30bc3c1db325','蒙示涉汝詩次韻','陳與義','宋','宋诗','song-poetry','','[]','城南天倒影，綠浪摇十里。',156,'全唐诗/poet.song.100000.json','["城南天倒影，綠浪摇十里。", "使君雲夢胸，猶復錄此水。", "舟行及雨霽，秋色在葭葦。", "煙涵翠縠潤，月照金波委。", "知公已忘機，鷗鷺宛停峙。", "向來趨熱士，說似顙應泚。", "俗子與清遊，自古劇函矢。", "如何有雙脚，受垢不受洗。", "異哉公殊嗜，記此兩苦李。", "詩成墮衡門，名字污紙尾。", "明當躡公迹，佳處不待指。", "會逢白沙渚，我舍真可徙。", "鳴騶儻重來，傍舫傾我耳。"]'),
('f7c49e6d-9647-4355-a8ee-ca991d63d2fb','再和','陳與義','宋','宋诗','song-poetry','','[]','洪河豈不壯，餘潤彌九里。',156,'全唐诗/poet.song.100000.json','["洪河豈不壯，餘潤彌九里。", "海內所詠歌，在德不在水。", "德人經行地，可敬及蒲葦。", "况有水如此，浪去劇雪委。", "念昔涉濤江，怒鼉如山峙。", "天風怖殺人，舟定舷有泚。", "惕然三夜夢，沙礫下飛矢。", "至今逢溝壑，敢照不敢洗。", "忽誦涉汝詩，五字擬蘇李。", "快言擊汰事，想見魚掉尾。", "十年疑此樂，始誤斗柄指。", "便當策我足，歲月忽轉徙。", "未辦志和舟，且洗子荆耳。"]'),
('dcb8f2f1-9852-422c-8cd8-4a02257a9281','遊峴山次韻三首  其一','陳與義','宋','宋诗','song-poetry','','[]','夜度一程雲，平明踏山址。',144,'全唐诗/poet.song.100000.json','["夜度一程雲，平明踏山址。", "山神豈妬我，飛雨亂眸子。", "重岳衮衮去，前傑後俊偉。", "晦明更百態，始望那及此。", "路窮得精廬，稅駕諮祖始。", "老僧千金意，佳處相指似。", "先生一笑領，得句易翻水。", "安石未歸山，却要山料理。", "奇哉此一段，驚世無前軌。", "酬山以快飲，春蕨正滋旨。", "一丘儻許予，高卧飽松髓。", "城中謾拄笏，那知有茲事。"]'),
('27d3edd8-2b72-474b-9c77-d4410f1b60a6','遊峴山次韻三首  其二','陳與義','宋','宋诗','song-poetry','','[]','高人買山隱，百萬猶恨少。',144,'全唐诗/poet.song.100000.json','["高人買山隱，百萬猶恨少。", "客兒最省事，有屐一生了。", "東莊良不遥，十里望縹緲。", "縈紆並麥垅，翠浪四山繞。", "先生滯鹿車，去程通鳳沼。", "暫來山泉上，思與飛雲杳。", "雲北接雲南，一逕絕紛擾。", "竹林懷風雨，目斷極窈窈。", "從來無世塵，相對真不撓。", "龍兒爭地出，頭角已表表。", "先生囑支郎，勿使斤斧夭。", "終當乞一杖，險路扶吾老。"]'),
('e70c99f7-ed7f-4735-b4f9-03d7d6739eaf','遊峴山次韻三首  其三','陳與義','宋','宋诗','song-poetry','','[]','轉路山突兀，衆山之所望。',132,'全唐诗/poet.song.100000.json','["轉路山突兀，衆山之所望。", "懶融不下山，揖山會虛堂。", "大空出盤嬉，小空時侍傍。", "我遊瞻鐵鳳，力盡隨木羊。", "石窗非人世，意欲淩風翔。", "巉巉窗中人，出定髮有霜。", "過眼幾浮煙，關身一禪床。", "教我安心法，入鳥不亂行。", "似知使君尊，起炷柏子香。", "隴雲亦堪寄，分作我歸裝。", "好在窗前竹，伴師老蒼蒼。"]'),
('80371301-3d99-4975-987c-b34c80884c24','再賦  其一','陳與義','宋','宋诗','song-poetry','','[]','堂堂李杜壇，誰敢躡其址。',144,'全唐诗/poet.song.100000.json','["堂堂李杜壇，誰敢躡其址。", "先生坐壇上，持鉞令餘子。", "由來文字伯，不但表奏偉。", "高懷淡無嗜，寓興或留此。", "平生上林手，避謗淹二始。", "登臨意超然，筆落風雨似。", "事異柳司馬，辛苦記山水。", "樂哉邦無事，那待猛政理。", "駕言慰吾民，不愧城門軌。", "看山笑鄒湛，句外寄深旨。", "巖樹閱幾客，尚餘堯時髓。", "撫板歌公詩，未暇知餘事。"]'),
('02b03b00-1431-492e-a96a-f3fbedc8e179','再賦  其二','陳與義','宋','宋诗','song-poetry','','[]','興公賦天台，千字一何少。',144,'全唐诗/poet.song.100000.json','["興公賦天台，千字一何少。", "峴山逢巧匠，籠絡六詩了。", "餘情到娘子，心動雲縹緲。", "彷彿山阿人，薜荔一身繞。", "殷勤供泚筆，路轉得龍沼。", "應龍喜公來，噓氣紛霧杳。", "忽然張蓋起，知不受人擾。", "詩成中有畫，幽情雜荒窈。", "從公雖一快，顧有和詩撓。", "是事姑置之，歸路迷日表。", "安得永茲樂，彭鏗尚爲夭。", "但愁歸城中，念山令人老。"]'),
('4e92d5cc-c6ea-4154-a24d-35ef3ca92d38','再賦  其三','陳與義','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','脩眉入幽夢，起費西南望。',132,'全唐诗/poet.song.100000.json','["脩眉入幽夢，起費西南望。", "終願學柳文，買泉築愚堂。", "錯磨高壁翠，日日在我旁。", "忽在新野鄒，行從泰山羊。", "城中瞻使君，駕鶴高馳翔。", "詩成墮人世，字字含風霜。", "平生仰止勤，不但上下床。", "顧許俗士駕，平參丈人行。", "封姨豈嗔予，震怒挾阿香。", "知公終可恃，不記當趨裝。", "清歡豈有極，夜色來蒼蒼。"]'),
('d78674b6-f28f-47b7-8644-b47959545e57','秋月','陳與義','宋','宋诗','song-poetry','','[]','袢暑推不去，快風喜來過。',96,'全唐诗/poet.song.100000.json','["袢暑推不去，快風喜來過。", "西榮遲明月，與子聊婆娑。", "初如金盆湧，稍若玉鑑磨。", "亭亭倚華魄，艷艷舒凍波。", "夜氣清入骨，奈此光景何。", "一杯幸相屬，安能廢吟哦。", "纖阿無停輪，衰鬢颯已多。", "及時會行樂，無惜醉顔酡。"]'),
('80099b2e-4bea-4b30-b35e-e7731ec20061','均臺辭二首  其一','陳與義','宋','宋诗','song-poetry','','[]','小桃借春春已來，平分和氣入均臺。',80,'全唐诗/poet.song.100000.json','["小桃借春春已來，平分和氣入均臺。", "夜來臺邊草環綠，今朝芒生滿三木。", "街頭拍手鬧千兒，齊唱中和宣布曲。", "使君坐嘯鬧如雲，請釀百川壽使君。", "但願使君長樂職，不須更看杓虛實。"]'),
('22cb5dea-db15-4a17-a2aa-0ac616597e4f','均臺辭二首  其二','陳與義','宋','宋诗','song-poetry','','[]','東家西家爾盍來，聽說空圄如春臺。',82,'全唐诗/poet.song.100000.json','["東家西家爾盍來，聽說空圄如春臺。", "决曹高卧印生綠，叢棘化爲交遜木。", "策勳此木那可遺，動地風摇枝不曲。", "願我無訟到來雲，莫辭著力借寇君。", "借得賢侯雖爾職，但恐朝廷要人調鼎實。"]'),
('0ec577d8-e4dc-4ce1-beb1-4c3c87d17256','長沙寺桂花重開','陳與義','宋','宋诗','song-poetry','','[]','天遣幽花兩度開，黄昏梵放此徘徊。',32,'全唐诗/poet.song.100000.json','["天遣幽花兩度開，黄昏梵放此徘徊。", "不教居士卧禪榻，喚出西廂共看來。"]'),
('3bd82cfc-6327-4d4c-bc58-7cfe1db8b1d5','和若拙弟得陪遊後園  其一','陳與義','宋','宋诗','song-poetry','','[]','西園冠蓋坐生風，更欲長繩繫六龍。',32,'全唐诗/poet.song.100000.json','["西園冠蓋坐生風，更欲長繩繫六龍。", "惟有病夫能省事，北窗三友是過從。"]'),
('0cfcda43-089d-4033-a0c9-61309c0dd780','和若拙弟得陪遊後園  其二','陳與義','宋','宋诗','song-poetry','','[]','壯夫三箭功名手，儒士百篇藜莧腸。',32,'全唐诗/poet.song.100000.json','["壯夫三箭功名手，儒士百篇藜莧腸。", "莫道人人握珠玉，應須字字挾風霜。"]'),
('417cd584-b4d6-402e-a459-45fc13eeb68e','季高送酒','陳與義','宋','宋诗','song-poetry','','[]','自接麯生蓬戶外，便呼伯雅竹床頭。',32,'全唐诗/poet.song.100000.json','["自接麯生蓬戶外，便呼伯雅竹床頭。", "真逢幼婦著黄絹，直遣從事到青州。"]'),
('a58f2626-4191-4616-b879-b0071000e1dd','墨戲二首 蘭','陳與義','宋','宋诗','song-poetry','','[]','鄂州遷客一花說，仇池老仙五字銘。',32,'全唐诗/poet.song.100000.json','["鄂州遷客一花說，仇池老仙五字銘。", "併入晴窗三昧手，不須辛苦讀騷經。"]'),
('71a58bc7-4842-466c-a622-061f46f4f787','墨戲二首 蕙','陳與義','宋','宋诗','song-poetry','','[]','人間風露不到畹，只有酪奴無世塵。',32,'全唐诗/poet.song.100000.json','["人間風露不到畹，只有酪奴無世塵。", "何須更待秋風至，蕭艾從來不共春。"]'),
('7b450a71-eecb-4c3c-a0c6-9a7addf00856','和孫升之','陳與義','宋','宋诗','song-poetry','','[]','姬國餘芳代有人，于今公子秀溪濆。',64,'全唐诗/poet.song.100000.json','["姬國餘芳代有人，于今公子秀溪濆。", "處心如水尚書市，能賦臨流靖節君。", "花島紅雲春句麗，月梅疏影夜香聞。", "囊開古錦湖山出，何意一星窺妙文。"]'),
('08aecaa9-d2e1-4393-9c50-98e201f55254','寺居','陳與義','宋','宋诗','song-poetry','','[]','招提遠占一牛鳴，阻絕干戈得暫經。',64,'全唐诗/poet.song.100000.json','["招提遠占一牛鳴，阻絕干戈得暫經。", "夢境了知非有實，醉鄉不入自常醒。", "樓臺近水涵明鑑，草樹連空寫素屏。", "物象自堪供客眼，未須覓句戶長扃。"]'),
('fea6c44c-6b79-4449-ad7d-ad8b59cef064','某竊慕東坡以鐵拄杖爲樂全生日之壽今以大銅瓶上判府待制庶幾因物以露區區且作詩二首將之亦東坡故事  其一','陳與義','宋','宋诗','song-poetry','','[]','要學東坡壽樂全，此瓶端合供儒先。',64,'全唐诗/poet.song.100000.json','["要學東坡壽樂全，此瓶端合供儒先。", "鐵如意畔無憂畏，玉唾壺傍耐歲年。", "項似董宣真是强，腹如邊孝故應便。", "與公剩貯爲霖水，不羨宮門承露仙。"]'),
('3b8f28ec-33f6-4d0a-802c-a746564dc44d','某竊慕東坡以鐵拄杖爲樂全生日之壽今以大銅瓶上判府待制庶幾因物以露區區且作詩二首將之亦東坡故事  其二','陳與義','宋','宋诗','song-poetry','','[]','不與觀音伴柳枝，要令奇相解公頤。',64,'全唐诗/poet.song.100000.json','["不與觀音伴柳枝，要令奇相解公頤。", "會逢白氏編書日，猶夢陶家貯粟時。", "安用作盤供歃血，也勝爲鉢困催詩。", "千年秀結重重綠，長映先生鬢與眉。"]'),
('de4ed650-6cf6-4ce3-9594-fca18585517f','又用韻春雪','陳與義','宋','宋诗','song-poetry','','[]','急雪催詩興未闌，東風肯奈鳥烏寒。',64,'全唐诗/poet.song.100000.json','["急雪催詩興未闌，東風肯奈鳥烏寒。", "最憐度牖勤勤意，更接飛花細細看。", "連夜拋回三白瑞，及時驚動五辛盤。", "袁安久絕千人望，春破還思綺一端。"]'),
('ed227ad0-4cc4-460d-9809-87a93eca559b','次韻邢子友','陳與義','宋','宋诗','song-poetry','','[]','壯士如今爛莫收，尚思抽矢射旄頭。',64,'全唐诗/poet.song.100000.json','["壯士如今爛莫收，尚思抽矢射旄頭。", "不堪苦霧侵衰鬢，稍喜和煙入戍樓。", "萬里中原空費夢，三春勝日偶成遊。", "青松遠嶺偏驚眼，薄晚闌干更少留。"]'),
('af8e3335-5b49-4f41-a712-44839c185adb','某用家弟韻賦絕句上浼清視蕪詞累句非敢以爲詩也賜一言卒相之','陳與義','宋','宋诗','song-poetry','','[]','萬里平生幾蛇足，九州何路不羊腸。',32,'全唐诗/poet.song.100000.json','["萬里平生幾蛇足，九州何路不羊腸。", "只應綠士蒼官輩，却解從公到雪霜。"]'),
('11006fdd-2936-426d-a793-63da4443b2e1','某以雨有嘉應遂占有秋輒採用家弟韻賦二絕句少貲勤恤之誠也  其一','陳與義','宋','宋诗','song-poetry','','[]','雲氣初看龍起湫，雨聲旋聽樹驚秋。',32,'全唐诗/poet.song.100000.json','["雲氣初看龍起湫，雨聲旋聽樹驚秋。", "已教農父歌田守，更遣虞人信魏侯。"]'),
('f78196a9-7dc0-41c2-b2c4-61364f4b6352','某以雨有嘉應遂占有秋輒採用家弟韻賦二絕句少貲勤恤之誠也  其二','陳與義','宋','宋诗','song-poetry','','[]','紀德刊碑不厭豐，龍眠深洞一言通。',32,'全唐诗/poet.song.100000.json','["紀德刊碑不厭豐，龍眠深洞一言通。", "坐看綠浪摇千里，拔薤栽榆未當功。"]'),
('716ddb97-7a08-4443-b03d-62caca98164f','梅','陳與義','宋','宋诗','song-poetry','','[]','愛歌纖影上窗紗，無限輕香夜遶家。',32,'全唐诗/poet.song.100000.json','["愛歌纖影上窗紗，無限輕香夜遶家。", "一陣東風濕殘雪，强將嬌淚學梨花。"]'),
('c0a07d7c-c660-40a4-8257-d5987e1cc9bf','蒙知府寵示秋日郡圃佳製遂侍杖屨逍遥林水間輒次韻四篇上瀆台覽  其一','陳與義','宋','宋诗','song-poetry','','[]','歲月移文外，乾坤杖屨中。',48,'全唐诗/poet.song.100000.json','["歲月移文外，乾坤杖屨中。", "鏗然五字律，健在百夫雄。", "秋入池深碧，寒欺葉遞紅。", "此間兼吏隱，端不減遊嵩。"]'),
('ad66c883-629d-4d15-8825-de970cfd2619','蒙知府寵示秋日郡圃佳製遂侍杖屨逍遥林水間輒次韻四篇上瀆台覽  其二','陳與義','宋','宋诗','song-poetry','','[]','鳥語知公樂，晴山及我遊。',48,'全唐诗/poet.song.100000.json','["鳥語知公樂，晴山及我遊。", "盡排物外事，拚作酒中浮。", "菊蕊離雙鬢，林聲隱四愁。", "騷人例喜賦，政自不關秋。"]'),
('bba00416-3493-4cb6-b619-38fbfe6fb2f2','蒙知府寵示秋日郡圃佳製遂侍杖屨逍遥林水間輒次韻四篇上瀆台覽  其三','陳與義','宋','宋诗','song-poetry','','[]','竹際笙簧起，回聽衆籟微。',48,'全唐诗/poet.song.100000.json','["竹際笙簧起，回聽衆籟微。", "時陪物外賞，肯念日斜歸。", "草色違秋意，池光浄客衣。", "吟公清絕句，政爾不能肥。"]'),
('2cb60371-a902-4b52-9306-b067f195cf89','蒙知府寵示秋日郡圃佳製遂侍杖屨逍遥林水間輒次韻四篇上瀆台覽  其四','陳與義','宋','宋诗','song-poetry','','[]','一笑聊開口，千憂不上眉。',48,'全唐诗/poet.song.100000.json','["一笑聊開口，千憂不上眉。", "林深受風得，柏老到霜知。", "小憩逢筠洞，幽尋及枳籬。", "願公勤秉燭，裁詠棗離離。"]'),
('2aeec56c-fea7-4d7f-b483-80d5b53cedc0','送人歸京師','陳與義','宋','宋诗','song-poetry','','["\u79bb\u522b", "\u6292\u6000"]','門外子規啼未休，山村日落夢悠悠。',32,'全唐诗/poet.song.100000.json','["門外子規啼未休，山村日落夢悠悠。", "故園便是無兵馬，猶有歸時一段愁。"]'),
('8a8dd822-da0e-4bb4-9f5c-3c6471e3001d','雪','陳與義','宋','宋诗','song-poetry','','[]','仙人手持白鸞尾，夜半朝元明月裏。',64,'全唐诗/poet.song.100000.json','["仙人手持白鸞尾，夜半朝元明月裏。", "羽衣三振風不斷，下視銀潢一千里。", "玉軑載花分後前，欲落未落天恍然。", "餘標從向人間去，乞與袁安破曉眠。"]'),
('940f547a-9603-4604-9a5f-f3a22b493bb4','賦康平老銅雀硯','陳與義','宋','宋诗','song-poetry','','[]','鄴城臺殿已荒凉，依舊山河滿夕陽。',32,'全唐诗/poet.song.100000.json','["鄴城臺殿已荒凉，依舊山河滿夕陽。", "瓦礫却鑱今日硯，似教人世寫興亡。"]'),
('125f91c8-81ab-475a-8a06-9a9f30bca4bc','和顔持約','陳與義','宋','宋诗','song-poetry','','[]','半篙寒碧秋垂釣，一笛西風夜倚樓。',32,'全唐诗/poet.song.100000.json','["半篙寒碧秋垂釣，一笛西風夜倚樓。", "多少巫山舊家事，老來分付水東流。"]'),
('e93e15ca-b3c9-4410-9fcc-e91f74547d3c','早行','陳與義','宋','宋诗','song-poetry','','[]','露侵駝褐曉寒輕，星斗闌干分外明。',32,'全唐诗/poet.song.100000.json','["露侵駝褐曉寒輕，星斗闌干分外明。", "寂寞小橋和夢過，稻田深處草蟲鳴。"]'),
('f1bde063-7b59-4a7c-aa7e-b7a58b72d729','寄題康平老眄柯亭','陳與義','宋','宋诗','song-poetry','','[]','高懷志丘壑，既足不願餘。',168,'全唐诗/poet.song.100000.json','["高懷志丘壑，既足不願餘。", "惜哉三逕荒，滯彼天一隅。", "小築聊自適，空園闢榛蕪。", "清影吊高槐，氣與西山俱。", "何以開子顔，庭柯作森疏。", "月露洗塵翳，天風吹笙竽。", "方其寓目時，萬象供嘯呼。", "終然成坐忘，天地猶空虛。", "券外果何有，浮雲只須臾。", "乃知鍾鼎豐，未勝山林癯。", "淵明死千年，日月走名譽。", "不肯見督郵，歸來守舊廬。", "可憐骨已朽，後有誰繼渠。", "願子副名實，此事吾欲書。"]'),
('303c0e59-c562-49c1-bf7a-669a8eac1ad5','余識景純家弟出其詩見示喜其同臭味也輒用大成黄字韻賦八句贈之','陳與義','宋','宋诗','song-poetry','','[]','阿奴喜氣照人黄，傳得新詩細作行。',64,'全唐诗/poet.song.100000.json','["阿奴喜氣照人黄，傳得新詩細作行。", "可愛懸知似楊柳，忘憂復不待檳榔。", "魏收已獲崔昂譽，摩詰仍推相國長。", "曷不少留東閤醉，剩收篇詠作歸裝。"]'),
('94c3d94d-7c40-45a2-9f1b-7295097a8760','次韻景純道中寄大成','陳與義','宋','宋诗','song-poetry','','[]','聞道歌行伏李紳，古來賢守是詩人。',64,'全唐诗/poet.song.100000.json','["聞道歌行伏李紳，古來賢守是詩人。", "久欽樂廣懷披霧，一見周瑜勝飲醇。", "海內期公黄閤老，尊前容我白綸巾。", "佳篇咀嚼真堪飽，此日何憂甑有塵。"]'),
('427314e5-ffbf-4574-9135-95ae166af791','再蒙寵示佳什殆無遺巧勉成二章一以報佳貺一以自貽  其一','陳與義','宋','宋诗','song-poetry','','[]','睆睆休嫌笏與紳，如公本是九包人。',64,'全唐诗/poet.song.100000.json','["睆睆休嫌笏與紳，如公本是九包人。", "讀書只用三冬足，學道從來一色醇。", "太尉談辭仍玉麈，侍中風韻更紗巾。", "誰言上界多官府，亦許散仙追後塵。"]'),
('8f374085-89ae-49d2-9684-a71ea1d25966','再蒙寵示佳什殆無遺巧勉成二章一以報佳貺一以自貽  其二','陳與義','宋','宋诗','song-poetry','','[]','諸公衮衮坐垂紳，誰信北風欺得人。',64,'全唐诗/poet.song.100000.json','["諸公衮衮坐垂紳，誰信北風欺得人。", "遮眼讀書何用解，發顔要酒可須醇。", "十年白社空看鏡，萬里青天一岸巾。", "少待奇章到三日，試將冠蓋拂埃塵。"]'),
('0f0aaf6c-2bf7-4f05-9081-221a316beedd','同家弟用前韻謝判府惠酒  其一','陳與義','宋','宋诗','song-poetry','','[]','銜杯樂聖便稱賢，無酒猶堪卧甕間。',64,'全唐诗/poet.song.100000.json','["銜杯樂聖便稱賢，無酒猶堪卧甕間。", "使者在門催僕僕，麯車入夢正班班。", "不煩白水真人力，來自青城道士山。", "千載王弘同並美，未應杞菊賦寒慳。"]'),
('cb5ffd3b-d96f-4731-b6f3-e7010634b04e','同家弟用前韻謝判府惠酒  其二','陳與義','宋','宋诗','song-poetry','','[]','日飲知非貧士宜，要逃語穽稅心鞿。',64,'全唐诗/poet.song.100000.json','["日飲知非貧士宜，要逃語穽稅心鞿。", "所須唯酒非虛語，以醉爲鄉可徑歸。", "鸚鵡鸕鶿俱得道，螟蛉蜾蠃共忘機。", "狂言戲作麻姑送，無奈閽人與我違。"]'),
('873f984a-5e34-4f8a-9455-4c7fd9326e82','次韻家弟所賦','陳與義','宋','宋诗','song-poetry','','[]','曹劉方駕信優爲，不廢東郊坐保釐。',64,'全唐诗/poet.song.100000.json','["曹劉方駕信優爲，不廢東郊坐保釐。", "投蚓問公逢老手，聯珠及我愧連枝。", "定知來者傾三歎，共了流年費幾詩。", "瘀絮車斜敢將去，樂天那畏一微之。"]'),
('a6349e33-fea9-4a70-922f-87db7f4c154b','徙舍蒙大成賜詩','陳與義','宋','宋诗','song-poetry','','[]','南北東西共一塵，得坻隨處可收身。',64,'全唐诗/poet.song.100000.json','["南北東西共一塵，得坻隨處可收身。", "卜居賦就知謀拙，入宅詩成覺意新。", "三徑蓬蒿猶恨淺，九流賓客未嫌貧。", "不須更待高軒過，袖有珠璣已照鄰。"]'),
('adb86f8f-28e2-4921-a7b4-d1da2ff5876f','次韻宋主簿詩','陳與義','宋','宋诗','song-poetry','','[]','九折灣中萬斛舟，怪公隨處得心休。',64,'全唐诗/poet.song.100000.json','["九折灣中萬斛舟，怪公隨處得心休。", "未應菊徑關心急，聊爲魚槎盡意留。", "陸子舊蹤餘馬頂，羊公遺碣見龜頭。", "遥知太白無多事，醉裏詩成不待搜。"]'),
('07eed2c2-45d7-4cff-a027-eefe974e44b7','用大成四桂坊韻賦詩贈令狐昆仲','陳與義','宋','宋诗','song-poetry','','[]','鄉人洗眼看銀黄，得桂連枝手尚香。',64,'全唐诗/poet.song.100000.json','["鄉人洗眼看銀黄，得桂連枝手尚香。", "盛事固應傳雁塔，新詩不減住雞坊。", "醍酥乳酪元同味，羯末封胡更合堂。", "從此葛恢門下客，知名可但一楊方。"]'),
('d08bb5ce-c19c-406c-9a10-5cfd4f48155e','留別葛汝州','陳與義','宋','宋诗','song-poetry','','[]','平生師友塵莫數，兩眼偏明向公許。',160,'全唐诗/poet.song.100000.json','["平生師友塵莫數，兩眼偏明向公許。", "一時盛德人中驥，四海知名地上虎。", "東序階墀再靴板，西州杖屨三寒暑。", "我方庶兄湯惠休，公乃小兒楊德祖。", "未頒還朝尺一詔，不愧專城丈二組。", "爲公剩買銀管筆，容我時親玉柄麈。", "近蒙五字落珠璣，如服一丸生翅羽。", "別離真成惜夜燭，感歎更值歌朝雨。", "行看入侍玉皇案，與進不待金剛杵。", "勸公慎勿學孔光，薦士何妨似張禹。"]'),
('3ef70bc9-c667-468b-8824-78cc2e8fe324','蒙賜佳什欽歎不足不揆淺陋輒次元韻','陳與義','宋','宋诗','song-poetry','','[]','退之高文仰東岱，籍湜傳盟其足賴。',160,'全唐诗/poet.song.100000.json','["退之高文仰東岱，籍湜傳盟其足賴。", "固知法嗣要龍象，先生端是毗陵派。", "方駕曹劉蓋餘力，壓倒元白聊一快。", "向來班門收衆材，賓履費公珠幾琲。", "三熏會有堪此事，群犬未免驚所怪。", "但知樓仰百尺顛，豈覺波涵千頃外。", "南州短簿令公喜，巍峩峩冠陸離佩。", "有如若士那可無，筆勢已超聲律界。", "相將問道留十日，滿座真成折床會。", "清詩忽復墮華牋，要使握瑜誇等輩。"]'),
('a1880dc8-f12b-4c24-a24a-3cdfda03570d','某蒙示詠家弟所撰班史屬辭長句三歎之餘輒用元韻以示家弟謹布師席','陳與義','宋','宋诗','song-poetry','','[]','雋永雜俎雖甚旨，何似三冬足文史。',128,'全唐诗/poet.song.100000.json','["雋永雜俎雖甚旨，何似三冬足文史。", "羨子皮裏西京書，議論逼人驚亹亹。", "戲爲語韻網所遺，人皆百能子千之。", "雖非張巡遍記誦，豈與李翰爭毫釐。", "不待區區隸古定，便令景宗知去病。", "掇要虛煩四十篇，三卷之博能擬聖。", "儒林丈人摛藻春，作詩印可融心神。", "我亦從今悔迂學，不須更辨瓚稱臣。"]'),
('a720775f-04a0-43ad-827d-2974498e4dae','蒙再示屬辭三歎之餘讚巨麗無地托言輒依元韻再成一章非獨助家弟稱謝區區少褒之使進學焉亦師席善誘之意也','陳與義','宋','宋诗','song-poetry','','[]','書如嘉殽要知旨，區區太沖空詠史。',131,'全唐诗/poet.song.100000.json','["書如嘉殽要知旨，區區太沖空詠史。", "百年能挂幾牛角，火急編摩時亹亹。", "柳家文類今無遺，可忍行事空違之。", "此書真是群玉府，事辭所不遺毫釐。", "子不見劉勰書成要人定，豈但令人愈頭病。", "偶向車前問沈公，果符夢裏隨先聖。", "兩詩入手喜生春，從今護持知有神。", "便可繕寫持獻御，注解不須煩五臣。"]'),
('16cf11cf-9eaa-43b2-9d56-352f9a06b702','昨日侍巾鉢飯于天寧蒙示佳什謹次韻','陳與義','宋','宋诗','song-poetry','','[]','朱門未知禪悅義，富不期奢奢自至。',96,'全唐诗/poet.song.100000.json','["朱門未知禪悅義，富不期奢奢自至。", "二韮雖寒故是公，萬羊賈禍徒封衛。", "我公居塵不染塵，便隨一鉢遺甘辛。", "出家雖非將相事，食菜要是英雄人。", "臞儒一生用心苦，何曾夢見雞映黍。", "中丞惜福幸見分，晚食從公當羔羜。"]'),
('d5040919-d2b5-4e93-b94f-a0deaa05ad93','蒙再示佳什不敢虛辱厚賜謹再用韻','陳與義','宋','宋诗','song-poetry','','[]','先生明經今蔡義，念佛仍師大勢至。',96,'全唐诗/poet.song.100000.json','["先生明經今蔡義，念佛仍師大勢至。", "食菜不待周顒書，要斷貪殺兼自衛。", "顔回平生拾墮塵，蓼蟲食蓼忘其辛。", "先生種福我無禍，成佛定是同功人。", "兩詩見戒言甚苦，肯賦黄雞啄秋黍。", "從今但見懶殘芋，不敢求嘗鑒虛羜。"]'),
('6540d89d-90ba-453d-add6-7f21a5448b07','承知府待制誕生之辰輒廣善懷菩薩故事成古詩一首仰惟經世之外深入佛海而某欲託辭以寄款款適獲此事發寤於心似非偶然者獨荒陋不足以侈此殊慶耳','陳與義','宋','宋诗','song-poetry','','[]','歲星欲吐芒不開，昴星避次光低佪。',128,'全唐诗/poet.song.100000.json','["歲星欲吐芒不開，昴星避次光低佪。", "麒麟鸑鷟紛夾侍，善懷菩薩當重來。", "仙公風流今幾歲，再託高門瑞當世。", "買香趁浴驚衆聾，要識此僧今我是。", "金粟後身何足言，釋迦親送非虛傳。", "稽首西來大菩薩，住世小劫須千年。", "宰官說法聊應會，餘事文章亦三昧。", "世間底物堪壽公，本自金剛無可壞。"]'),
('f106f9ea-8176-4169-a21f-c4d2b0eb603d','遊紫邏洞','陳與義','宋','宋诗','song-poetry','','[]','我不願封萬戶侯，願向紫邏從公遊。',128,'全唐诗/poet.song.100000.json','["我不願封萬戶侯，願向紫邏從公遊。", "鄆州溪堂虢州洞，未有退之詩可留。", "水近山流清澈底，竹飽千霜節如此。", "廊廟之具千金軀，底事便著山巖裏。", "蒲鞭掛壁一事無，環珮聲中了朝晡。", "祝融不到林深處，客至五月懷貂狐。", "徇華大夫無此樂，從渠遮山用翠幙。", "若問此間奇絕處，但道胸中有丘壑。"]'),
('4a873a6a-c5e2-4a24-bc76-32f8a36858a8','研銘','陳與義','宋','宋诗','song-poetry','','[]','無住菴，老居士。',88,'全唐诗/poet.song.100000.json','["無住菴，老居士。", "紫玉池，娛晚歲。", "不出菴，書誦偈。", "誰使之，踐朝市。", "入承明，司帝制。", "如眢井，久不治。", "百尺泉，來莫冀。", "古之人，輕百計。", "惟出處，不敢易。", "嗟已晚，覺非是。", "勒斯銘，戒後世。"]'),
('17bea1a9-07ba-4ced-bf48-577e76ad1c2d','曾徽言運判出張生所畫馬','陳與義','宋','宋诗','song-poetry','','[]','槃礴解衣處，胸中應不羣。',48,'全唐诗/poet.song.100000.json','["槃礴解衣處，胸中應不羣。", "未呈千里足，空見五花文。", "良樂世難有，驥駑誰與分。", "高才喜能事，故遣畫蘭筋。"]'),
('43241fed-dc1e-4519-ba54-282ec2b61996','火蛾','陳與義','宋','宋诗','song-poetry','','[]','陽光不照臨，積陰生此類。',48,'全唐诗/poet.song.100000.json','["陽光不照臨，積陰生此類。", "非無惜死心，素有賊明意。", "粉穿紅焰燋，翅撲蘭膏沸。", "爲爾一傷嗟，自棄非天棄。"]'),
('3dc01024-807c-498d-a18f-7553ea42599a','海棠','陳與義','宋','宋诗','song-poetry','','[]','紅粧翠袖一番新，人向園林作好春。',32,'全唐诗/poet.song.100000.json','["紅粧翠袖一番新，人向園林作好春。", "却笑華清誇睡足，只今羅襪久無塵。"]'),
('dbd80761-738b-432f-bfd1-4728dd60ff1d','燒香','陳與義','宋','宋诗','song-poetry','','[]','明窗延靜晝，默坐息諸緣。',96,'全唐诗/poet.song.100000.json','["明窗延靜晝，默坐息諸緣。", "聊將無窮意，寓此一炷烟。", "當時戒定慧，妙供均人天。", "我豈不清□，于今醒心然。", "爐香裊孤碧，雲縷飛數千。", "悠然凌空去，縹緲隨風還。", "世事有過現，薰性無變遷。", "應如水中月，波定還自丸。"]'),
('cea603ca-fa43-4d15-9c22-e7e2107d7c5d','紅葵','陳與義','宋','宋诗','song-poetry','','[]','恐是牡丹重換紫，又疑芍藥再飛紅。',32,'全唐诗/poet.song.100000.json','["恐是牡丹重換紫，又疑芍藥再飛紅。", "妖嬈不辨桑間女，蔽芾深迷苧下翁。"]'),
('5c0d007f-5fd6-4a3e-a935-5cc10c125c67','山居','陳與義','宋','宋诗','song-poetry','','[]','耿耿虛堂一榻秋，人間高枕幾王侯。',64,'全唐诗/poet.song.100000.json','["耿耿虛堂一榻秋，人間高枕幾王侯。", "亂雲未放曉山出，片月不隨寒水流。", "檢校一身渾是懶，平章千古得無愁。", "湘波見說清人骨，恨不移家阿那州。"]'),
('2a9b3aff-9417-4deb-bd96-68e5adcafd80','雨過','陳與義','宋','宋诗','song-poetry','','[]','水堂長日靜鷗沙，便覺京塵隔鬢華。',32,'全唐诗/poet.song.100000.json','["水堂長日靜鷗沙，便覺京塵隔鬢華。", "夢裏不知凉是雨，卷簾微溼在荷花。"]'),
('3ba10b21-278e-43d1-a75f-ec61bc96b4f7','長干行','陳與義','宋','宋诗','song-poetry','','[]','妾家長干里，春慵晏未起。',180,'全唐诗/poet.song.100000.json','["妾家長干里，春慵晏未起。", "花香襲夢回，略略事梳洗。", "妝臺罷窺鏡，盛色照江水。", "郎帆十幅輕，渾不聞櫓聲。", "曲岸轉掀篷，一見兮目成。", "羞聞媒致辭，心許郎深情。", "一床兩年少，相看悔不早。", "酒懽娛藏鬮，園嬉索鬬草。", "含笑盟春風，同心以偕老。", "郎行有程期，郎知妾未知。", "鷁首生羽翼，蛾眉無光輝。", "寄來紙上字，不盡心中事。", "問遍相逢人，不如自見真。", "心苦淚更苦，滴爛閨中土。", "寄語里中兒，莫作商人婦。"]'),
('e4502820-22ea-4dfd-a974-9447eac442de','九日家中','陳與義','宋','宋诗','song-poetry','','[]','風雨吳江冷，雲天故國賒。',48,'全唐诗/poet.song.100000.json','["風雨吳江冷，雲天故國賒。", "扶頭呼白酒，揩眼認黄花。", "客夢蛩聲歇，邊心雁字斜。", "明年又何處，高樹莫啼鴉。"]'),
('2943fb3b-48ae-49b3-9d1e-0934b8f057c1','來禽','陳與義','宋','宋诗','song-poetry','','[]','粲粲來禽已著花，芳根誰徙向天涯。',32,'全唐诗/poet.song.100000.json','["粲粲來禽已著花，芳根誰徙向天涯。", "好尋青李相遮映，風味應同逸少家。"]'),
('6a440060-37de-40cc-b649-3293ddf52841','宣風樓','陳與義','宋','宋诗','song-poetry','','[]','樓迥雲隨畫栱飛，卷簾又映雪晴時。',32,'全唐诗/poet.song.100000.json','["樓迥雲隨畫栱飛，卷簾又映雪晴時。", "千林凍解陰霾掃，放出青山分外奇。"]'),
('4dcfc979-e142-4617-90f2-beeb23ce7a90','萬玉亭','陳與義','宋','宋诗','song-poetry','','[]','萬玉中間作此亭，規模雖小意高深。',64,'全唐诗/poet.song.100000.json','["萬玉中間作此亭，規模雖小意高深。", "稚篁畏日生檐下，老樹禁風長綠陰。", "不道官中盡湯火，誰知鬧裏有山林。", "公餘獨在斜陽外，百歲頑身萬古心。"]'),
('5c477bc6-8d59-4745-a9ee-84a7a883280b','句','陳與義','宋','宋诗','song-poetry','','[]','老對白桂花。',6,'全唐诗/poet.song.100000.json','["老對白桂花。"]'),
('b18c5790-99ef-4d94-85fc-b0bb69cf27d2','野泊對月有感','周莘','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','可憐江月亂中明，應識逋逃病客情。',64,'全唐诗/poet.song.100000.json','["可憐江月亂中明，應識逋逃病客情。", "斗柄闌干洞庭野，角聲淒斷岳陽城。", "酒添客淚愁仍濺，浪卷歸心暗自驚。", "欲問行朝近消息，眼中羣盜尚縱橫。"]'),
('96a4fc8b-83da-49ee-b43f-d7b257fa35d3','明月樓','張致遠','宋','宋诗','song-poetry','','[]','明月樓前可萬家，鳳山菴下日初斜。',32,'全唐诗/poet.song.100000.json','["明月樓前可萬家，鳳山菴下日初斜。", "風流耆舊消沉盡，空睇寒江耿暮霞。"]'),
('88efa631-8c42-4cc2-ac2f-634b6fd8644b','祭梅州守','張致遠','宋','宋诗','song-poetry','','[]','四百餘年鰐不歸，七十二灘險莫支。',32,'全唐诗/poet.song.100000.json','["四百餘年鰐不歸，七十二灘險莫支。", "千艘上下無傾欹，波間小艇理筩絲。"]'),
('456a37d7-f31c-4132-b8cd-20c527187fa9','觀陳諫議祠有感','張致遠','宋','宋诗','song-poetry','','[]','權門車馬日騑騑，獨犯天顔咫尺威。',64,'全唐诗/poet.song.100000.json','["權門車馬日騑騑，獨犯天顔咫尺威。", "願借君王斬馬劍，何慚妻子泣牛衣。", "丹書到死成羅織，青史平生賴發揮。", "遥望湘濱成楚些，英魂應逐屈原歸。"]'),
('fd5c3606-6817-405f-87d6-651810d62e75','百丈寺','張致遠','宋','宋诗','song-poetry','','[]','微官驅我走塵埃，每到林泉眼豁開。',32,'全唐诗/poet.song.100000.json','["微官驅我走塵埃，每到林泉眼豁開。", "蓮社未容書姓字，又隨流水出山來。"]'),
('00847221-b9a2-424c-ab46-8bdfcd807bae','句  其一','張致遠','宋','宋诗','song-poetry','','[]','曾井有泉消毒瘴，程江無屋祠高賢。',16,'全唐诗/poet.song.100000.json','["曾井有泉消毒瘴，程江無屋祠高賢。"]'),
('caf3f25c-c84c-46bf-b3b1-75c911c71e90','句  其二','張致遠','宋','宋诗','song-poetry','','[]','三寺樓臺烟霧裏，一川蘆葦畫圖中。',16,'全唐诗/poet.song.100000.json','["三寺樓臺烟霧裏，一川蘆葦畫圖中。"]'),
('513e47b5-323c-4a66-994c-131c5b5246ed','絕句','楊杞','宋','宋诗','song-poetry','','[]','三間茅屋獨家村，風雨蕭蕭可斷魂。',32,'全唐诗/poet.song.100000.json','["三間茅屋獨家村，風雨蕭蕭可斷魂。", "舊日相如猶有壁，如今無壁更無門。"]'),
('6da9094b-1540-4630-a86b-622bb0da5d35','偈','釋景深','宋','宋诗','song-poetry','','[]','火裏靈苗秀，無根偏界生。',24,'全唐诗/poet.song.100000.json','["火裏靈苗秀，無根偏界生。", "諸人如體悉，千里共途行。"]'),
('1924b77b-ac41-488c-90aa-cb144ae1a061','辭衆偈','釋景深','宋','宋诗','song-poetry','','[]','不用剃頭，何須澡浴。',20,'全唐诗/poet.song.100000.json','["不用剃頭，何須澡浴。", "一堆紅焰，千足萬足。"]'),
('731a3286-20b2-483b-a716-c40fb3ef0d0a','題范文正公書伯夷頌後','秦檜','宋','宋诗','song-poetry','','[]','高賢邈已遠，凜凜生氣存。',24,'全唐诗/poet.song.100000.json','["高賢邈已遠，凜凜生氣存。", "韓范不時有，此心誰與論。"]'),
('9eaf420f-d35e-40cb-ac99-284c1c7d2752','句','秦檜','宋','宋诗','song-poetry','','[]','若得水田三百畝，這番不做猴孫王。',16,'全唐诗/poet.song.100000.json','["若得水田三百畝，這番不做猴孫王。"]'),
('704c90ea-9bd4-43d7-a61f-be84bbeb23ca','句','秦檜客','宋','宋诗','song-poetry','','[]','傳聞是日慈寧殿，亦把爐香祝帝師。',16,'全唐诗/poet.song.100000.json','["傳聞是日慈寧殿，亦把爐香祝帝師。"]'),
('53de85ba-af6c-4c38-b661-663ad06a1a58','黄陵廟','陸士規','宋','宋诗','song-poetry','','[]','東風吹草綠離離，路入黄陵古廟西。',32,'全唐诗/poet.song.100000.json','["東風吹草綠離離，路入黄陵古廟西。", "帝子不知春又去，亂山無主鷓鴣啼。"]'),
('6ed55091-b25c-48f4-915c-ca12c382ce6d','句','李善','宋','宋诗','song-poetry','','[]','無窮基有無窮問，第一人爲第一官。',16,'全唐诗/poet.song.100000.json','["無窮基有無窮問，第一人爲第一官。"]'),
('08a261cb-4e4e-4fbc-aa36-cd478a5014dc','梁寶寺','湯喬年','宋','宋诗','song-poetry','','[]','田舍風光迥，僧房意象深。',48,'全唐诗/poet.song.100000.json','["田舍風光迥，僧房意象深。", "未窮千里目，聊慰一時心。", "遠樹輕烟入，孤村落日侵。", "自非真靜者，誰復有幽尋。"]'),
('e6f776e6-d9cb-4279-912d-d9f3f8fb50d9','拂雲亭','洪興祖','宋','宋诗','song-poetry','','[]','黄雲收盡綠針齊，江北江南水拍隄。',32,'全唐诗/poet.song.100000.json','["黄雲收盡綠針齊，江北江南水拍隄。", "野老扶携相告語，兒童今始識鋤犁。"]'),
('b233f70d-134e-4562-be3f-0584f76fb2d2','句','洪興祖','宋','宋诗','song-poetry','','[]','願公十襲勿浪出，六丁取將飛辟歷。',16,'全唐诗/poet.song.100000.json','["願公十襲勿浪出，六丁取將飛辟歷。"]'),
('0d76689c-f083-45a8-989b-67fe5516b6aa','耕圖二十一首 浸種','樓璹','宋','宋诗','song-poetry','','[]','谿頭夜雨足，門外春水生。',48,'全唐诗/poet.song.100000.json','["谿頭夜雨足，門外春水生。", "筠籃浸淺碧，嘉穀抽新萌。", "西疇將有事，耒耜隨晨興。", "隻雞祭句芒，再拜祈秋成。"]'),
('d83df217-f416-458d-b560-9b602b8f24d5','耕圖二十一首 耕','樓璹','宋','宋诗','song-poetry','','[]','東皋一犂雨，布穀初催耕。',48,'全唐诗/poet.song.100000.json','["東皋一犂雨，布穀初催耕。", "綠野暗春曉，烏犍苦肩赬。", "我銜勸農字，杖策東郊行。", "永懷歷山下，法事關聖情。"]'),
('459982ac-430a-4f31-b619-f157892bc046','耕圖二十一首 杷耨','樓璹','宋','宋诗','song-poetry','','[]','雨笠冒宿霧，風蓑擁春寒。',48,'全唐诗/poet.song.100000.json','["雨笠冒宿霧，風蓑擁春寒。", "破塊得甘霔，齧塍浸微瀾。", "泥深四蹄重，日暮兩股酸。", "謂彼牛後人，著鞭無作難。"]'),
('41d07f6c-fc8f-469f-9c75-d4e43c7c84a9','耕圖二十一首 耖','樓璹','宋','宋诗','song-poetry','','[]','脫绔下田中，盎漿著塍尾。',48,'全唐诗/poet.song.100000.json','["脫绔下田中，盎漿著塍尾。", "巡行遍畦畛，扶耖均泥滓。", "遲遲春日斜，稍稍樵歌起。", "薄暮佩牛歸，共浴前谿水。"]'),
('5856a206-8767-4ebd-aa4d-4b7a36b1cccd','耕圖二十一首 碌碡','樓璹','宋','宋诗','song-poetry','','[]','力田巧機事，利器由心匠。',48,'全唐诗/poet.song.100000.json','["力田巧機事，利器由心匠。", "翩翩轉圜樞，衮衮鳴翠浪。", "三春欲盡頭，萬頃平如掌。", "漸暄牛已喘，長懷丙丞相。"]'),
('cee9a2a9-6da8-4af9-adb0-fd3fc58b7ebc','耕圖二十一首 布秧','樓璹','宋','宋诗','song-poetry','','[]','舊穀發新穎，梅黄雨生肥。',48,'全唐诗/poet.song.100000.json','["舊穀發新穎，梅黄雨生肥。", "下田初播殖，却行手奮揮。", "明朝望平疇，綠鍼刺風漪。", "審此一寸根，行作合穗期。"]'),
('268f439c-940b-4d9d-9e9a-558ddd15dcbb','耕圖二十一首 淤蔭','樓璹','宋','宋诗','song-poetry','','[]','殺草聞吳兒，灑灰傳自祖。',48,'全唐诗/poet.song.100000.json','["殺草聞吳兒，灑灰傳自祖。", "田田皆沃壤，泫泫流膏乳。", "塍頭烏啄泥，谷口鳩喚雨。", "敢望稼如雲，工夫蓋如許。"]'),
('eb81f9f9-0e29-43d1-9ccf-7fab9fc65228','耕圖二十一首 拔秧','樓璹','宋','宋诗','song-poetry','','[]','新秧初出水，渺渺翠毯齊。',48,'全唐诗/poet.song.100000.json','["新秧初出水，渺渺翠毯齊。", "清晨且拔擢，父子爭提携。", "既沐青滿握，再櫛根無泥。", "及時趁芒種，散著畦東西。"]'),
('b88b4883-ad37-466e-bd54-b771ce33f305','耕圖二十一首 插秧','樓璹','宋','宋诗','song-poetry','','[]','晨雨麥秋潤，午風槐夏凉。',48,'全唐诗/poet.song.100000.json','["晨雨麥秋潤，午風槐夏凉。", "谿南與谿北，嘯歌插新秧。", "拋擲不停手，左右無亂行。", "我將教秧馬，代勞民莫忘。"]'),
('813ac977-844b-4691-804f-d99dea7849d0','耕圖二十一首 一耘','樓璹','宋','宋诗','song-poetry','','[]','時雨既已降，良苗日懷新。',48,'全唐诗/poet.song.100000.json','["時雨既已降，良苗日懷新。", "去草如去惡，務令盡陳根。", "泥蟠任犢鼻，膝行生浪紋。", "眷惟聖天子，儻亦思鳥耘。"]'),
('8943e730-adb4-4a13-b76b-08e66263b0cb','耕圖二十一首 二耘','樓璹','宋','宋诗','song-poetry','','[]','解衣日炙背，戴笠汗濡首。',48,'全唐诗/poet.song.100000.json','["解衣日炙背，戴笠汗濡首。", "敢辭冒炎蒸，但欲去莨莠。", "壺漿與簞食，亭午來餉婦。", "要兒知稼穡，豈曰事携幼。"]'),
('17cdf548-eb51-4e5d-becb-4f85a37a8ba8','耕圖二十一首 三耘','樓璹','宋','宋诗','song-poetry','','[]','農田亦甚劬，三復事耘耔。',48,'全唐诗/poet.song.100000.json','["農田亦甚劬，三復事耘耔。", "經年苦艱食，喜見苗薿薿。", "老農念一飽，對此出饞水。", "願天均雨暘，滿野如雲委。"]'),
('108360d9-5f47-4f84-81bd-052f98826bbf','耕圖二十一首 灌溉','樓璹','宋','宋诗','song-poetry','','[]','揠苗鄙宋人，抱甕慚蒙莊。',48,'全唐诗/poet.song.100000.json','["揠苗鄙宋人，抱甕慚蒙莊。", "何如銜尾鴉，倒流竭池塘。", "䆉䅉舞翠浪，籧篨生晝凉。", "斜陽耿衰柳，笑歌閒女郎。"]'),
('ebc6fe38-8376-4c4e-9b46-f11530a1741d','耕圖二十一首 收刈','樓璹','宋','宋诗','song-poetry','','[]','田家刈穫時，腰鎌競倉卒。',48,'全唐诗/poet.song.100000.json','["田家刈穫時，腰鎌競倉卒。", "霜濃手龜坼，日永身罄折。", "兒童行拾穗，風色凌短褐。", "歡呼荷擔歸，望望屋山月。"]'),
('8f8f7988-c42c-41eb-b761-074e2760c05c','耕圖二十一首 登場','樓璹','宋','宋诗','song-poetry','','[]','禾黍已登場，稍覺農事優。',48,'全唐诗/poet.song.100000.json','["禾黍已登場，稍覺農事優。", "黄雲滿高架，白水空西疇。", "用此可卒歲，願言免防秋。", "太平本無象，村舍炊煙浮。"]'),
('f3064046-da9c-41c2-ab46-f903afb67ca3','耕圖二十一首 持穗','樓璹','宋','宋诗','song-poetry','','[]','霜時天氣佳，風勁木葉脫。',48,'全唐诗/poet.song.100000.json','["霜時天氣佳，風勁木葉脫。", "持穗及此時，連枷聲亂發。", "黄雞啄遺粒，烏鳥喜聒聒。", "歸家抖塵埃，夜屋燒榾柮。"]'),
('5b1dccc7-e122-4fc9-898f-fabfb198fee3','耕圖二十一首 簸揚','樓璹','宋','宋诗','song-poetry','','[]','臨風細揚簸，糠粃零風前。',48,'全唐诗/poet.song.100000.json','["臨風細揚簸，糠粃零風前。", "傾瀉雨聲碎，把翫玉粒圓。", "短裙箕帚婦，收拾亦已專。", "豈圖較斗升，未敢忘凶年。"]'),
('f2ed999f-163a-4773-bc28-0e735c2cdf76','耕圖二十一首 礱','樓璹','宋','宋诗','song-poetry','','[]','推挽人摩肩，展轉石礪齒。',48,'全唐诗/poet.song.100000.json','["推挽人摩肩，展轉石礪齒。", "殷床作春雷，旋風落雲子。", "有如布山川，部婁勢相峙。", "前時斗量珠，滿眼俄有此。"]'),
('8d7232c1-bd3a-4fb3-9d2a-403d3e1a478a','耕圖二十一首 舂碓','樓璹','宋','宋诗','song-poetry','','[]','娟娟月過牆，簌簌風吹葉。',48,'全唐诗/poet.song.100000.json','["娟娟月過牆，簌簌風吹葉。", "田家當此時，村舂響相答。", "行聞炊玉香，會見流匙滑。", "更須水轉輪，地碓勞蹴蹋。"]'),
('fecc8a09-7b87-4af2-87fa-621da080e5f4','耕圖二十一首 籭','樓璹','宋','宋诗','song-poetry','','[]','茅檐閒杵臼，竹屋細籭簸。',48,'全唐诗/poet.song.100000.json','["茅檐閒杵臼，竹屋細籭簸。", "照人珠琲光，奮臂風雨過。", "計功初不淺，飽食良自賀。", "西鄰華屋兒，醉飽正高卧。"]'),
('697de327-e83e-465d-9ded-ff759f3224c7','耕圖二十一首 入倉','樓璹','宋','宋诗','song-poetry','','[]','天寒牛在牢，歲暮粟入庾。',48,'全唐诗/poet.song.100000.json','["天寒牛在牢，歲暮粟入庾。", "田父有餘樂，炙背卧檐廡。", "却愁催賦租，胥吏來旁午。", "輸官王事了，索飯兒叫怒。"]'),
('4bc6771c-b94b-42f8-a102-e9cb92d5dca8','織圖二十四首 浴蠶','樓璹','宋','宋诗','song-poetry','','[]','農桑將有事，時節過禁烟。',48,'全唐诗/poet.song.100000.json','["農桑將有事，時節過禁烟。", "輕風歸燕日，小雨浴蠶天。", "春衫卷縞袂，盆池弄清泉。", "深宮想齋戒，躬桑率民先。"]'),
('c6c0928d-d0f7-4f79-a101-ebe7363904bd','織圖二十四首 下蠶','樓璹','宋','宋诗','song-poetry','','[]','穀雨無幾日，谿山暖風高。',48,'全唐诗/poet.song.100000.json','["穀雨無幾日，谿山暖風高。", "華蠶初破殻，落紙細于毛。", "柔桑摘蟬翼，簌簌才容刀。", "茅檐紙窗明，未覺眼力勞。"]'),
('0c1b5c91-1596-4c07-ae6d-8cc0175fa6bf','織圖二十四首 餵蠶','樓璹','宋','宋诗','song-poetry','','[]','蠶兒初飯時，桑葉如錢許。',48,'全唐诗/poet.song.100000.json','["蠶兒初飯時，桑葉如錢許。", "扳條摘鵝黄，藉紙觀蟻聚。", "屋頭草木長，窗下兒女語。", "日長人頗閒，鍼線隨緝補。"]'),
('4b9d3348-5be3-4d41-a5fc-02510588ea7d','織圖二十四首 一眠','樓璹','宋','宋诗','song-poetry','','[]','蠶眠白日靜，鳥語青春長。',48,'全唐诗/poet.song.100000.json','["蠶眠白日靜，鳥語青春長。", "抱脛聊假寐，孰能事梳妝。", "水邊多麗人，羅衣蹋春陽。", "春陽無限思，豈知問農桑。"]'),
('eacfe6e6-c62e-4d37-879e-9337f6d32934','織圖二十四首 二眠','樓璹','宋','宋诗','song-poetry','','[]','吳蠶一再眠，竹屋下簾幕。',48,'全唐诗/poet.song.100000.json','["吳蠶一再眠，竹屋下簾幕。", "拍手弄嬰兒，一笑姑不惡。", "風來麥秀寒，雨過桑沃若。", "日高蠶未起，谷鳥鳴百箔。"]'),
('8efefc8b-0583-4240-b30c-329624a001bc','織圖二十四首 三眠','樓璹','宋','宋诗','song-poetry','','[]','屋裏蠶三眠，門前春過半。',48,'全唐诗/poet.song.100000.json','["屋裏蠶三眠，門前春過半。", "桑麻綠陰合，風雨長檠暗。", "葉底蟲絲繁，卧作字畫短。", "偷閒一枕肱，夢與楊花亂。"]'),
('f68c7c8d-1e62-4977-b26d-ca203ba0f4c0','織圖二十四首 分箔','樓璹','宋','宋诗','song-poetry','','[]','三眠三起餘，飽葉蠶局促。',48,'全唐诗/poet.song.100000.json','["三眠三起餘，飽葉蠶局促。", "衆多旋分箔，早晚磓滿屋。", "郊原過新雨，桑柘添濃綠。", "竹閒快活吟，慚愧麥飽熟。"]'),
('b134cf10-9baf-4d9a-96b9-75e91f03f296','織圖二十四首 採桑','樓璹','宋','宋诗','song-poetry','','[]','吳兒歌採桑，桑下青春深。',48,'全唐诗/poet.song.100000.json','["吳兒歌採桑，桑下青春深。", "鄰里講歡好，遜畔無欺侵。", "筠籃各自携，筠梯高倍尋。", "黄鸝飽紫葚，啞咤鳴綠陰。"]'),
('f6c1ffcd-06dc-49e9-a132-4e2c1ac659ad','織圖二十四首 大起','樓璹','宋','宋诗','song-poetry','','[]','盈箱大起時，食桑聲似雨。',48,'全唐诗/poet.song.100000.json','["盈箱大起時，食桑聲似雨。", "春風老不知，蠶婦忙如許。", "呼兒刈青麥，朝飯已過午。", "妖歌得綾羅，不易青裙女。"]'),
('392d1984-a2b1-4eda-a5f5-8d8ae2375320','織圖二十四首 捉績','樓璹','宋','宋诗','song-poetry','','[]','麥黄雨初足，蠶老人愈忙。',48,'全唐诗/poet.song.100000.json','["麥黄雨初足，蠶老人愈忙。", "辛勤減眠食，顛倒著衣裳。", "絲腸映綠葉，練練金色光。", "松明照夜屋，杜宇啼東岡。"]'),
('a4f7cebf-4c0a-49fb-98f5-fb53be477e3e','織圖二十四首 上簇','樓璹','宋','宋诗','song-poetry','','[]','采采綠葉空，翦翦白茅短。',48,'全唐诗/poet.song.100000.json','["采采綠葉空，翦翦白茅短。", "撒簇輕放手，蠶老絲腸嫩。", "山市浮晴嵐，風日作妍暖。", "會看繭如甕，纍纍光眩眼。"]'),
('ef76d626-0516-455b-b296-d9b209370886','織圖二十四首 炙箔','樓璹','宋','宋诗','song-poetry','','[]','峩峩爇薪炭，重重下簾幕。',48,'全唐诗/poet.song.100000.json','["峩峩爇薪炭，重重下簾幕。", "初出蟲結網，遽若雪滿箔。", "老翁不勝勤，候火珠汗落。", "得閒兒女子，困卧呼不覺。"]'),
('610b4b03-791c-4fe3-9746-b0a1f5f4bed9','織圖二十四首 下簇','樓璹','宋','宋诗','song-poetry','','[]','晴明開雪屋，門巷排銀山。',48,'全唐诗/poet.song.100000.json','["晴明開雪屋，門巷排銀山。", "一年蠶事辦，下簇春向闌。", "鄰里兩相賀，翁媼一笑歡。", "后妃應獻繭，喜色開天顔。"]'),
('51a51366-8728-4938-9492-9b7efcb7e424','織圖二十四首 擇繭','樓璹','宋','宋诗','song-poetry','','[]','大繭至八蠶，小繭止獨蛹。',48,'全唐诗/poet.song.100000.json','["大繭至八蠶，小繭止獨蛹。", "繭衣繞指柔，收拾擬何用。", "冬來作縹絖，與兒禦寒凍。", "衣帛非不能，債多租稅重。"]'),
('79501faa-28d7-42ac-8a7c-3663f5c816c7','織圖二十四首 窖繭','樓璹','宋','宋诗','song-poetry','','[]','盤中水晶鹹，井上梧桐葉。',48,'全唐诗/poet.song.100000.json','["盤中水晶鹹，井上梧桐葉。", "陶器固封泥，窖繭過旬浹。", "門前春水生，布穀催畚鍤。", "明朝蹋繅車，車輪纏白氎。"]'),
('2cd4c654-a895-4844-90ca-24016aac0bc8','織圖二十四首 繅絲','樓璹','宋','宋诗','song-poetry','','[]','連村煮繭香，解事誰家娘。',48,'全唐诗/poet.song.100000.json','["連村煮繭香，解事誰家娘。", "盈盈意媚竈，拍拍手探湯。", "上盆顔色好，轉軸頭緒長。", "晚來得少休，女伴語隔牆。"]'),
('977ec7ee-346f-4148-9541-37228232cb26','織圖二十四首 蠶蛾','樓璹','宋','宋诗','song-poetry','','[]','蛾初脫纏縛，如蝶栩栩然。',48,'全唐诗/poet.song.100000.json','["蛾初脫纏縛，如蝶栩栩然。", "得偶粉翅光，散子金粟圜。", "歲月判悠悠，種嗣期綿綿。", "送蛾臨遠水，早歸屬明年。"]'),
('47947d2a-3cca-484f-a0ce-432fd993c020','織圖二十四首 祝謝','樓璹','宋','宋诗','song-poetry','','[]','春前作蠶市，盛事傳西蜀。',48,'全唐诗/poet.song.100000.json','["春前作蠶市，盛事傳西蜀。", "此邦享先蠶，再拜絲滿目。", "馬革裹玉肌，能神不爲辱。", "雖云事渺茫，解與民爲福。"]'),
('f44f0a83-f3ef-4931-a7c7-c03cd290dea5','織圖二十四首 絡絲','樓璹','宋','宋诗','song-poetry','','[]','兒夫督機絲，輸官趁時節。',48,'全唐诗/poet.song.100000.json','["兒夫督機絲，輸官趁時節。", "向來催租瘢，正爲坐踰越。", "朝來掉籰勤，寧復辭腕脫。", "辛勤夜未眠，敗屋燈明滅。"]'),
('50966c9b-2f0e-4ecc-8a23-efef12ce425b','織圖二十四首 經','樓璹','宋','宋诗','song-poetry','','[]','素絲頭緒多，羨君好安排。',48,'全唐诗/poet.song.100000.json','["素絲頭緒多，羨君好安排。", "青鞋不動塵，緩步交去來。", "眽眽意欲亂，眷眷首重回。", "王言正如絲，亦付經綸才。"]'),
('f981f967-bcab-471f-a262-620527bab149','織圖二十四首 緯','樓璹','宋','宋诗','song-poetry','','[]','浸緯供織作，寒女兩髻丫。',48,'全唐诗/poet.song.100000.json','["浸緯供織作，寒女兩髻丫。", "繾綣一縷絲，成就百種花。", "弄水春筍寒，卷輪蟾影斜。", "人閒小阿香，晴空轉雷車。"]'),
('e504d82d-4ca1-4de3-b839-7e8faa86db00','織圖二十四首 織','樓璹','宋','宋诗','song-poetry','','[]','青鐙映幃幙，絡緯鳴井欄。',48,'全唐诗/poet.song.100000.json','["青鐙映幃幙，絡緯鳴井欄。", "軋軋揮素手，風露淒已寒。", "辛勤度幾梭，始復成一端。", "寄言羅綺伴，當念麻苧單。"]'),
('6b3cfb56-1e69-4023-b3a6-b139caeac90b','織圖二十四首 攀花','樓璹','宋','宋诗','song-poetry','','[]','時態尚新巧，女工慕精勤。',48,'全唐诗/poet.song.100000.json','["時態尚新巧，女工慕精勤。", "心手暗相應，照眼花紛紜。", "殷勤挑錦字，曲折讀回文。", "更將無限思，織作雁背雲。"]'),
('99bcae57-b597-41d1-901f-bf46ee068c5b','織圖二十四首 翦帛','樓璹','宋','宋诗','song-poetry','','[]','低眉事機杼，細意把刀尺。',48,'全唐诗/poet.song.100000.json','["低眉事機杼，細意把刀尺。", "盈盈彼美人，翦翦其束帛。", "輸官給邊用，辛苦何足惜。", "大勝漢繚綾，粉涴不再著。"]'),
('06323b7c-6723-4146-b2e6-b3f4a7c51689','隆山院','宋之才','宋','宋诗','song-poetry','','[]','危磴盤雲杪，驚濤漲晚空。',48,'全唐诗/poet.song.100000.json','["危磴盤雲杪，驚濤漲晚空。", "江山端有待，杖履偶相同。", "孤塔蒼茫外，千帆杳靄中。", "誰知丘壑趣，未縛軟塵紅。"]'),
('78bc34a7-8ee7-4b13-ad35-fa603dab3a47','觀潮閣','宋之才','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','風烟未息倩詩催，小立欄桿亦快哉。',64,'全唐诗/poet.song.100000.json','["風烟未息倩詩催，小立欄桿亦快哉。", "江面貼天晴更好，濤頭拍案去仍回。", "晚山過雨亂鬟擁，細舶點空浮雁來。", "坐待月明寒練凈，片槎直欲到蓬萊。"]'),
('e29636e4-d728-4248-b5c3-af867b050c9e','石柱庵','宋之才','宋','宋诗','song-poetry','','[]','煉形仙入天聰洞，卓錫僧歸石柱庵。',32,'全唐诗/poet.song.100000.json','["煉形仙入天聰洞，卓錫僧歸石柱庵。", "窮勝不知天已晚，歸來藥徑月盈籃。"]'),
('ddebc9d2-3faf-4256-910e-ea4ba1c695f3','李伯紀丞相挽詩','賀允中','宋','宋诗','song-poetry','','[]','已矣經邦業，茫然造物心。',48,'全唐诗/poet.song.100000.json','["已矣經邦業，茫然造物心。", "人生固有定，天意頗難諶。", "此日嗟亡鑑，當年用作霖。", "吾皇方願治，十事想遺箴。"]'),
('88283ef8-763c-41ac-9947-7e5804230cb9','題石橋','賀允中','宋','宋诗','song-poetry','','[]','敢祈方廣現危梁，千古燈燃共此光。',32,'全唐诗/poet.song.100000.json','["敢祈方廣現危梁，千古燈燃共此光。", "聊試茶花便歸去，杖頭挑得晚風凉。"]'),
('88ab18ea-36af-4505-bb65-188277cb83e0','金山亭呈翁守二首  其一','方廷實','宋','宋诗','song-poetry','','[]','新亭高敞枕城隈，萬里江山爽氣來。',64,'全唐诗/poet.song.100000.json','["新亭高敞枕城隈，萬里江山爽氣來。", "雲外孤峰擎日晚，林間啼鳥喚春回。", "登車謾有澄清志，覽景慚非賦詠才。", "太守風流民訟簡，落成尊酒許相陪。"]'),
('72c5567a-04c8-4dd8-9004-48ad2447ccb6','金山亭呈翁守二首  其二','方廷實','宋','宋诗','song-poetry','','[]','丹碧崔嵬切斗魁，峰巒懷抱水縈回。',64,'全唐诗/poet.song.100000.json','["丹碧崔嵬切斗魁，峰巒懷抱水縈回。", "春歸巖谷幽花發，日上樓臺宿霧開。", "天近鳳城瞻帝座，雲迷鼇海接蓬萊。", "登臨誰會遲留意，共折梅花更一杯。"]'),
('215c468c-65ea-4de6-ac82-43f7883ed85c','句','方廷實','宋','宋诗','song-poetry','','[]','書亂床頭無甲乙，鳥鳴窗外自宮商。',16,'全唐诗/poet.song.100000.json','["書亂床頭無甲乙，鳥鳴窗外自宮商。"]'),
('db210129-2a60-460b-9454-09814d765570','白馬井','許康民','宋','宋诗','song-poetry','','[]','矍鑠平生善用兵，論他薏苡得貪名。',32,'全唐诗/poet.song.100000.json','["矍鑠平生善用兵，論他薏苡得貪名。", "不因渴驥遺蹤在，誰識將軍到底清。"]'),
('7eba67eb-1aeb-47d0-b678-6bb643fc2e93','寄吳晞遠','祖秀實','宋','宋诗','song-poetry','','[]','官路聲名二十年，江鄉舊仰貳車賢。',64,'全唐诗/poet.song.100000.json','["官路聲名二十年，江鄉舊仰貳車賢。", "推將事業歸塵外，收得功夫到酒邊。", "解榻幾聞招隱士，炷香終日對韋編。", "公朝況是登耆哲，早晚蒲輪穩著鞭。"]'),
('33245bc9-c5fc-4242-af64-1edc3c173319','過太平州拜李端叔遺像','折彥質','宋','宋诗','song-poetry','','[]','東來已數月，弛擔已渺茫。',144,'全唐诗/poet.song.100000.json','["東來已數月，弛擔已渺茫。", "猶喜災患身，獲登先生堂。", "肅衣拜遺像，依然雙頰光。", "宛若侍坐側，妙語發天藏。", "厄窮出天意，人理難度量。", "所幸言不朽，與世爲文章。", "齎此復何恨，私淑良不忘。", "小郎出見我，問知雛鳳凰。", "他年起門戶，塵滓濯秋陽。", "世事幾變滅，人生真黄粱。", "置之不足道，感慨涕淚滂。", "我行方有程，墳山空相望。"]'),
('4d19826f-8b55-42a0-943d-b8e8b87d4e7d','觀汪丞相所藏崔白畫羅漢','折彥質','宋','宋诗','song-poetry','','[]','山堂漠漠開曉烟，何許大士當四筵。',224,'全唐诗/poet.song.100000.json','["山堂漠漠開曉烟，何許大士當四筵。", "坐忘默識形骸外，持鉢植杖風露前。", "老龍欲奮屢回首，於菟甚馴非畏鞭。", "小兒已解辨人我，抱頭怖走成癡顛。", "豈知畏愛果何物，手裏舍利空燭天。", "嗟余耳目更淺陋，喜歡獲遇希有緣。", "神明泰定始一笑，摩挲粉墨心茫然。", "平生崔白畫常見，邂逅入眼多棄捐。", "莫言人物斗奇崛，醉裏落筆神助焉。", "汪公昔入魏帥幕，嘆息鉅壁圍神仙。", "歸尋十疋好東絹，恰有名手能摹傳。", "提携萬里到嶺表，尤物自得高人憐。", "邇來劫火壞諸有，陪都正苦紛戈鋋。", "無力挽河爲吹洗，披圖感極淚如泉。"]'),
('98403a6a-c9cd-4865-ae5b-c91505471b97','湘山留別','折彥質','宋','宋诗','song-poetry','','[]','寓久渾忘客，臨行似別家。',48,'全唐诗/poet.song.100000.json','["寓久渾忘客，臨行似別家。", "途窮身更怯，秋老鬢先華。", "生計黄茅合，歸期碧海賒。", "湘山今夜雨，留我意無涯。"]'),
('8ff32929-7dc0-45bf-9ff5-feecbfd711ec','跋浯溪造極圖','折彥質','宋','宋诗','song-poetry','','[]','浯溪未到已登臨，筆力能窮造化心。',32,'全唐诗/poet.song.100000.json','["浯溪未到已登臨，筆力能窮造化心。", "我是零陵新逐客，披圖一一可追尋。"]'),
('ce245f80-711c-4d44-8b7c-07c431e9ee7c','跋湘西清絕圖','折彥質','宋','宋诗','song-poetry','','[]','與山分淺正傷神，蠟屐明朝陌上塵。',32,'全唐诗/poet.song.100000.json','["與山分淺正傷神，蠟屐明朝陌上塵。", "誰寫湘西清絕景，巧移林壑慰行人。"]'),
('ff29c045-3ac9-45b9-8b65-89b973172d2d','超然亭','折彥質','宋','宋诗','song-poetry','','[]','超然亭上鬢毛斑，浩蕩秋風小立閒。',64,'全唐诗/poet.song.100000.json','["超然亭上鬢毛斑，浩蕩秋風小立閒。", "豈爲詩情堪過海，只緣脚力要尋山。", "峭峰斷續天容缺，高壘縈紆地勢慳。", "回首不堪東北望，桂林萬里是秦關。"]'),
('fe1bbd98-88fe-47de-aae0-a9478b0b72f7','濯纓亭','折彥質','宋','宋诗','song-poetry','','[]','澄練正縈檻，高屏近擁門。',24,'全唐诗/poet.song.100000.json','["澄練正縈檻，高屏近擁門。", "偏宜雲慘澹，更好月黄昏。"]'),
('9db1b932-09e9-465a-a05f-f2f82a15c27f','雷州蘇公樓','折彥質','宋','宋诗','song-poetry','','[]','二蘇翰墨仙，謫墜百蠻裏。',24,'全唐诗/poet.song.100000.json','["二蘇翰墨仙，謫墜百蠻裏。", "弟兄對床眠，此意孤一世。"]'),
('e4fc05dd-4555-4a7f-a7c9-914534b1f65b','寇萊公廟  其一','折彥質','宋','宋诗','song-poetry','','[]','萊公英特姿，譚笑安社稷。',24,'全唐诗/poet.song.100000.json','["萊公英特姿，譚笑安社稷。", "流離死窮荒，志士氣益塞。"]'),
('c10d1d45-8ea7-4877-9563-521f9e950ae0','寇萊公廟  其二','折彥質','宋','宋诗','song-poetry','','[]','死謫憐忠愍，生還喜子由。',24,'全唐诗/poet.song.100000.json','["死謫憐忠愍，生還喜子由。", "荒祠連舊宅，幾見海雲秋。"]'),
('e02cb0ab-beac-432e-8150-d209f0141e49','留別王六公','折彥質','宋','宋诗','song-poetry','','[]','六公八十尚占星，授法東坡今大成。',64,'全唐诗/poet.song.100000.json','["六公八十尚占星，授法東坡今大成。", "此歲得歸言不食，幾時當雨信如盟。", "誤人功業忍更問，老我林泉如可營。", "他日疑謀誰爲决，無由重到訪君平。"]'),
('4026b63e-617d-4477-bfde-e17c397782fc','渡海','折彥質','宋','宋诗','song-poetry','','[]','朝宗于海固願也，一葦杭之如勇何。',32,'全唐诗/poet.song.100000.json','["朝宗于海固願也，一葦杭之如勇何。", "著淺驚呼過又喜，此生是等事嘗多。"]'),
('2a688a53-debd-4754-b41a-58dd88d8030c','北歸渡海','折彥質','宋','宋诗','song-poetry','','[]','去日驚濤遠拍天，飛廉幾覆逐臣船。',32,'全唐诗/poet.song.100000.json','["去日驚濤遠拍天，飛廉幾覆逐臣船。", "歸舟陡頓能安穩，便覺君恩更煥然。"]'),
('6c65118c-67d3-4174-b8da-baa0ad9a66ee','留別許廷惠','折彥質','宋','宋诗','song-poetry','','[]','架空作屋纔容膝，中有道人能湛然。',64,'全唐诗/poet.song.100000.json','["架空作屋纔容膝，中有道人能湛然。", "門外紅塵雖擾擾，枕邊清夢自翩翩。", "君如海燕時須到，我似江鷗日又遷。", "回首石橋橋上月，與誰同賞第三年。"]'),
('79835c26-07a9-4903-a2d4-9191f56c3580','謝許君瑶','折彥質','宋','宋诗','song-poetry','','[]','東坡遺物來歸我，兩手摩挲思不窮。',32,'全唐诗/poet.song.100000.json','["東坡遺物來歸我，兩手摩挲思不窮。", "舉取吾家阿堵物，愧無青玉案酬公。"]'),
('00795e22-7a3b-4322-91b8-24649b65e713','全州尹氏觀','折彥質','宋','宋诗','song-poetry','','[]','當門懸泉一線白，繞屋稻田千畝青。',32,'全唐诗/poet.song.100000.json','["當門懸泉一線白，繞屋稻田千畝青。", "未論茯苓能解垢，且教月色滿空庭。"]'),
('411b9bfb-8c1d-408e-a979-0d98a778ff54','法輪寺','折彥質','宋','宋诗','song-poetry','','[]','路轉崎嶇嶺，水藏委曲田。',48,'全唐诗/poet.song.100000.json','["路轉崎嶇嶺，水藏委曲田。", "茂林深似海，古剎湛如淵。", "岣嶁未可到，禹碑真謾傳。", "西林歸恐暮，欲去又茫然。"]'),
('2dc13fcc-527c-45a6-9973-21bb8a716580','勝業寺','折彥質','宋','宋诗','song-poetry','','[]','故宮餘禹跡，勝地屬僧家。',48,'全唐诗/poet.song.100000.json','["故宮餘禹跡，勝地屬僧家。", "古廟松陰合，幽亭竹影斜。", "嶺雲吟外澹，山鳥定中譁。", "譴逐成輕別，空懷客路賒。"]'),
('72ec3939-ff97-4e2e-904b-80d3abe3c98a','句  其一','折彥質','宋','宋诗','song-poetry','','[]','煉丹垂老心猶健，懷橘當年事已非。',16,'全唐诗/poet.song.100000.json','["煉丹垂老心猶健，懷橘當年事已非。"]'),
('2491a1d0-ae11-4d0a-a0de-48017e505874','句  其二','折彥質','宋','宋诗','song-poetry','','[]','石橋步月公居後，橘井烹茶我在先。',16,'全唐诗/poet.song.100000.json','["石橋步月公居後，橘井烹茶我在先。"]'),
('c12fd99d-ad2b-459d-a232-25b881ce1f47','句  其三','折彥質','宋','宋诗','song-poetry','','[]','待公輔佐中興了，乞取袈裟送暮身。',16,'全唐诗/poet.song.100000.json','["待公輔佐中興了，乞取袈裟送暮身。"]'),
('55b1e5d5-d280-4151-a266-3d5de624ffee','次韻大父曬麥','蘇籀','宋','宋诗','song-poetry','','[]','西郊歲種十畝麥，自笑不耕惟坐食。',160,'全唐诗/poet.song.100000.json','["西郊歲種十畝麥，自笑不耕惟坐食。", "吾人一飽已天幸，此外何心更求得。", "我田長熟無旱潦，玉粒收來堅且好。", "豈同豪右執券契，虐取多求急於盜。", "我家治生無奇功，累世守此慈儉風。", "倉囷不滿非所恤，冒暑一曬安敢慵。", "長空不見纖雲起，沽酒烹雞會鄰里。", "炎飚不厭塵滿身，冷餅行看冰上齒。", "閒居捨此一事無，狥時干祿姑捨諸。", "信知爲農自足樂，秦相未必賢牽盧。"]'),
('445163a4-f29f-40e7-bbfc-a5313ea3628f','大父令賦舊扇','蘇籀','宋','宋诗','song-poetry','','[]','裁紈當團扇，當暑不離手。',108,'全唐诗/poet.song.100000.json','["裁紈當團扇，當暑不離手。", "炎凉一推遷，委擲昏塵垢。", "蒙蒙縈蛛網，闇闇迷遠岫。", "人情逐時移，浪自分好醜。", "一朝被收錄，已迫朱明候。", "開篋振浮埃，清風亦生袖。", "有愛必有憎，無新故無舊。", "可憐漢婕妤，涕泣將爲咎。", "賢哉楚令尹，無欣亦無詬。"]'),
('2b4e65a8-3790-45b5-a510-eab2450a2d9a','大父令賦捕魚','蘇籀','宋','宋诗','song-poetry','','[]','寒魚不樂水，遇汕輒來依。',96,'全唐诗/poet.song.100000.json','["寒魚不樂水，遇汕輒來依。", "溪邊蓑笠翁，智深魚莫知。", "網罟既不設，釣竿亦罷携。", "蕭然徒手來，一一收無遺。", "幽人買魚食，心亦憐魚癡。", "早知烹割苦，寧如在流澌。", "世人豈異此，外物常見羈。", "好在李斯犬，當觀莊子犧。"]'),
('38716613-761a-40a3-92ab-822c1deb34d9','咸陽縣令求清渭樓詩和何子應長句','蘇籀','宋','宋诗','song-poetry','','[]','秦如蒹葭未飽霜，四維不舉空豪强。',288,'全唐诗/poet.song.100000.json','["秦如蒹葭未飽霜，四維不舉空豪强。", "神疲鬼乏赴功利，兆自襄公終始皇。", "富極薰天力斡地，諸侯西來誰敢當。", "范雎李斯乘利勢，蒙驁白起先戎行。", "韓盧前奔宋鵲舉，角逐海內如驅羊。", "干戈取之刑法治，舉事夸淫惟快意。", "時移數盡非徒然，直筆汗青遭唾毀。", "咸陽宮殿無尺瓦，直抵南山是禾稼。", "山巔觀闕總成塵，清渭東流無晝夜。", "昔時此水貫宮垣，今日淪漣縣樓下。", "無復秦娥洗粧水，時有村童飲牛馬。", "秋波泠泠泛紅葉，春天波蕩桃花節。", "清名不與世榮辱，混濁何嘗妨至潔。", "八川分流皆異態，七澤胸中無芥蔕。", "直須面面倚危欄，殫睹雍州原野火。", "樓中有客雍門彈，坐上悲歌擊樽壞。", "何侯精采如琳琅，携詩揖我謂我臧。", "我今爲子登樓賦，書版一諷悲興亡。"]'),
('ed408935-931b-45a4-9570-818e533b1efe','次韻范氏子園居即事三首  其一','蘇籀','宋','宋诗','song-poetry','','[]','媚蘭多畦畹，黨竹論尺尋。',72,'全唐诗/poet.song.100000.json','["媚蘭多畦畹，黨竹論尺尋。", "倦矣一枝足，卓哉千里心。", "氣含湖海姿，名掛羆虎林。", "長髯罥世累，禿鬢微霜侵。", "雕鉆久已休，潜伏恨不深。", "亭丘近來趣，何止如山陰。"]'),
('e74a1bd3-8ccd-4f4c-88a1-34bc310f7600','次韻范氏子園居即事三首  其二','蘇籀','宋','宋诗','song-poetry','','[]','沼沚清漣生，沄沄復浼浼。',48,'全唐诗/poet.song.100000.json','["沼沚清漣生，沄沄復浼浼。", "爨清飯不足，歡賞心無餒。", "金絲撚條柯，酥蠟滴趺蕾。", "櫻桃與芍藥，春事卜貞悔。"]'),
('4ca9f2aa-86cd-41bf-ac23-62cfe59c29b7','次韻范氏子園居即事三首  其三','蘇籀','宋','宋诗','song-poetry','','[]','花開且復謝，迴首悲今昨。',72,'全唐诗/poet.song.100000.json','["花開且復謝，迴首悲今昨。", "席月吹參差，臨芳傾鑿落。", "莎蘋藉醉枕，風竹驚眠覺。", "賓僚上馬去，烏鳥相呼樂。", "春光在木杪，花絮相紛箔。", "酒到忘醇醨，客來無善惡。"]'),
('4ccdb701-24d5-4b92-a824-32e636d6f617','耕者得古玉指環一首','蘇籀','宋','宋诗','song-poetry','','[]','百世繁華墮劫灰，淒凉斷簪并擘釵。',176,'全唐诗/poet.song.100000.json','["百世繁華墮劫灰，淒凉斷簪并擘釵。", "淑顔窈窕亦塵土，指環耕出田中來。", "野人辛勤務稼穡，兩手龜拆闢草萊。", "未知此環竟安用，但訝光采尤奇瑰。", "王孫捉麈不辨玉，手面膏拭無纖埃。", "柔荑纖纖擢紺袖，五雲書勢高崔嵬。", "金撥收聲飫犀筯，冰遏紅牙誠妙哉。", "指環不肯貧家售，東鄰女貧人道醜。", "巧梳墮馬長掃眉，五色紝針工組繡。", "古人製器知爲誰，今時豈乏春風手。", "春葱銀甲深藏袖，偕老賦詩須我友。"]'),
('fb546a16-0989-4257-8dc1-ceb5f435c02c','遊寒谿次醅字韻題九曲亭一首','蘇籀','宋','宋诗','song-poetry','','[]','幅巾戲漉彭澤醅，尺書間覓來禽栽。',224,'全唐诗/poet.song.100000.json','["幅巾戲漉彭澤醅，尺書間覓來禽栽。", "東坡居士五年久，真主未遽求鹽梅。", "扁舟夷猶水刻窟，雙履禿缺峯峩嵬。", "招揖西山與東魯，迴首閶闔并玉臺。", "標牓高甍方外景，不染時世毫端埃。", "倚空千重翡翠蓋，落日萬頃琉璃堆。", "興酣魚鳥安樂國，喜溢僕馭陶家罍。", "惜哉二老削舊跡，不論石上并牆隈。", "碕岸橫舟昔時處，刻劃獨免漫蒼苔。", "梵剎青蓮舊僧社，徑遂幾合無人開。", "方今九原如可作，足使四海無凋摧。", "封章千載垂可否，玉堂黄閤猶儋雷。", "精義窮神致實用，不變生死無去來。", "天下書生踐遺跡，棠蔭處處思賢哀。"]'),
('a049ab15-923b-4e91-9dc5-9293874e7b70','次韻答晁以道見贈二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','骨髓緘藏萬古謀，畔牢愁思不禁秋。',64,'全唐诗/poet.song.100000.json','["骨髓緘藏萬古謀，畔牢愁思不禁秋。", "常憐屈宋鳴中古，不遇丘軻放一頭。", "文賦東坡推典麗，簡書西路失歸休。", "看公議論方遊夏，豈數蘇州與柳州。"]'),
('6367a60f-9352-4c52-8d9f-7945becb9f54','次韻答晁以道見贈二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','玉井之泉汲又新，腐陳收拾已空囷。',32,'全唐诗/poet.song.100000.json','["玉井之泉汲又新，腐陳收拾已空囷。", "鐵牛城下三年眼，剨見仇池社裏人。"]'),
('1b3f444b-d344-4f89-969a-9a640fbea11a','次韻范機宜感懷','蘇籀','宋','宋诗','song-poetry','','[]','珪組紛紛蟻慕羶，徇人可否冀超遷。',64,'全唐诗/poet.song.100000.json','["珪組紛紛蟻慕羶，徇人可否冀超遷。", "傷哉遠略疲中國，慟矣長星出亙天。", "晉楚春秋書失國，惠昭徒馭竟言旋。", "朝廷得士爲强弱，郭隗來歸不首燕。"]'),
('73585a60-4fd2-4822-9fb9-f527db238110','送王機宜歸襄陽侍下一首','蘇籀','宋','宋诗','song-poetry','','[]','乃公振旅來，河湟新奏捷。',228,'全唐诗/poet.song.100000.json','["乃公振旅來，河湟新奏捷。", "詩禮壯齋壇，荆州初妥帖。", "王郎賦緇衣，旦暮刷燕越。", "從容挽六鈞，邂逅記三篋。", "賞奇必先覩，語怪尤欣愜。", "樵徑曳斑杖，僧窗敷白氎。", "解頤千慮却，爬癢衆賓厭。", "轅門熊虎士，鐵面竦長鬣。", "椎牛赴大釂，割肉揮長鋏。", "酸寒商公邑，會我縈仕牒。", "兒嘷羹不糝，女瘦裙剩摺。", "嫉邪髮衝冠，憂國鬚屢鑷。", "侯家有美載，寒冬相煖熱。", "騕褭带青萍，於菟包璅甲。", "風磴好扶輪，冰溪多病涉。", "淒凉熊耳下，小雪輕塵浥。", "升堂語君公，浚治千樓堞。", "勉勉足兵食，孜孜撫疲苶。", "政成在簡易，可大賢人業。"]'),
('23b30d3f-cd80-44b7-9ec1-c896f571c725','黄筌畫金盆鴿孟蜀屏風者也一首','蘇籀','宋','宋诗','song-poetry','','[]','孟氏觀闕嘗鮮新，虯虯栱桷翔青冥。',272,'全唐诗/poet.song.100000.json','["孟氏觀闕嘗鮮新，虯虯栱桷翔青冥。", "可憐當年百事足，鬼眼未遽窺高明。", "鋪首倉琅百樓聳，寶簾珠带關銀屏。", "風臺露榭敞錦纈，朝朝暮暮吹竽笙。", "鵝溪白繭冰雪清，黄史舐筆研丹青。", "屏間觀者誠粲者，醉頰融煖蘭膏勻。", "金槃滴取宮桃露，點𪑮鉛朱三昧處。", "融怡宿粉暈嬌紅，一片辭枝三月暮。", "妙趣忘言心獨覩，花好更教宮女妬。", "綵翎降趾戲宮廷，啄哺馴和謝籠籞。", "跖石窺盆刷羽儀，天樂鳳簫鶱欲舉。", "智者創物仁者守，何嗟及矣何追咎。", "當時高岸尚微茫，零落萍蓬入誰手。", "華堂粉壁倚叉竿，五十年前亡是叟。", "細說盈虧閱今古，我曹知愛當知惡。", "此間風韻出成都，花上杜鵑啼最苦。", "見之坐右久彌新，咄咄庸工難與語。"]'),
('57f102a1-2ebf-473c-a20d-9ace4c560020','避地詠史一首','蘇籀','宋','宋诗','song-poetry','','[]','量力難貪督亢圖，馮亭致地禍來歟。',64,'全唐诗/poet.song.100000.json','["量力難貪督亢圖，馮亭致地禍來歟。", "摸金公子驅長戟，割地先生醉墮車。", "乘傳有人延劇孟，運籌何術困由余。", "鬼方政賴高宗克，雅信周公無逸書。"]'),
('f5540458-6f98-40e0-910a-af322706d4d5','東坡三絕句  其一','蘇籀','宋','宋诗','song-poetry','','[]','門庭桃柳人人護，焚屋新遭盜跖餘。',32,'全唐诗/poet.song.100000.json','["門庭桃柳人人護，焚屋新遭盜跖餘。", "鄰社蕭條近尤劇，孫孫子子寶公書。"]'),
('c5830cc4-c303-4d89-bec2-c7a271dff838','東坡三絕句  其二','蘇籀','宋','宋诗','song-poetry','','[]','嶺背泉甘陵谷遷，危亭圜顧尚依然。',32,'全唐诗/poet.song.100000.json','["嶺背泉甘陵谷遷，危亭圜顧尚依然。", "春蘭秋菊無終古，地上居人世世賢。"]'),
('ab19b304-f221-4fc1-9413-1b4833e8341d','東坡三絕句  其三','蘇籀','宋','宋诗','song-poetry','','[]','爲文赤壁并黄坂，奇韻平生想像中。',32,'全唐诗/poet.song.100000.json','["爲文赤壁并黄坂，奇韻平生想像中。", "延目練江咨逝水，舉頭碧落看飛鴻。"]'),
('58552a81-a7ca-4cd2-a8e3-11b54b75dcda','過故丞相呂汲公墳剎二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','元祐推諧弼，乾坤豈小康。',48,'全唐诗/poet.song.100000.json','["元祐推諧弼，乾坤豈小康。", "曹參尚清浄，蕭傅性剛方。", "報國無遺恨，興邦舉舊章。", "累年公議白，名與日星光。"]'),
('f558d937-9c58-4c5d-9f23-237d2e5c210f','過故丞相呂汲公墳剎二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','纏綿思舊賦，沈痛八哀篇。',48,'全唐诗/poet.song.100000.json','["纏綿思舊賦，沈痛八哀篇。", "宇宙門人盡，謀謨國史傳。", "高閎人莫及，何代獨無賢。", "欲說源流遠，還應筆似椽。"]'),
('a9a21728-b651-456d-834e-e087646b4e91','南溪太息一首','蘇籀','宋','宋诗','song-poetry','','[]','東坡曾賞南溪雪，他日流芳好事孫。',64,'全唐诗/poet.song.100000.json','["東坡曾賞南溪雪，他日流芳好事孫。", "寒祲稜稜裹崧岱，憂端憤憤塞乾坤。", "赤囊政爾勞邊吏，白羽多應落酒樽。", "太息九原何可作，逸才誰敢賦招魂。"]'),
('22f55799-c944-44bd-8e35-8f62ab4141f4','舟中懷古一首','蘇籀','宋','宋诗','song-poetry','','[]','耀德先王不耀兵，汪洋施澤在生靈。',96,'全唐诗/poet.song.100000.json','["耀德先王不耀兵，汪洋施澤在生靈。", "孰違天戒并民欲，不愛邦家嗜虜庭。", "作俑亂生誠有自，覆車勢合亦難停。", "山河異境傷王導，雲海高翔羨管寧。", "願以絲毫裨漢室，豈無弓矢斃胡星。", "愚翁事業空遺臭，經義分明戰血腥。"]'),
('59e6004b-c950-4dd2-9096-9e9358dfbb11','次韻陳叔易遠別離三首  其一','蘇籀','宋','宋诗','song-poetry','','[]','晝短宵未明，何朝妾覿君。',60,'全唐诗/poet.song.100000.json','["晝短宵未明，何朝妾覿君。", "淚滴九霄雨，愁凝千古雲。", "鳳藏丹霄晚，鴻遵沙磧遠。", "樓迥眼波窮，軸折離魂斷。", "安得葛陂龍，肉骨丹九轉。"]'),
('4e657ac6-c240-4178-ab9e-ab7d6caff857','次韻陳叔易遠別離三首  其二','蘇籀','宋','宋诗','song-poetry','','[]','婦慧弗諳事，謂世無離索。',60,'全唐诗/poet.song.100000.json','["婦慧弗諳事，謂世無離索。", "洋洋舊依蒲，逐逐難翳藿。", "衝風遞弱羽，爛漫何鄉落。", "憂端埒南山，那堪魯酒薄。", "人力末如何，天公良可託。"]'),
('32d123d9-8f32-4847-b159-a1a964ec827b','次韻陳叔易遠別離三首  其三','蘇籀','宋','宋诗','song-poetry','','[]','別情荼無苦，訣語若爲道。',60,'全唐诗/poet.song.100000.json','["別情荼無苦，訣語若爲道。", "日近長安遥，山圍煙浪遶。", "星河通故都，冰雪迫凋槁。", "迴轅尚茫茫，延頸空矯矯。", "卜歸付乾策，此策何人抱。"]'),
('10cdb728-b9da-4e2b-8f56-a634d9972930','憶雍都一首','蘇籀','宋','宋诗','song-poetry','','[]','秦漢西都誰復加，茂陵賦筆大非夸。',112,'全唐诗/poet.song.100000.json','["秦漢西都誰復加，茂陵賦筆大非夸。", "西瞻周道平如砥，南揖秦山翠削瓜。", "電尾風鬉蹄逸健，蝟髯黧面手高叉。", "兵微將乏初無奈，賊破功成近可嘉。", "飄泊荆吳最蕭瑟，厭聞胡漢更紛挐。", "娛賓北榭忘憂酒，侍燕西川沒骨花。", "縱被蒓羹當羊酪，未諳艫舫憶驪騧。"]'),
('e93afdf1-0a22-4589-ae22-f7035bd9a6f9','梔子花一首','蘇籀','宋','宋诗','song-poetry','','[]','鏤裁雪羽元同質，合輯龍沈更一家。',64,'全唐诗/poet.song.100000.json','["鏤裁雪羽元同質，合輯龍沈更一家。", "氣襲禪僧鼻端白，葩敷溪女鬢唇斜。", "牽纏薌色誠虛幻，結習因緣可歎嗟。", "芍藥調和傳漢殿，酴醾脂澤有渾耶。"]'),
('b0307db1-9f08-47b7-9610-c236575da66a','鑒裁一首','蘇籀','宋','宋诗','song-poetry','','[]','喬公評老瞞，謫仙奇郭令。',108,'全唐诗/poet.song.100000.json','["喬公評老瞞，謫仙奇郭令。", "視遠數十載，偉歟真智聖。", "破賊此郎子，勿反吾同姓。", "凡才慁世間，鑒裁惟其證。", "大奸初難辨，明者獨深省。", "若人與斯評，厥重如鐘鼎。", "紛紛女媧土，安在所譏病。", "惟賢則知賢，絲亂行將整。", "掩書坐前軒，老眼安敢瞑。"]'),
('63b1cee7-27ab-4a16-8ae1-8b457c831492','夜飲一首','蘇籀','宋','宋诗','song-poetry','','[]','微生無限死之徒，瓦解絲棼不易圖。',64,'全唐诗/poet.song.100000.json','["微生無限死之徒，瓦解絲棼不易圖。", "一簣區區裨大壞，力行踽踽競長途。", "韜鈐籌策皆摧折，文籍條綱總闊疏。", "誰料孟嘉爲謝傅，笑觀蔣幹待周瑜。"]'),
('6dc5c279-dc89-42d3-955d-ff7c8e51c24a','去年一首','蘇籀','宋','宋诗','song-poetry','','[]','去年胡來清水巖，黄河狹隘冬凌頑。',368,'全唐诗/poet.song.100000.json','["去年胡來清水巖，黄河狹隘冬凌頑。", "戾如飄風速如鬼，犬豕淫虐豺狼貪。", "探馬星奔汗流地，猛士眥裂髮指冠。", "潼雍見兵不及萬，半闕甲胄屯河邊。", "隆寒身體例皸瘃，亦復勉强橫戈鋋。", "它司金繒封雍府，犒軍紙襖如泥錢。", "胡人隔水相笑侮，殺身於爾何值焉。", "同州告急唇齒喻，無兵赴救誠難旃。", "元戎鈐下兵八百，蒼頭廝養爭後先。", "鄜延詔發五千騎，此日收兵姑自全。", "平時保甲例烏合，縣符迫促揮空拳。", "甚哉田夫無鬥志，一夕驚走如窮煙。", "漢將蒼黄結旌遁，虜騎勢合彌山川。", "關中控弦誠萬騎，忠臣義士力可宣。", "書生命運亦蹇劣，我師疲少鄰敵堅。", "却憶長安無事日，談及禍亂爲尤愆。", "飯囊酒罋誇厚福，捧土揭木皆才賢。", "生靈未悉坐何罪，髓腦塗地尤蒼天。", "天公誠能祐戎虜，豈復不解興中原。", "案圖戎索八百郡，我邦日蹙知誰憐。", "吳中據江恃舟檝，惴惴慄慄聊偷安。", "旅人流徙隘城郭，歲事寒薄理勢然。", "去年往矣不須問，安枕而卧祈來年。"]'),
('09648cfc-f178-461d-bc9f-6b90c1c1b31f','維摩詰一首','蘇籀','宋','宋诗','song-poetry','','[]','杯杓何人執其咎，脅脅卑卑十年臭。',96,'全唐诗/poet.song.100000.json','["杯杓何人執其咎，脅脅卑卑十年臭。", "邂逅瓊枝解渴心，京洛豈嘗開豆蔻。", "博山沈水燒春晝，採英擷萼春風手。", "九迴蠆卷紆餘秀，尺六仙圍楚宮瘦。", "癡狂無限熱肝脾，盛詫櫻桃比垂柳。", "槁木寒灰不二門，禪功道力何妍陋。"]'),
('4fa747ec-c16a-4d13-a5e0-aa028a4731ad','偶成二絕  其一','蘇籀','宋','宋诗','song-poetry','','[]','古風未必今人操，老氣休祈大吏歡。',32,'全唐诗/poet.song.100000.json','["古風未必今人操，老氣休祈大吏歡。", "捫腹定無奇士術，蕭然且作野人看。"]'),
('39e68fa4-c249-49fb-9f05-361df02e0fc1','偶成二絕  其二','蘇籀','宋','宋诗','song-poetry','','[]','延陵乃有能詩鑒，子路猶爲少讀書。',32,'全唐诗/poet.song.100000.json','["延陵乃有能詩鑒，子路猶爲少讀書。", "習氣未忘番簡冊，白頭稽古不應愚。"]'),
('9d34fcfa-b02e-4650-a253-0856c5953f6f','梅雨一首','蘇籀','宋','宋诗','song-poetry','','[]','柑花銷殞荔殊小，海上雨雲氛氣昏。',64,'全唐诗/poet.song.100000.json','["柑花銷殞荔殊小，海上雨雲氛氣昏。", "感慨干戈異鄉客，愁思骨肉與誰論。", "白魚紫笋清庖隸，盧橘楊梅積市門。", "作吏天涯何所得，一春黄卷伴芳樽。"]'),
('34e1d353-151c-43dd-a5a3-41f31de9fdac','張孺人九十六歲簽判求眉壽堂詩二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','鵲巢流慶嗣如參，鶴髮人間仰達尊。',64,'全唐诗/poet.song.100000.json','["鵲巢流慶嗣如參，鶴髮人間仰達尊。", "經眼盡知三世事，含飴已看幾重孫。", "承顔捧詔疏封邑，扇枕溫床不倚門。", "取數西方無量佛，滿堂氛馥貝多翻。"]'),
('9b477618-070b-45e0-a226-677c5e604b00','張孺人九十六歲簽判求眉壽堂詩二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','蕭同叔子無令笑，緜上之推乃棄官。',64,'全唐诗/poet.song.100000.json','["蕭同叔子無令笑，緜上之推乃棄官。", "咸羨此堂稱聖善，累從治劇勸平反。", "晨昏不怠諄諄誨，僮使皆沾洩洩歡。", "紫詔又當稱大國，安輿五馬疊榮觀。"]'),
('f6b9237d-93ed-4685-a936-2e707f05db2b','陋居一首','蘇籀','宋','宋诗','song-poetry','','[]','平生甕牖蔀茆菁，江左那無寸土寧。',64,'全唐诗/poet.song.100000.json','["平生甕牖蔀茆菁，江左那無寸土寧。", "遊宦飄然紆幕燕，陋居粗有讀書螢。", "浮生佛脚須當抱，亂世儒衣便欲停。", "天定災祥在淫善，北溟安得勝南溟。"]'),
('5b31d400-0273-4a0f-8bd4-743fa9e73bd7','羣盜一首','蘇籀','宋','宋诗','song-poetry','','[]','貪得不知義，流風紊四維。',216,'全唐诗/poet.song.100000.json','["貪得不知義，流風紊四維。", "珪珇實盲昏，黥髠亦覬窺。", "諒非跖蹻才，競揭椎埋旗。", "巨猾肆滔天，小醜爭攘欺。", "立國計安出，顧無以家爲。", "三州破竹勢，吏卒傷撓隳。", "越人竟何能，非復尉佗時。", "壺簞迎王旅，克捷劍之湄。", "閩府幸宴然，一毫未嘗虧。", "噫吾有以待，致爾由他歧。", "殘蘗失追襲，諸將咸思歸。", "勉哉方伯職，力拯鄰邦危。", "漳濱拏未解，蜂蝎生武夷。", "姑息倒囷藏，諄複行文移。", "近事苟目前，遠憂那敢知。", "天運未太平，佛力亦其微。", "武夫勿告勞，儒冠須出奇。", "知人與安民，此責誠塞之。"]'),
('f6e3a847-c829-4f14-9141-ba8639a64f83','秋分一首','蘇籀','宋','宋诗','song-poetry','','[]','礎濕嵐昏近海多，劍霜清刮手親磨。',64,'全唐诗/poet.song.100000.json','["礎濕嵐昏近海多，劍霜清刮手親磨。", "輪囷馬棧非難整，索漠牛衣且勿呵。", "好住延陵皋澤去，强同溱洧濟人過。", "坐令幽谷遷喬木，盛論中原喻尉佗。"]'),
('87568fa5-f5a4-4dfa-aea0-b23166af1d03','范箕叟啜茗一首','蘇籀','宋','宋诗','song-poetry','','[]','無窮賞物胡名達，希世纖柔不計金。',64,'全唐诗/poet.song.100000.json','["無窮賞物胡名達，希世纖柔不計金。", "愛雪并花也延命，擲絲與竹却知音。", "情閒未絕毫釐念，文艷何妨鐵石心。", "雅倩樊蠻誦長恨，飲茶亦可擬芳斟。"]'),
('8108046f-55d2-43b9-8d33-09c450cae8f0','程帥父朝議年八十餘諸人作詩褒詠次韻一首','蘇籀','宋','宋诗','song-poetry','','[]','郎潛華首寤鑾輿，連帥元戎十乘車。',64,'全唐诗/poet.song.100000.json','["郎潛華首寤鑾輿，連帥元戎十乘車。", "吏道薛公何必問，史才倚相妙稱書。", "雍容鳩杖朝裾偉，談笑蒲鞭法網疏。", "萬石恬侯定非晚，閩人安枕夢維魚。"]'),
('66b974b6-5955-44d3-b133-60ee7fd529ad','凍雨一首','蘇籀','宋','宋诗','song-poetry','','[]','淋淋凍雨滴春朝，正月寒威倍凓憀。',64,'全唐诗/poet.song.100000.json','["淋淋凍雨滴春朝，正月寒威倍凓憀。", "汩淖不甘勞皁隸，執輿豈必勝芻蕘。", "素餐致寇思長策，失業疲氓想易招。", "馴伏强豪蘇餒乏，濟時籌略直須超。"]'),
('59bdc140-43af-4516-903a-e558c2fa34f4','贈蘇文瓘','蘇籀','宋','宋诗','song-poetry','','[]','推明能隼骨專車，按地談天河洛圖。',96,'全唐诗/poet.song.100000.json','["推明能隼骨專車，按地談天河洛圖。", "漢魏晉唐皆貫澈，典墳今昔不荒蕪。", "君家庭戶聞風旨，吾事分毫等博屠。", "豈待曲終思雅頌，直緣背癢遇麻姑。", "預求補益三年艾，深識妖邪九尾狐。", "博物偉然窺子產，濟時豈必愧夷吾。"]'),
('e75631b3-eca4-428c-9949-1f23df5da403','酴醾一首','蘇籀','宋','宋诗','song-poetry','','[]','絆挽風光數丈枝，曳松拖雪不勝宜。',64,'全唐诗/poet.song.100000.json','["絆挽風光數丈枝，曳松拖雪不勝宜。", "濃鉛輕素誰調練，鬰蕙滋蘭無等夷。", "婆律著人酲自解，昆吾雕玉賞尤奇。", "攀條嚊蕊思京洛，末利晶熒自一時。"]'),
('117f0a17-0960-43e4-8cf2-5f33e67df1c1','次韻鄧志宏三月辛卯大雨雹','蘇籀','宋','宋诗','song-poetry','','[]','剝圭碎璧崑山頹，天容黯慘凝不開。',96,'全唐诗/poet.song.100000.json','["剝圭碎璧崑山頹，天容黯慘凝不開。", "隋和抵鵲虎兕吼，陽愆陰伏推從來。", "雀鼠懷安怖入壁，聲侔海翻星隕石。", "疾雷破山萬壑沸，急雨懸河平地尺。", "嘉生春淺纔纖毫，季子禦雹勤嗟嘷。", "沖沖鑿冰窮谷裏，申豐此說殊未高。"]'),
('61852dfc-c04e-45bd-9563-4dabb4749e22','次梅齋嚴韻','蘇籀','宋','宋诗','song-poetry','','[]','振條裂石寒颼颼，霰集黄昏天爲愁。',64,'全唐诗/poet.song.100000.json','["振條裂石寒颼颼，霰集黄昏天爲愁。", "若蘭政恐遠庭戶，健步斸本移巖幽。", "斷魂能返神可雪，照夜薰天欲奔月。", "妖韶敷艷滿東風，膚清骨秀無相絕。"]'),
('5afcb05e-1e91-4d5b-b02d-03742d0aa9ba','跋思古齋詩卷','蘇籀','宋','宋诗','song-poetry','','[]','娉然林下趣，仙袂擁書籤。',48,'全唐诗/poet.song.100000.json','["娉然林下趣，仙袂擁書籤。", "心迹清無滓，情聲慧且謙。", "瑣窗龜背戲，彤管兔毫尖。", "十願獨非僭，陶云那得添。"]'),
('896cc840-dd3a-41d7-affe-d2c1c818bef7','僧庵崖上榴花','蘇籀','宋','宋诗','song-poetry','','[]','蒼崖有紅榴，照眼風櫺迥。',108,'全唐诗/poet.song.100000.json','["蒼崖有紅榴，照眼風櫺迥。", "鶴頂磨丹明，猩唇染羅竟。", "天然同心蒂，物理有殊稟。", "青鳥蹙絳巾，奇膠綴琴軫。", "子雲畔牢愁，無偕溱洧贈。", "思致玉瓏鬆，皎兮麗宮井。", "江嶠瑣蠻煙，空煩洛生詠。", "山僧遞形語，呵乃枯禪病。", "喁諷獨移時，鶻沒天宇浄。"]'),
('07d193b6-dd9d-41e9-b1b1-e1fc4ea4f032','遊鼓山一首','蘇籀','宋','宋诗','song-poetry','','[]','呼船起柁乘潮平，掠窗飄箔疏雨傾。',256,'全唐诗/poet.song.100000.json','["呼船起柁乘潮平，掠窗飄箔疏雨傾。", "漱石枕流東道主，櫛風沐雨吾曹行。", "百尋懸瀑瀉紳珮，兩邊喬木翔枅甍。", "乞漿滿甌牛乳粥，縱酒下筯駝蹄羹。", "躋摩頂踵歷蹬術，牽挽葛藟披荆榛。", "荒浪攙差復奄靄，巀嶭屭贔仍稜層。", "嘷煙嘯雨猨鶴宅，絕山航海樵漁能。", "草衣穴處避世士，木食澗飲安禪僧。", "芝房雲閣無盡藏，月屏風幌長明燈。", "笑看闤闠一蟻垤，揮斥氛祲投蠻藤。", "經行石竇解縢屩，飲灌匏杓談淄澠。", "莫嗔踏碎蒼苔色，莫嫌汲濁陰井清。", "膏肓泉石有鑒裁，騰踔巖崿試股肱。", "要識石鼓真面目，立置枕几非繪繒。", "風吹楊葉此山下，欲問故老知誰應。", "市朝一夢爭奪際，山海蕭散堪伏膺。"]'),
('44f1d891-2137-494f-b069-f0697dfa3d98','和洪玉甫祕監荔枝三首  其一','蘇籀','宋','宋诗','song-poetry','','[]','林杪摘星隕，江干疑燒然。',48,'全唐诗/poet.song.100000.json','["林杪摘星隕，江干疑燒然。", "香包浣花錦，冰質藐姑仙。", "巨擘紛璀璨，丁香吐妙妍。", "唐亡傾國笑，何物免罹愆。"]'),
('b4557ae6-468e-4e25-8ad9-5750ae43637b','和洪玉甫祕監荔枝三首  其二','蘇籀','宋','宋诗','song-poetry','','[]','閩中譜殊盛，唐相賦初工。',48,'全唐诗/poet.song.100000.json','["閩中譜殊盛，唐相賦初工。", "萬點凝霞赤，三危滴露叢。", "驅蘆抵烏鵲，投李飫兒童。", "子美吟西蜀，櫻桃先後紅。"]'),
('9f2adb48-c2f0-4fe3-ba2f-b3fc5a1bef87','和洪玉甫祕監荔枝三首  其三','蘇籀','宋','宋诗','song-poetry','','[]','瘴鄉駢瑣質，善地最蒲閩。',48,'全唐诗/poet.song.100000.json','["瘴鄉駢瑣質，善地最蒲閩。", "冠絕林間品，難爲坐上賓。", "蟠桃壽天帝，萍實薦居宸。", "無逸爲龜策，何煩萬馬塵。"]'),
('7eb3956d-b034-459d-bd6b-c469f288d2e0','次韻待制王公出示李公丞相鼓山唱和之什不揆蕪累奉和一首','蘇籀','宋','宋诗','song-poetry','','[]','顒昂經世量，超軼塵秕浄。',240,'全唐诗/poet.song.100000.json','["顒昂經世量，超軼塵秕浄。", "猗歟尋山屐，泛矣隨波艇。", "顔筆振巖崖，戎眼清水鏡。", "平籋青雲步，何如蒼蘚蹬。", "忘懷挈伯雅，寓意彈韻磬。", "物外赤松期，域中兜率夐。", "江溟噓吸際，霞祲廓虧映。", "龍象千礎攢，簦屩十方并。", "彌天各縱辯，酌海終弗罄。", "公侯誠得一，品物將大定。", "瞿曇舊摽蕝，嵌洞尤奇勝。", "雷唱澗流迴，石刻惟人競。", "半山琅玕響，一井玻瓈瑩。", "松風瀑水合，時鳥慁人聽。", "慷慨羊鄒遊，雍容裴白並。", "溪谷有佳色，題品益光幸。", "渭濱行將獵，詔促預參乘。", "王公居客右，羊舌偕趙孟。", "小人繆好事，大冊挾晨暝。", "擊節穆清風，續騷聊比興。"]'),
('361d6713-38fc-4f3b-9599-d15a927aacde','次韻洪令穀瑞平遠臺','蘇籀','宋','宋诗','song-poetry','','[]','能賦憑高所得多，海雲巖崿若君何。',64,'全唐诗/poet.song.100000.json','["能賦憑高所得多，海雲巖崿若君何。", "兼通西竺瞿曇意，欲和南風虞舜歌。", "怪石甘泉作檀施，長廊古殿蔭多羅。", "相期正始微言緒，詩眼休嫌俗吏過。"]'),
('0352733a-d43c-4a39-89fa-d2d9cb5f2b1f','洪子再示論詩之意答一首','蘇籀','宋','宋诗','song-poetry','','[]','文章三昧亦無多，甄品難甘狀杜何。',64,'全唐诗/poet.song.100000.json','["文章三昧亦無多，甄品難甘狀杜何。", "撚脫髭鬚徒自哂，可憐彈鋏爲誰歌。", "腐陳點化爲珍玩，翡翠鷦鷯入罻羅。", "擬續蘭臺快哉賦，後來作者豈容過。"]'),
('3815ef46-bcf8-4e16-917c-995b6bd8052c','王叔明示長句訝烏澗人不出楚則失矣齊亦未爲得也次韻一笑','蘇籀','宋','宋诗','song-poetry','','[]','忍對三峯閟兩山，澹蛾三五韻幽閒。',112,'全唐诗/poet.song.100000.json','["忍對三峯閟兩山，澹蛾三五韻幽閒。", "王郎賓席自水冷，君須舉玦人捨環。", "烏澗門階未嘗峻，瑞峯重深一百間。", "列屋羅帷隔風日，九迴沈水紆髻鬟。", "使君素負凌霄志，臞儒何以換酡顔。", "龍香小袖酬綠醑，不管紫雲私有語。", "美哉江色釀山光，青瑣勤開看煙雨。"]'),
('018febc9-6cab-45f4-84d0-b46b99940eec','次韻王丈豐父待制荔枝二十韻','蘇籀','宋','宋诗','song-poetry','','[]','葉實根株尚老蒼，龍鱗皋比貴先嘗。',320,'全唐诗/poet.song.100000.json','["葉實根株尚老蒼，龍鱗皋比貴先嘗。", "千林斷送詩騷酒，三絕無逾色味薌。", "爛醞恢台養風骨，涵滋沆瀣結天漿。", "怕寒僻處深於越，贄貢無階遇有唐。", "葱鬰梧楸共庭戶，風流芝玉秀齋房。", "剖緘絳錦紛狼藉，瑩手摩尼可比方。", "頳卵鱗皴雄俎豆，雙珠同蒂媚釵梁。", "摘憂林薄明朝竭，繆論蕉盧幾許黄。", "口腹定非孤寓客，甘腴盡道勝吾鄉。", "峽山高詠詩昌白，韶石英風賦予張。", "芍藥亦能煩驛置，蒲萄豈必擅西凉。", "彈圜金橘差堅久，瑛赤含桃詎可雙。", "逆目提籠過闤闠，解頤夢渴吸湖江。", "仲宣鴻筆絲綸手，摩詰清才黼藻光。", "妙絕揀枝牆欲動，纖攕稱擘侍于傍。", "翰林紀績延真賞，縣長繩愆且彌忘。", "賜燕行看與懷核，分題今日記升堂。", "傷時有似少陵杜，上疏豈惟臨武羌。", "深忌河豚恕瑶柱，沈思橄欖過糖霜。", "詞情鑒裁俱超卓，促召龍墀獻皂囊。"]'),
('4f3c07ac-cca8-4cee-9ef1-5bf1a4fa6c35','木樨花一首','蘇籀','宋','宋诗','song-poetry','','[]','何處聞國薌，珍木秀巖谷。',108,'全唐诗/poet.song.100000.json','["何處聞國薌，珍木秀巖谷。", "高標蕙蘭枝，妙輯沈麝酷。", "葉葉秋聲中，霏霏早英蔌。", "介特有如松，繁華豈慚菊。", "勃蔚襲軒墀，薰沾滿衣服。", "情人擢纖指，拾蕊動盈掬。", "蘼蕪見離騷，苓藿入譜錄。", "卉裳未可更，鮑肆或爭逐。", "亂插琉璃瓶，於斯殊不俗。"]'),
('9149b42f-7a2e-48ed-b713-2334eb4f9882','寒夜','蘇籀','宋','宋诗','song-poetry','','[]','鐵檠知漏永，熠燿照蚍蜉。',48,'全唐诗/poet.song.100000.json','["鐵檠知漏永，熠燿照蚍蜉。", "三策遺當世，一封陳厥謨。", "甫田須疾耒，巨浸想乘桴。", "應猝誠乖用，何名道不誣。"]'),
('c42d1724-acd6-430c-a36d-89f380b573ba','觀兵','蘇籀','宋','宋诗','song-poetry','','[]','錯捐金带子輿臺，李典張遼安在哉。',64,'全唐诗/poet.song.100000.json','["錯捐金带子輿臺，李典張遼安在哉。", "濟溺我應知大略，摧鋒人自得高才。", "伍符勤選加搜練，戎閫徐圖妙鑒裁。", "引領山西十萬騎，中原失御實堪哀。"]'),
('3c9487cd-0ec7-4e31-b52c-a59325957016','次韻洪穀瑞模臨皋亭四畫','蘇籀','宋','宋诗','song-poetry','','[]','退筆殘煤作冢池，庶幾極力更前追。',64,'全唐诗/poet.song.100000.json','["退筆殘煤作冢池，庶幾極力更前追。", "尋源巴峽濤瀧派，得骨柯山鐵樹枝。", "京口風雲隨叱咤，渭川霆電掃端欹。", "刻舟事往何嗟及，拙目高心付黠癡。"]'),
('a7fad082-6dac-4a4f-8176-2d2f1c0037d0','次韻洪令三月晦見寄','蘇籀','宋','宋诗','song-poetry','','[]','摻袂東君屬此觴，朱明履運返何鄉。',64,'全唐诗/poet.song.100000.json','["摻袂東君屬此觴，朱明履運返何鄉。", "結成碩果鸝鶊語，吹盡落花桑柘光。", "梅雨聞君醉山閣，麥風招我步濠梁。", "惜春歲月那相貸，腸斷連山草樹長。"]'),
('b8151646-93b5-4217-aafb-5a7b73c5f568','東山一首','蘇籀','宋','宋诗','song-poetry','','[]','骯髒田官委吏偕，山於吾屬倍青哉。',96,'全唐诗/poet.song.100000.json','["骯髒田官委吏偕，山於吾屬倍青哉。", "星言輿轎蒙蘢裏，山半振衣囂鬨埃。", "針水布畦春澤匝，吟風夾路歲寒來。", "架巖刳木泉悲響，鏁洞白雲花爛開。", "灰冷虛堂敷白氎，爨清一飯脯青苔。", "欲求出世三空義，一咄疏狂道眼裁。"]'),
('40a93558-742f-4d07-9419-7b71702e1c0d','程帥新作止戈堂索詩謹賦三首  其一','蘇籀','宋','宋诗','song-poetry','','[]','建州氓隸敢滔天，亂領妖腰伏乃愆。',64,'全唐诗/poet.song.100000.json','["建州氓隸敢滔天，亂領妖腰伏乃愆。", "獻馘牙門森㦸纛，解嚴後廡戢戈鋋。", "勞歸宣潤奇材客，勅賜番禺饋米船。", "勸課蠶桑陳俎豆，頑愚悛悟悔從前。"]'),
('0185afc8-88fd-476c-a578-4cc5f3a99361','程帥新作止戈堂索詩謹賦三首  其二','蘇籀','宋','宋诗','song-poetry','','[]','都士萬家吁盜守，日行三百檄書馳。',64,'全唐诗/poet.song.100000.json','["都士萬家吁盜守，日行三百檄書馳。", "蠻刀短楯相繩擿，章甫毛錐亦可支。", "三道來攻吾設儆，千艘利涉爾焉知。", "三州十萬歸農畝，櫜戢無窮歌頌詩。"]'),
('311f462c-90b5-4168-af10-e62fc8886612','程帥新作止戈堂索詩謹賦三首  其三','蘇籀','宋','宋诗','song-poetry','','[]','楚王禁暴慚京觀，漢世殘民闢徼邊。',64,'全唐诗/poet.song.100000.json','["楚王禁暴慚京觀，漢世殘民闢徼邊。", "伐叛從來非得已，修文自古屬高賢。", "禽魚草木無垠惠，鄉校康莊議論妍。", "盡悴使君朝聽美，不然海國豈安全。"]'),
('4c7921e0-0bae-4197-bec3-5e575c4cd26f','連雨偶成二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','檻櫺生菌地生衣，釜甑有魚盤有薇。',64,'全唐诗/poet.song.100000.json','["檻櫺生菌地生衣，釜甑有魚盤有薇。", "適俗簪裾取縈挽，累人口腹得嶇崎。", "行看海霧江雲盡，却放風臺月觀輝。", "撥置圖書絕欣慨，一巾一鉢款山扉。"]'),
('fc0d3023-62fb-4f9d-9b2c-2f9a0ac41e53','連雨偶成二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','愚翁夸甫骨應寒，宇宙因誰危與安。',64,'全唐诗/poet.song.100000.json','["愚翁夸甫骨應寒，宇宙因誰危與安。", "治道灼知斯鞅妄，中興竊擬導安難。", "文章一伎真何益，得失他年極易觀。", "私喜崔駰薄班固，繆賢朱博毀師丹。"]'),
('ebc6f0ae-0ff6-407a-b3d4-46311cac865b','雕木工','蘇籀','宋','宋诗','song-poetry','','[]','君不見嶧山高崖斯相蹟，棗木刻模真並失。',134,'全唐诗/poet.song.100000.json','["君不見嶧山高崖斯相蹟，棗木刻模真並失。", "又不見深之袖手安國碑，帝悟百牛掀倒石。", "秦唐二子皆有聲，何必今人不逾昔。", "拙工礪器雕不已，印版傳書差可貴。", "方趺圖首效碑影，穿鑿膠黏總紕纇。", "鳳山之水生瓊玖，斲磨光澤堅而黝。", "文章光艷照千古，玉牒萬金吁可剖。", "刊劖四海多名手，何必區區鎸腐朽。"]'),
('fa3ac386-fb70-41ab-82c1-0d2e4ad8c52c','送朱喬年被舉薦監石井鎮','蘇籀','宋','宋诗','song-poetry','','[]','石井鎮初騰一鶚，管城子健斡千鈞。',64,'全唐诗/poet.song.100000.json','["石井鎮初騰一鶚，管城子健斡千鈞。", "已然自足雄吾黨，其進祇應軼古人。", "衣被卉裳殊欲慣，解捐犢佩猾商馴。", "萬鍾他日扶危手，五斗怡怡爲奉親。"]'),
('4e8a28e4-92be-424e-a193-41148510ebcc','奉和秘監洪丈迎諫議徐公建除之什并次元韻','蘇籀','宋','宋诗','song-poetry','','[]','建極翊皇輿，蓬廬懷致主。',144,'全唐诗/poet.song.100000.json','["建極翊皇輿，蓬廬懷致主。", "除書肆時夏，提綱衆目舉。", "滿朝想風采，愛及巾墊雨。", "平平戒自守，落落進攻取。", "定傾繄其人，防秋今尚暑。", "執輿岣嶁嶺，櫛風閩海浦。", "破的出新詩，江山繚樽俎。", "危機見未萌，剛鯁殊不吐。", "成憲萬方瞻，作者七人數。", "收召無遺賢，商山非爲呂。", "開悟堯舜心，亢宗誠刻苦。", "閉門踰厥垣，孰與驅馳許。"]'),
('8378fc1f-5559-43db-bba0-3f0fccb6968d','古勸學行','蘇籀','宋','宋诗','song-poetry','','[]','昔歲原伯魯，前日棘子成。',220,'全唐诗/poet.song.100000.json','["昔歲原伯魯，前日棘子成。", "所謂悉常事，野哉亦苟生。", "豈知負孔聖，義理如何行。", "善飯斯爲福，食肉其堪盲。", "六籍漫不省，千載誰辨明。", "秦時害文維法吏，趙高趦趄誑當世。", "小夫無知信可恥，大官不學粗且鄙。", "深思博問如其智，精義入神以致治。", "從來廊廟須奇策，乃用弓戈爲快意。", "孔明澤中梁甫吟，著表行師肯倩人。", "呂蒙孜孜窺往事，知新益解圖當今。", "橫槊胡爲忘試藝，不文不武伊何遵。", "嗟予貧賤年將老，學古憂時滿懷抱。", "斯民陷溺豈無說，天下復平要有道。", "子思立教自明誠，伯業華巔愈貪討。"]'),
('c5e7c9cd-d1c4-4e01-aebd-bb9b1f9fe41c','夏旱一首','蘇籀','宋','宋诗','song-poetry','','[]','陽厄會百六，驕亢慘如燬。',240,'全唐诗/poet.song.100000.json','["陽厄會百六，驕亢慘如燬。", "素秋垂二七，十旬赤千里。", "土田靈龜坼，水車渴烏柅。", "歷時書不雨，槁矣吁田穉。", "雖然海有潮，何堪井無水。", "塞鼻炎煙鬰，吹面江風靡。", "憬俗雪不降，炎洲冰詎履。", "虐魃豈勝誅，巫尪窘臞悴。", "雩禜按典彝，祝史殊跛倚。", "資舟舟已盡，振廩廩餘幾。", "枵然望雲漢，邈乎嗥屏翳。", "戎虜未入朝，耕戰誠勞勩。", "收募聯什伍，倍蓰給餉饋。", "伊人虧顆粒，主者遭忿詈。", "覆載疑亭育，蘧蒢視生類。", "作爲三日霖，霶沱萬事理。", "焦枯已不救，根蘗或可冀。", "疲民億萬口，生生荷天帝。", "侏儒一囊足，孤寡千箱賜。", "三軍盡鳧藻，邦邑豈小乂。"]'),
('78d80a0c-3d62-47ac-9363-9c5f19acb2fb','張子安求無外道人挽詞  其一','蘇籀','宋','宋诗','song-poetry','','[]','奉匜誰過仲卿賢，獨泣牛衣枕淚眠。',64,'全唐诗/poet.song.100000.json','["奉匜誰過仲卿賢，獨泣牛衣枕淚眠。", "墨誤唾花衫未故，詩題摘葉柹猶鮮。", "悽凉玉雪卿卿意，惆悵房櫳步步蓮。", "撫念琴書舊同賞，爵名重刻更巍然。"]'),
('2d23bf89-73c5-4991-9dc4-4431a627c409','張子安求無外道人挽詞  其二','蘇籀','宋','宋诗','song-poetry','','[]','芙蓉城闕宜通籍，姑射山頭素卜鄰。',64,'全唐诗/poet.song.100000.json','["芙蓉城闕宜通籍，姑射山頭素卜鄰。", "舉世難工斷腸句，何時再得捧心人。", "芝蘭奕代傳遺懿，玉樹千年鎖暗塵。", "珍重清風入襟袖，每篇佳處想精神。"]'),
('74577eec-a624-4e39-8df1-0e951d11336d','閩中秩滿一首','蘇籀','宋','宋诗','song-poetry','','[]','蠻府同僚問字奇，老成衣鉢舊箴規。',64,'全唐诗/poet.song.100000.json','["蠻府同僚問字奇，老成衣鉢舊箴規。", "颶風不訝飛黄雀，汙瀆猶將貸病鴟。", "前日幕謀非妙伎，今時民瘼愧良醫。", "徑從南浦携書笈，吉貝裳衣皂帽帷。"]'),
('e718ec5d-ed43-4b60-930f-235be6595e29','次韻洪穀瑞見和','蘇籀','宋','宋诗','song-poetry','','[]','此間空洞最無奇，整整從繩僅滿規。',64,'全唐诗/poet.song.100000.json','["此間空洞最無奇，整整從繩僅滿規。", "併譜沈薌及苓藿，公言羊質錄鴞鴟。", "禿巾鮑肆穿芒屩，爭席畦丁與馬醫。", "海浸冰銷元凱癖，玉杯繁露董生帷。"]'),
('e69000da-037c-4a27-8b5f-b29ac78578e6','招范子儀登昇山次范韻','蘇籀','宋','宋诗','song-poetry','','[]','束带殊憎市聲沸，幅巾聊復隱居尋。',64,'全唐诗/poet.song.100000.json','["束带殊憎市聲沸，幅巾聊復隱居尋。", "凌虛馬鞍林巒表，滴翠駝裘澗谷深。", "箇裏膏肓空自許，何期煙雨撓重臨。", "長瓶大白開狂喙，絕海驅山歎未禁。"]'),
('a48cb0bc-811d-4767-a1ff-912a21a2c2e4','送范比部持節廣東','蘇籀','宋','宋诗','song-poetry','','[]','羊城使者神仙中，苒苒叱馭凌雲蹤。',192,'全唐诗/poet.song.100000.json','["羊城使者神仙中，苒苒叱馭凌雲蹤。", "繡袂吾徒强摻執，解手一舉南飛鴻。", "君侯烜赫標肉譜，文正烈祖忠宣父。", "典刑付託呼所鍾，經國風規儼如故。", "傷時嗟我思古人，遺直茂勳君世嗣。", "春秋主盟由范氏，不戰屈人從范智。", "備嘗世故無難易，出入淹迴俱掌計。", "世推汲偃似長孺，共懷下惠賢展喜。", "鳥言夷面吾氓耳，豈弟公清渠自理。", "聲華本實警蠻貊，鋒穎天然加峭利。", "轉糧遵海爰究度，併按三河應不避。", "追車少日便還朝，首出儒林冠循吏。"]'),
('6f94e8c1-1627-43b5-a666-36d77b8be916','與可墨竹二十韻','蘇籀','宋','宋诗','song-poetry','','[]','天工奇水墨，晴景照檀欒。',240,'全唐诗/poet.song.100000.json','["天工奇水墨，晴景照檀欒。", "影動嵇阮愛，筍穿淇渭干。", "禪翁三昧力，老手一揮間。", "意匠先鶻落，心造忘筆端。", "芥胸極蓊蔚，振袖疾飛翰。", "道妙進乎伎，自得即之安。", "剛耿在眉睫，歲寒出脾肝。", "動色娛傾耳，可聽非惟觀。", "颯遝掀翠羽，交戛敲琅玕。", "雷驚碧霄聳，風倒懸崖攀。", "雨霜斜重勢，龍鳳飛鳴竿。", "勁挺加掩冉，英奇閱雕殘。", "緹繒釘牆仞，秀絕襲衣冠。", "備悉湖州派，恨不彭城看。", "不可無此君，寧可弗至膰。", "買林自虧蔽，折檻縈叢攢。", "房攏侍便嬖，園苑隔扃關。", "要見一室中，幸容四壁寬。", "此畫會通靈，請公牢鐍緘。", "王侯儻奉借，定鏁空厨還。"]'),
('b1f76cc4-9af8-4065-a578-2c4807667239','次韻范子儀怡山飯訖訪王仙君舊迹一首','蘇籀','宋','宋诗','song-poetry','','[]','雲衲撞鐘集，鶴衣輿轎來。',48,'全唐诗/poet.song.100000.json','["雲衲撞鐘集，鶴衣輿轎來。", "暫沽彭澤酒，豈礙太常齋。", "道釋縱橫說，門庭南北開。", "皂叢天籟響，棋罷想龜迴。"]'),
('cda0c9d9-cc12-4c1d-8840-ad5e83e22ae4','次韻范子儀東山之什','蘇籀','宋','宋诗','song-poetry','','[]','東隅嶺嶠紆層出，濃翠春粧日夕佳。',64,'全唐诗/poet.song.100000.json','["東隅嶺嶠紆層出，濃翠春粧日夕佳。", "僧老林丘黨猨鹿，地靈山澤產龍蛇。", "井泉移得天台脈，洞壑時開閬苑花。", "可笑籃輿趁斜日，白雲迴首梵王家。"]'),
('d1cac450-f6d5-4d32-bbd6-9c612af99a99','次韻伯業賦詩相迎喜予解秩一首','蘇籀','宋','宋诗','song-poetry','','[]','長衾大枕寢將安，猘子成擒路不難。',64,'全唐诗/poet.song.100000.json','["長衾大枕寢將安，猘子成擒路不難。", "充類未應於義盡，去官無責本恭寬。", "兵戈銷弭非吾力，冠劍疏慵强汝彈。", "新歲舉觴嘉善禱，掃清崧潁並憑鞍。"]'),
('6b49a23e-254e-47c2-b3ff-4e83469405c3','次韻洪六丈舍人蘇黄馬券一首','蘇籀','宋','宋诗','song-poetry','','[]','長鳴天廐起毛龍，萬馬皆喑一洗中。',64,'全唐诗/poet.song.100000.json','["長鳴天廐起毛龍，萬馬皆喑一洗中。", "立仗式儀稽馬叟，解驂牽賜有裴公。", "累年兵火蘇黄蹟，舊券山河带礪同。", "攬筆詩翁擬騷雅，雄然臺閣快哉風。"]'),
('4346d607-c5ee-494a-9708-485a1f4e6d40','汲東坡所浚井一首','蘇籀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','帥貳英英駐節旄，繼唐流澤便滔滔。',64,'全唐诗/poet.song.100000.json','["帥貳英英駐節旄，繼唐流澤便滔滔。", "源深東絕三橋市，漲縮西湖二寸篙。", "溝駛甃堅無旱潦，瓶翻筒漏飲豚羔。", "私家誦佛千畦稻，官帑收功萬斛醪。"]'),
('36295134-8b93-4e14-8e62-89c145c8c697','旅舍中秋一首','蘇籀','宋','宋诗','song-poetry','','[]','蘆笙茆茹野人編，竹几藜床已侈然。',64,'全唐诗/poet.song.100000.json','["蘆笙茆茹野人編，竹几藜床已侈然。", "月滿光臨感珠夜，風高冷過曝衣天。", "酒浮爐肆人呼友，雀啅梅花鷺睨蓮。", "靜士兀然方止酒，舊琴不計有無絃。"]'),
('aaddc1f7-7966-42d6-b041-14a0ea660f65','小僧乞其師靜悟塔銘一首','蘇籀','宋','宋诗','song-poetry','','[]','劫火吳宮盡，耆年亦已殂。',48,'全唐诗/poet.song.100000.json','["劫火吳宮盡，耆年亦已殂。", "勤拳依佛敕，精苦是僧摸。", "願力歸兜率，宗風化給孤。", "禪心不淪謝，楚些漫招呼。"]'),
('1c2b799d-be89-49ae-af79-5e89015dc6a9','將軍一首','蘇籀','宋','宋诗','song-poetry','','[]','將軍義勇名，蜂蟻嘗旅拒。',192,'全唐诗/poet.song.100000.json','["將軍義勇名，蜂蟻嘗旅拒。", "俯邇建赤油，超摇揮白羽。", "不辭援鼓桴，豈以遺君父。", "匈奴恨未滅，致官逾噲伍。", "麾下例千金，赫然士豫附。", "家庭樹曲旃，天街騰露布。", "平昌平恩侯，議論寧肯忤。", "萬金十千戶，募將斬亡虜。", "列屋鏁名倡，連車載清酤。", "用錢取水衡，卜宅凌武庫。", "山岳勢能移，震電赫憑怒。", "畫地成江河，鼻息吹雲霧。", "私鬬患不怯，公戰則先務。", "可憐金玉帛，殊勝煙埃土。", "嗟彼紳佩儔，索漠何太窶。", "試移名將傳，予汝頻晤語。"]'),
('03a0e0cd-83e4-48ed-9837-8bbcf00b2076','夜凉','蘇籀','宋','宋诗','song-poetry','','[]','白屋秋聲裏，蹉跎旅食春。',48,'全唐诗/poet.song.100000.json','["白屋秋聲裏，蹉跎旅食春。", "挑燈魯酒薄，拊枕越雞晨。", "學術家傳業，風流德有鄰。", "似聞川陜捷，吾道付峨岷。"]'),
('cb40d565-8ab8-4344-b4e4-467b2b898492','題張公文潛詩卷一首','蘇籀','宋','宋诗','song-poetry','','[]','羣才奔正始，辨論軼髯卿。',204,'全唐诗/poet.song.100000.json','["羣才奔正始，辨論軼髯卿。", "諸老力推轂，斯文有定評。", "龍旗叔孫氏，金筆左丘明。", "杕杜嘗嗤點，椒蘭足陷傾。", "窮途乖黨侶，陋屋掛冠纓。", "彰炳流千載，嗟咨奠兩楹。", "桑枌墮兵火，簡札落寰瀛。", "態度雲霞蔚，瑰奇珠玉生。", "淵停真可挹，川駛不留行。", "機杼班揚舊，笙竽陶謝并。", "風騷齊穆若，郊島埒低平。", "百末芳蜂採，千岐理刃迎。", "斧斤皆閣束，鑿枘自天成。", "大論尤宏博，短章工冽清。", "精微演孔佛，剛毅獎周京。", "糲食何曾饜，高標不朽名。", "斐然愚小子，欽詠有餘聲。"]'),
('ab2c3164-2b5d-4375-a319-7cc133bf2951','國士一首','蘇籀','宋','宋诗','song-poetry','','[]','五陵少年銅乳臭，哲肅何甘作牛後。',160,'全唐诗/poet.song.100000.json','["五陵少年銅乳臭，哲肅何甘作牛後。", "曲合汙世鄉愿徒，俗學聾瞽紛蕪莠。", "文士規模正始間，風流可喜未曾有。", "志士機敏常濟務，斡旋金穀捷趨走。", "取亂尤須見兵勢，料敵先應决攻守。", "至言碩畫安危機，却顧前思能審究。", "服戎角力乃兵耳，入幄造膝直禦寇。", "人心天意歸有道，務穡訓學臻富壽。", "自古迂儒無益算，蓋世奇才實天授。", "誰能剡牘出公言，明年定取單于首。"]'),
('5aa4d199-9c9b-485c-a7a8-d15746773d92','聞舊曲一首','蘇籀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','短舞長謳撩性情，狗翻砑鼓醉承平。',64,'全唐诗/poet.song.100000.json','["短舞長謳撩性情，狗翻砑鼓醉承平。", "六么花下西湖集，三疊雲凝玉塞聲。", "治世之音豈淪謝，淫哇已極返和清。", "關雎正雅終知律，前聖嘗云畏後生。"]'),
('588ab744-159f-4963-b028-4cc6554ee768','中觴二絕  其一','蘇籀','宋','宋诗','song-poetry','','[]','欲瀾秋水剪瞳人，愁絕春山傚玉真。',32,'全唐诗/poet.song.100000.json','["欲瀾秋水剪瞳人，愁絕春山傚玉真。", "擘了荔支拋荳蔻，送鈎非復近前嗔。"]'),
('11d493a1-a764-4681-8777-b38c63ccc0f3','中觴二絕  其二','蘇籀','宋','宋诗','song-poetry','','[]','珠貫筍彎奇出倫，龍蘭入縷疊文茵。',32,'全唐诗/poet.song.100000.json','["珠貫筍彎奇出倫，龍蘭入縷疊文茵。", "芳年長好長歡夜，滿意同心同夢人。"]'),
('68417bbf-0201-4b17-ab0f-e4a63275ee5a','題兩黄仙人鍊丹山頂一絕','蘇籀','宋','宋诗','song-poetry','','[]','絲毫觸石千山澤，喙吻傳聲萬壑雷。',32,'全唐诗/poet.song.100000.json','["絲毫觸石千山澤，喙吻傳聲萬壑雷。", "信有蘚書標洞府，不應俗駕半途迴。"]'),
('81b1c1e9-612f-49b1-aa3d-d897f3f69e2d','平津一首','蘇籀','宋','宋诗','song-poetry','','[]','布衣海上看羣豕，金門晚躋作三吏。',128,'全唐诗/poet.song.100000.json','["布衣海上看羣豕，金門晚躋作三吏。", "漢主功名氣薄雲，柄用儒術親且貴。", "曉通當世博前聞，自得春秋有餘地。", "臣節儉約君道廣，烜赫顒昂仍布被。", "蒼海西南罷遠征，懇棄朔方違詔旨。", "發策不如朱長史，庭論依違何委靡。", "議誅郭解沮卜式，山東鄙人殊不鄙。", "流輩紛紛稱職難，黄髮鬖髿保終始。"]'),
('f896fd04-c4cd-47ee-bfa6-c4bd5b511e5d','皇甫一首','蘇籀','宋','宋诗','song-poetry','','[]','吏部初學除陳言，學成理達無可刪。',144,'全唐诗/poet.song.100000.json','["吏部初學除陳言，學成理達無可刪。", "腐朽點化皆不凡，有如黄河出崑崙。", "魚龍萬怪隨濤奔，志氣剛偉充乾坤。", "灌溉所短誇雄渾，篇什性情禮義根。", "亦曰餘事期知文，弟子皇甫同光塵。", "師說豈不明淵源，首推燕許潤王綸。", "明堂郊廟嚴且尊，嗚呼古人弗妄云。", "研鉆百家窮典墳，兩賢纂組承華勛。", "演敷奇致開妙門，盪耀四海蘇頑昏。"]'),
('98f67422-9448-4d3a-bc3f-8c1a63c3e3bb','中壘一首','蘇籀','宋','宋诗','song-poetry','','[]','更生傾側四斥已，精誠所祈格天地。',224,'全唐诗/poet.song.100000.json','["更生傾側四斥已，精誠所祈格天地。", "著明深切安危機，同道蕭周數人耳。", "不容何病見君子，節義政應强國勢。", "倖卿權尹豈嘗無，忠正得朋僥冒柅。", "可憐孤直援又寡，惡惡如風力排詆。", "漢皇聽納知其忠，左右側目爭摧圮。", "親親公族人莫比，按據春秋憂變異。", "蕭張戮死正人空，挫姦救危寧畏忌。", "勤勤請抑外家權，社稷安榮長久計。", "二十餘年列大夫，痛切皇輿難坐視。", "當時不謂秦無人，異世知音誠歎企。", "亂生禍重英傑資，無競維人當樹置。", "絳侯博陸在巖廊，高武不復憂劉氏。", "胡爲一簣障江河，諫鼓屢鳴那得濟。"]'),
('a9d52b45-a7be-464b-a7b1-818e178038d4','甲寅歲雪一首','蘇籀','宋','宋诗','song-poetry','','[]','冬燠陽淫遇上春，飛霙爽徹浩無垠。',96,'全唐诗/poet.song.100000.json','["冬燠陽淫遇上春，飛霙爽徹浩無垠。", "凌霄據壤平窪凸，破塊抽萌蝕腐陳。", "皎潔肌容宜夜覿，培堆靀鬆詰朝新。", "勻勻帝澤烝民粒，止止人寰世界塵。", "野渡舟沈堆鷺羽，豪家堂下散瑶珉。", "袁生高卧誠清尚，慧可安心奈苦辛。"]'),
('2fc071ea-e4ac-4068-9b51-700e0e5f243b','程待制邁父求挽詞  其一','蘇籀','宋','宋诗','song-poetry','','[]','從班有子蒔陔蘭，三貴相承德齒官。',64,'全唐诗/poet.song.100000.json','["從班有子蒔陔蘭，三貴相承德齒官。", "政理庭闈貽濟美，暄凉枕席問平安。", "箕裘桑梓人欽羨，滫瀡膏飴養色難。", "千乘送車傾井邑，劍留傳寶涕汍瀾。"]'),
('df856ab5-3846-48c9-8f92-f27cf6da3744','程待制邁父求挽詞  其二','蘇籀','宋','宋诗','song-poetry','','[]','太古衣冠綺季風，厖眉鶴骨似霜松。',64,'全唐诗/poet.song.100000.json','["太古衣冠綺季風，厖眉鶴骨似霜松。", "一枰瓜葛爲嬉笑，奕葉芝蘭真睦雍。", "珍具乞言端有屬，搢紳歌詠慶惟鍾。", "歸全五福殊無憾，密印行將一品封。"]'),
('9328c449-0111-4cb7-bbb8-9903bb96d594','題僧寮白瑞薌一首','蘇籀','宋','宋诗','song-poetry','','[]','芳蕤何蒨絢，尤物真旖旎。',72,'全唐诗/poet.song.100000.json','["芳蕤何蒨絢，尤物真旖旎。", "五葉映雕欄，三椏駢粉蕊。", "妍分春月魄，香徹肌骨髓。", "壁觀艷成魔，鶴林神作祟。", "豈特梅可簪，殊勝麝多忌。", "野藋與戎葵，猶堪解其穢。"]'),
('21269828-2475-40de-9402-5fb020851a70','韓簿之常山送行一首','蘇籀','宋','宋诗','song-poetry','','[]','蒼隼卑飛亦將擊，素琴不擬貴高張。',128,'全唐诗/poet.song.100000.json','["蒼隼卑飛亦將擊，素琴不擬貴高張。", "勾稽俛首親朱墨，甘旨役心謀稻粱。", "吏幹能稱追伯仲，朝端近例寘周行。", "題名塔廟經坊市，俯瞷煙雲越澗岡。", "相勉三餘牽著擬，助栽九畹待芬芳。", "縶維騏驥初從軛，强勁蒹葭要飽霜。", "縣小官閒無甚責，秩卑俸薄又何傷。", "公田私畝工夫遍，世閥前修在激昂。"]'),
('8c5e1a1f-a2f5-45b6-9fe8-3f0f2b8b935d','紬史','蘇籀','宋','宋诗','song-poetry','','[]','延陵皋壤决歸歟，習氣過憂觚不觚。',64,'全唐诗/poet.song.100000.json','["延陵皋壤决歸歟，習氣過憂觚不觚。", "何怪倚門嗟抗髒，近來合樂寵侏儒。", "過關自欲聞雞唱，居肆何須較馬摸。", "乖合偶然非汝力，迷途先覺解攣拘。"]'),
('6651bf87-1722-40f5-b279-4b4af7222cf9','著書','蘇籀','宋','宋诗','song-poetry','','[]','著書前古老虞卿，何必窮愁學乃成。',64,'全唐诗/poet.song.100000.json','["著書前古老虞卿，何必窮愁學乃成。", "駕說精心是家訓，修辭肆筆體人情。", "少年竦躍文章慕，老去沖融道術鳴。", "流略從今皆指掌，粗令衰世不喑盲。"]'),
('453a31b3-41e6-41ba-8d2c-faa8850c1734','大塢山寺','蘇籀','宋','宋诗','song-poetry','','[]','巘谷窈幽深，映發杉松嘉。',168,'全唐诗/poet.song.100000.json','["巘谷窈幽深，映發杉松嘉。", "擊鉢半喬木，燒香亂煙霞。", "穹林擢峭壁，攙竦迴環遮。", "四合山復山，泉籟音響譁。", "清致滿樓閣，道人心靡他。", "寒磵柹栗秋，暗窗秀枇杷。", "倦飛暫投迹，脫兔無復罝。", "茹粲鹽酪空，解釧與笄珈。", "餘生愧語偷，逆旅即住家。", "戰鼓震淮甸，雄師奮爪牙。", "儒士繆揣摩，戎韜政紛拏。", "才智爲人謀，何事丘中麻。", "冥鴻跨海岱，逝水悲榮華。", "曠哉遊方外，心迹同幽遐。"]'),
('51046b2c-0aea-4d72-ab75-9744f96a73ab','幽栖三首  其一','蘇籀','宋','宋诗','song-poetry','','[]','去去追濠濮，悠悠平渭莘。',48,'全唐诗/poet.song.100000.json','["去去追濠濮，悠悠平渭莘。", "荒凉羅雀處，寤寐叱牛頻。", "鴞炙逢希闊，萍虀適醞醇。", "自謀螻蟻穴，何以拯斯人。"]'),
('9cd79f26-12c4-4280-ac1d-b7396bd98f5b','幽栖三首  其二','蘇籀','宋','宋诗','song-poetry','','[]','豹霧谷容晦，虎風林響寒。',48,'全唐诗/poet.song.100000.json','["豹霧谷容晦，虎風林響寒。", "通宵喧澗瀨，出日照嵐巒。", "掩卷妨作樂，搘筇詠考槃。", "王孫有窟宅，吾道尚艱難。"]'),
('bedb9b06-3388-4c42-8a74-45ee44b8f551','幽栖三首  其三','蘇籀','宋','宋诗','song-poetry','','[]','三芝羽人佇，五誡壞衣脩。',48,'全唐诗/poet.song.100000.json','["三芝羽人佇，五誡壞衣脩。", "農圃日用事，芻蕘無幾求。", "林丘識真趣，城闕罷菟裘。", "揮斥塵勞客，平生爲道謀。"]'),
('303bca36-8a60-4a4b-9bb6-0e08a31b678f','臘雪一首','蘇籀','宋','宋诗','song-poetry','','[]','吞屋糝空嗥越犬，如椽懸乳戰吳僧。',64,'全唐诗/poet.song.100000.json','["吞屋糝空嗥越犬，如椽懸乳戰吳僧。", "皛然一色紛無際，飄瞥羣花散却凝。", "人迹禽飛遭屏絕，竹端松頂重何勝。", "將軍逐虜弓刀濕，坐幄書生能不能。"]'),
('b32b0b53-e3c7-4dc1-900e-e44dbbccfe09','晴日縱步二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','窮臘末垂風景和，久遊誠是我陵阿。',64,'全唐诗/poet.song.100000.json','["窮臘末垂風景和，久遊誠是我陵阿。", "牧童笛遠雞鳧散，獵戶弓鳴猯鹿多。", "季雅濙濙疑蜜釀，木奴小小似金槎。", "起溲十裂吳羹釅，止酒陶詩但獨哦。"]'),
('547d1c2c-35ba-435c-819a-b5dc9df926e3','晴日縱步二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','雲際潺湲入下田，田塍級級逗平泉。',64,'全唐诗/poet.song.100000.json','["雲際潺湲入下田，田塍級級逗平泉。", "羊腸犖确褰裳過，蝸殻跧藏插槿邊。", "荷蓧何人行嘆息，饋漿與客更留連。", "丹霞翠霧皆招隱，一抹殘陽衆木顛。"]'),
('a8449e7c-f67b-4000-8731-35157efb2e9f','和卷中韓子蒼梅花三首  其一','蘇籀','宋','宋诗','song-poetry','','[]','先開媚晴昊，孤艷斷魂時。',48,'全唐诗/poet.song.100000.json','["先開媚晴昊，孤艷斷魂時。", "遶樹沈煙度，凌寒檀暈披。", "參橫明月觀，雪細影娥池。", "結實冥冥雨，君看雀啅枝。"]'),
('440ace62-94ef-46d2-a2b0-eff141fdf4e7','和卷中韓子蒼梅花三首  其二','蘇籀','宋','宋诗','song-poetry','','[]','凍枿雖臞甚，含英山意催。',48,'全唐诗/poet.song.100000.json','["凍枿雖臞甚，含英山意催。", "斲冰衝曉色，綻綠透春迴。", "健步故人信，流芳好事杯。", "不論山水僻，往往拾香來。"]'),
('9640df6e-28e3-4a0c-b44c-bd60388be680','和卷中韓子蒼梅花三首  其三','蘇籀','宋','宋诗','song-poetry','','[]','國香傾國色，天質殆天憐。',48,'全唐诗/poet.song.100000.json','["國香傾國色，天質殆天憐。", "含笑冰崖側，無言石瀨濺。", "湘娥愁暮倚，孫令馥終筵。", "卜夜多松炬，玉容殊更妍。"]'),
('941f1c18-c3f5-4e35-95c0-7ff9b8884067','留別趙大年并姪十七秀才  其一','蘇籀','宋','宋诗','song-poetry','','[]','晉公賓佐選，英毅冠朝端。',48,'全唐诗/poet.song.100000.json','["晉公賓佐選，英毅冠朝端。", "三日拂冠劍，一時增羽翰。", "世家存器質，國論佇圖難。", "從此拋經卷，青氈拜近官。"]'),
('ae379700-ca43-45e8-abf3-1e640c272456','留別趙大年并姪十七秀才  其二','蘇籀','宋','宋诗','song-poetry','','[]','君年有餘富，我老漸來侵。',48,'全唐诗/poet.song.100000.json','["君年有餘富，我老漸來侵。", "莽蒼麏鼯野，峙停鸞鵠音。", "藜羹秉觚牘，篳路向山林。", "商略古人意，孜孜不患深。"]'),
('b3f277bd-af71-4c05-89c4-437f137448dc','瑞香一首呈韓子平','蘇籀','宋','宋诗','song-poetry','','[]','未拆嬌紅淺紫駢，差差衆葉翠翹然。',64,'全唐诗/poet.song.100000.json','["未拆嬌紅淺紫駢，差差衆葉翠翹然。", "誤稱蘭艷風流冠，且縱桃夭萬一憐。", "列檻閉帷增峭烈，訴杯閣筆負嬋娟。", "司花處子春風面，醲態奇香想象焉。"]'),
('96b19860-21e7-464e-b990-66a2d2f4b7c1','金華邵氏面山臨溪而居又架木爲亭雲林丘壑之勝趣乃兼得之邵氏求其名予誦東坡江郊詩名之曰蒨絢題一絕','蘇籀','宋','宋诗','song-poetry','','[]','茂林翠巘碧潺湲，凉月白雲飄素筵。',32,'全唐诗/poet.song.100000.json','["茂林翠巘碧潺湲，凉月白雲飄素筵。", "几杖逍遥領其會，佳哉蒨絢有餘妍。"]'),
('62ce96ca-a430-4804-bda5-dbb62af45bf0','大暑憶靈隱寺冷泉一首','蘇籀','宋','宋诗','song-poetry','','[]','我念熱客辭，懷哉冷泉遊。',171,'全唐诗/poet.song.100000.json','["我念熱客辭，懷哉冷泉遊。", "此水暨此山，清便物殊尤。", "澄渟快一生，晶澈奪兩眸。", "青瑶碧玻瓈，三頃方能侔。", "澡雪戲{山豦}間，大川漫悠悠。", "浣瀹鑑臨際，千仞險何求。", "面堂浸几筵，汎槳颺扁舟。", "泠泠析酲惛，一一數鰕鰍。", "當階掬珠璧，欹枕拖綸鈎。", "雷霆落閘喧，雪霜浮澗流。", "京江謝潔滑，苕霅雄偏州。", "月夕了無滓，暑天常似秋。", "拜塵付一咍，汩泥亦包羞。", "願浴岐山鳳，勿飲荆州牛。"]'),
('26ba6b80-437d-43d7-93a9-7fabfbefbd75','苦熱二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','示病劉松殊不飲，爍燔汗眩兀如癡。',64,'全唐诗/poet.song.100000.json','["示病劉松殊不飲，爍燔汗眩兀如癡。", "塵囂堀堁東山扇，汩濁祇慚叔度陂。", "茗汁粟漿迴渴夢，大門高屋憚炎曦。", "生靈惴惴苗同槁，救暍哀祈風雨吹。"]'),
('25cbb7f8-4423-4c95-b6a7-4d2c269d4b72','苦熱二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','越吟吳詠兩參商，我那皋原儂水鄉。',64,'全唐诗/poet.song.100000.json','["越吟吳詠兩參商，我那皋原儂水鄉。", "赤地千倉待舂簸，炎飚九夏劇晴陽。", "雲霓不族訟風伯，雷電慚勞驅畢方。", "獨卧嗟咨龍伯懶，夢乘天駟灑淋浪。"]'),
('1b8838bb-35b3-4d02-8b59-c18526e10fd3','題徐師川詩卷一首','蘇籀','宋','宋诗','song-poetry','','[]','學究村村自謂賢，西京涇渭派淪漣。',64,'全唐诗/poet.song.100000.json','["學究村村自謂賢，西京涇渭派淪漣。", "古人聖處工研貫，新義阿時力洗湔。", "炳闊多聞包宇宙，閴寥餘韻出蹄筌。", "飄然徑造騷人室，老憤應加視後鞭。"]'),
('b3016127-ea54-4065-9548-dcb4edd4c6f3','不雨一絕','蘇籀','宋','宋诗','song-poetry','','[]','雲將礮車來禦敵，雨師箭鏃插于房。',32,'全唐诗/poet.song.100000.json','["雲將礮車來禦敵，雨師箭鏃插于房。", "西成一顆望千滴，跋扈朱明未可量。"]'),
('54219aaa-7dbf-4d60-a0c2-076e6c601104','校讎古史二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','炎犧分紀到先秦，散脫前聞待發明。',64,'全唐诗/poet.song.100000.json','["炎犧分紀到先秦，散脫前聞待發明。", "處士妄談紛戰國，專門阿黨蔽西京。", "塵沙滌蕩川歸海，故實符同史與經。", "夢奠老人遺意得，摩天巨刃不留行。"]'),
('e9dde27e-2d29-4c3f-baba-26f42ce74b13','校讎古史二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','貌從周孔譏誣僞，臆斷詩書悉抵梧。',64,'全唐诗/poet.song.100000.json','["貌從周孔譏誣僞，臆斷詩書悉抵梧。", "悟鑒精明原本末，討窮商略較錙銖。", "所存偶免隨秦火，不喻遺忘笑漢儒。", "理勝凜然詞旨達，知音儻遇聖人徒。"]'),
('670065d2-e4d2-4f9a-9816-449d9298a7d0','次韻范才元中秋夜','蘇籀','宋','宋诗','song-poetry','','[]','常娥偕婺女，萬里玉京會。',96,'全唐诗/poet.song.100000.json','["常娥偕婺女，萬里玉京會。", "雲璈闋未終，莫靄黯愁對。", "真人一謦欬，開闔隨霽晦。", "寒波揚廣廷，清光一年最。", "頃刻人間世，銀色化諸穢。", "法士屏杯杓，癡兒戀珍貝。", "皆言此宵樂，復欲何時醉。", "蟾宮正植璧，星潢亦委佩。"]'),
('a62c357c-76f1-4de5-93ab-04923847cd13','晚秋偶成','蘇籀','宋','宋诗','song-poetry','','[]','生涯一笑槁梧橫，葉下寒波收潦清。',64,'全唐诗/poet.song.100000.json','["生涯一笑槁梧橫，葉下寒波收潦清。", "金鈿露香花近信，乳泓雲撥酒新萌。", "岷人罷賦家四壁，洛客懶吟棋一枰。", "流落粗疏分樵牧，故人衮衮任公卿。"]'),
('62ac3147-a7b1-4ac3-ab64-3977586915ed','僑居','蘇籀','宋','宋诗','song-poetry','','[]','買僮貸宅愈迂疏，穎士皆能講舊廬。',64,'全唐诗/poet.song.100000.json','["買僮貸宅愈迂疏，穎士皆能講舊廬。", "典學前聞質郯子，天人定勝取申胥。", "未應孤負囊中筆，粗爾消磨架上書。", "借問棼絲誰任理，豈惟短髮每晨梳。"]'),
('476c3dda-7e09-4cd4-8260-073b6e267b96','次韻伯父茶花  其一','蘇籀','宋','宋诗','song-poetry','','[]','鳥咮傾藍雨春霽，瓊芳入眼霧冬昏。',32,'全唐诗/poet.song.100000.json','["鳥咮傾藍雨春霽，瓊芳入眼霧冬昏。", "一枝膚雪壺中曜，靜几低窗養晏溫。"]'),
('13fa5980-87b2-422e-b3c4-e3cdc39c4fc4','次韻伯父茶花  其二','蘇籀','宋','宋诗','song-poetry','','[]','真態妖香自不言，斲冰修月妙無痕。',32,'全唐诗/poet.song.100000.json','["真態妖香自不言，斲冰修月妙無痕。", "直須嚌啜松風碗，豈患詩魔渴醉魂。"]'),
('a004f105-2b63-43aa-9e6d-9c8a3ec23e33','北榭','蘇籀','宋','宋诗','song-poetry','','[]','坐消床刃肘生胝，寓目危亭汗漫期。',128,'全唐诗/poet.song.100000.json','["坐消床刃肘生胝，寓目危亭汗漫期。", "奄靄煙嵐客愁絕，高明茨葦屋云誰。", "治城廛肆吁吾有，近市塵囂懶汝移。", "金剎仙梯霞祲近，雲軿風馬往來馳。", "鶴鳴華表青田志，雁引邊沙朔氣飛。", "越北燕南紛會解，傖音憬俗寖相知。", "藪丘水竹揮毫助，友愛朋從攝袂隨。", "老鈍貪追仲宣賦，達生不泥子長奇。"]'),
('37edcd21-a30f-4fdb-b1e6-b4ae79daa82b','陳翁妻何氏挽詞','蘇籀','宋','宋诗','song-poetry','','[]','馴和乃宗競，攻苦更家豐。',48,'全唐诗/poet.song.100000.json','["馴和乃宗競，攻苦更家豐。", "不失蒸嘗職，無非女士風。", "南陔泣笄冠，中饋歎光鴻。", "夜績燈誰續，承承錫祚隆。"]'),
('1b664cd6-5d49-4393-b5f5-a1d526ac286a','潘舍人求父朝議挽詩','蘇籀','宋','宋诗','song-poetry','','[]','紫微內史世常揚，鶴髮尊榮侍膝旁。',96,'全唐诗/poet.song.100000.json','["紫微內史世常揚，鶴髮尊榮侍膝旁。", "桂籍連枝皆挺特，蘭陔六藝競芬芳。", "雲霄門閥公侯拜，藻斧淵源典冊光。", "水擊三千由積厚，天資九十恃康强。", "青衿縞素行師服，輓鐸謳吟廣柳箱。", "大啟新阡高冢舍，義方不羨竇家郎。"]'),
('8b1465b2-7e4e-49d1-85d5-a559d3f986fb','寄呂德元時爲督府屬二絕  其一','蘇籀','宋','宋诗','song-poetry','','[]','稍費江南萬側釐，多謄符檄喻亡齊。',32,'全唐诗/poet.song.100000.json','["稍費江南萬側釐，多謄符檄喻亡齊。", "寬然折箠可入汴，已見票姚擒日磾。"]'),
('40227de4-ed5d-42e8-9c14-a77d2cae6ed8','寄呂德元時爲督府屬二絕  其二','蘇籀','宋','宋诗','song-poetry','','[]','祖生晚節並劉琨，獨免聲消賈謐塵。',32,'全唐诗/poet.song.100000.json','["祖生晚節並劉琨，獨免聲消賈謐塵。", "虎士淮淝初小捷，謝庭蘭玉絕常倫。"]'),
('be4ee50c-42e9-49a7-adf3-5bbf1926a605','靈巖寺偃松一首','蘇籀','宋','宋诗','song-poetry','','[]','直哉十尋幹，亭亭無附枝。',180,'全唐诗/poet.song.100000.json','["直哉十尋幹，亭亭無附枝。", "紆哉獨縱肆，蟠據何離奇。", "垂髯鬰千霜，蛟臂犀兕皮。", "揉剛爲謙屈，至高而聽卑。", "攀玩凡幾曲，凜冽英雄姿。", "傑卓矧尚同，擺落造物爲。", "進乎繩纆外，詭異有所施。", "激耳奏竽瑟，超世騰龍螭。", "橫秋老氣逸，軼材那紲羈。", "高可容冠輿，清甚生泠颸。", "先容器萬乘，愛身恐無辭。", "抑抑衛武公，逮下文王妃。", "筇竹與酒壺，掛空憩寂時。", "客來秋冬際，狗駟車雞栖。", "有僧捫翠拂，擎跽求此詩。"]'),
('1fb2f33e-dccf-4a23-9c5c-0af9fad8b04b','送韓少汲萍鄉尉','蘇籀','宋','宋诗','song-poetry','','[]','大門人望舊旌旄，嶺表瀧頭罄錯刀。',64,'全唐诗/poet.song.100000.json','["大門人望舊旌旄，嶺表瀧頭罄錯刀。", "中饋從誰合紅巹，郵亭自詭絮征袍。", "青衫九品非君慍，黄卷連車慰我曹。", "蘭蕙滿山山水縣，遥知放意詠離騷。"]'),
('b4311c5d-93dd-4dd6-9da7-6356a879dc9b','讀范龍閣五丈奏議三絕  其一','蘇籀','宋','宋诗','song-poetry','','[]','撫編屢歎才謨遠，早歲升堂拜若人。',32,'全唐诗/poet.song.100000.json','["撫編屢歎才謨遠，早歲升堂拜若人。", "亹亹聽言皆破的，龍蛇蟠屈負經綸。"]'),
('ea65631e-a0ae-4c68-adb5-65bd30fcf6dd','讀范龍閣五丈奏議三絕  其二','蘇籀','宋','宋诗','song-poetry','','[]','奕枰著著窮機變，庖刃恢恢中會通。',32,'全唐诗/poet.song.100000.json','["奕枰著著窮機變，庖刃恢恢中會通。", "世俗吏能那並比，汗顔血指竟何功。"]'),
('2ffe939a-2e57-4862-a52d-479dc20f34db','讀范龍閣五丈奏議三絕  其三','蘇籀','宋','宋诗','song-poetry','','[]','九原英魄誰能作，規略千條殆可尋。',32,'全唐诗/poet.song.100000.json','["九原英魄誰能作，規略千條殆可尋。", "佐佑艱難揣夷狄，似茲舉措好爲霖。"]'),
('03f99921-3284-4742-aa4f-5deb9e8608c2','題南圃一首','蘇籀','宋','宋诗','song-poetry','','[]','妖嫺十五餘，清春破瓜初。',72,'全唐诗/poet.song.100000.json','["妖嫺十五餘，清春破瓜初。", "婉膩詎如玉，凌風素雲裾。", "鶯燕妬聲實，窈心自有夫。", "取憐逆萬目，白地腸應無。", "惶惑少年士，逐麋不顧菟。", "傾囊買消渴，借問誰家姝。"]'),
('f1ddb8bd-56f2-43bb-b92b-e2c7c5af89ce','送都屬八舍弟桂林買馬一首','蘇籀','宋','宋诗','song-poetry','','[]','夷德貪婪漢財賄，莫惜金多能使鬼。',152,'全唐诗/poet.song.100000.json','["夷德貪婪漢財賄，莫惜金多能使鬼。", "噴玉難拘伏波式，上駟超摇獻天子。", "子今叱馭湘南裔，桂嶺下下復高高，鳥驚獸駭征人喟。", "當官官事從容理，思馬斯臧由此始。", "電尾風騣未平齒，絕壑踔山如歷塊。", "執驅效牽髯校尉，槽櫪經由書殿最。", "謝公總統修戎備，二柄德刑兼兩寄。", "不矜吾黨愈推能，宵旰潛心活國計。", "雜沓英豪乘虎騎，日闢神州一百里。"]'),
('b1615645-cd94-456e-8042-3971930ad6ff','望道一首','蘇籀','宋','宋诗','song-poetry','','[]','少年相尚依阿語，老大迴看不住心。',64,'全唐诗/poet.song.100000.json','["少年相尚依阿語，老大迴看不住心。", "望道尊師豈盲進，憂時論事敢浮沈。", "侏儒飽死嗤方朔，懸罄饑貧類展禽。", "好古宜交魯衛士，豳風咀噍有遺音。"]'),
('5eb8a467-5688-433d-9446-a21a9e2c4b94','疏懶一首','蘇籀','宋','宋诗','song-poetry','','[]','妨人作樂屏書籤，閣筆無情復强捻。',64,'全唐诗/poet.song.100000.json','["妨人作樂屏書籤，閣筆無情復强捻。", "執御祇應曩規範，鍛金不假別鎚鈐。", "花開咄咄人清苦，鳥哢聲聲夢黑憇。", "出世世間皆有道，糟醨餔啜量難兼。"]'),
('5060433a-c8a6-47bd-935d-9e0b9615b4a3','臨雙溪一首','蘇籀','宋','宋诗','song-poetry','','[]','汪汪西步桃花候，去去南巒蒼狗雲。',64,'全唐诗/poet.song.100000.json','["汪汪西步桃花候，去去南巒蒼狗雲。", "日煖汀沙牧人夢，春嬉鳧鶩野夫芹。", "繚郛左右交流澮，彼岸烟昏漲梓枌。", "頷首悠然辨真趣，會心比況有奇聞。"]'),
('2858903e-1f69-48d3-9ec4-ab59e24186f4','憶京雒木芍藥三絕  其一','蘇籀','宋','宋诗','song-poetry','','[]','熟美酣馨迸佳瑞，暈稜紅碧化神工。',32,'全唐诗/poet.song.100000.json','["熟美酣馨迸佳瑞，暈稜紅碧化神工。", "根株肇自韓郎染，葩蘤人間一洗空。"]'),
('68e6ff6c-2938-4781-aab8-44fac077d242','憶京雒木芍藥三絕  其二','蘇籀','宋','宋诗','song-poetry','','[]','沈薌亭北壓欄桿，眩耀熒煌障幄寬。',32,'全唐诗/poet.song.100000.json','["沈薌亭北壓欄桿，眩耀熒煌障幄寬。", "不薄官梅伴飛霰，只饒蘭蕙楚騷寒。"]'),
('615c3eed-8693-47b1-a2ca-2e477ae45163','憶京雒木芍藥三絕  其三','蘇籀','宋','宋诗','song-poetry','','[]','廬陵涑水携參佐，媚紫嬌黄左與姚。',32,'全唐诗/poet.song.100000.json','["廬陵涑水携參佐，媚紫嬌黄左與姚。", "何物山丹衒流俗，雒生懊惱慍蓬飄。"]'),
('476e22dc-609a-4032-84fb-3cccaf9013c6','睡起一首','蘇籀','宋','宋诗','song-poetry','','[]','身將抱甕灌田疇，老大徒傷鬢已秋。',64,'全唐诗/poet.song.100000.json','["身將抱甕灌田疇，老大徒傷鬢已秋。", "滯念生緣寧故我，濟時及物勉前修。", "勃磎行世終剛介，重惜尤人返自求。", "塞馬未嘗矜得儁，湘猨不在較羣猴。"]'),
('314c5ab2-0fd5-420a-985b-bc5822a4dc49','送才元長樂倅','蘇籀','宋','宋诗','song-poetry','','[]','東省西臺除吏目，軼才勿謂得途賒。',128,'全唐诗/poet.song.100000.json','["東省西臺除吏目，軼才勿謂得途賒。", "孰云相貳徒勞職，政恐東南弗復加。", "常衮頒宣禮翹秀，仲翔好事走幽遐。", "口占十吏傳州檄，指畫千條靖海涯。", "榕木覆街飛皂蓋，荔園供餉赫凝霞。", "政平訟簡清如水，能賦登高墨似鴉。", "咻彼夷音姑洛詠，歸來越橐換吳娃。", "摳衣岑范欽高致，談舌瀾翻潑貢茶。"]'),
('3e1d91d2-f543-4725-b66d-68eb4e544c50','秋夜聽雨一首','蘇籀','宋','宋诗','song-poetry','','[]','蕭騷闇響空階滴，復值幽人對榻時。',64,'全唐诗/poet.song.100000.json','["蕭騷闇響空階滴，復值幽人對榻時。", "旨趣逍遥稱漫叟，鋒鋩扞格愧神錐。", "願擯謝萬令閒處，實藉陳平屢出奇。", "心境卧輪非別伎，少年狡獪赴無爲。"]'),
('a1632c4d-d32d-401e-8710-ebf6e171b396','廛居一首','蘇籀','宋','宋诗','song-poetry','','[]','廣輪函丈中唐甓，安得青松柏篠柟。',64,'全唐诗/poet.song.100000.json','["廣輪函丈中唐甓，安得青松柏篠柟。", "蘭菊葵荷聊代匱，鳥烏鵞鴨粗相諳。", "中田他日規蝸舍，諸巘白雲縈翠嵐。", "耕殖自營天韻佚，世芬妨道豈宜躭。"]'),
('bf31e998-e7de-407b-b9bd-d8583768e8cc','簡江國韓尉謝珍惠二絕  其一','蘇籀','宋','宋诗','song-poetry','','[]','江國緜蠻登俎味，篛缸漬畔糝鹽醯。',32,'全唐诗/poet.song.100000.json','["江國緜蠻登俎味，篛缸漬畔糝鹽醯。", "坐愚糜殞追時好，嗟汝頭顱不自知。"]'),
('b1606f56-ad24-4d09-8a7a-ee6f8b2ff389','簡江國韓尉謝珍惠二絕  其二','蘇籀','宋','宋诗','song-poetry','','[]','獠羞巒錯儒庖溽，熊掌大嗤牛尾狸。',32,'全唐诗/poet.song.100000.json','["獠羞巒錯儒庖溽，熊掌大嗤牛尾狸。", "飫臠羊膀與駝蹠，芳辛咀噍半酣宜。"]'),
('e11e6c71-1a1f-4e6c-9ab7-4e3d4792541b','李監廟求拙軒一首','蘇籀','宋','宋诗','song-poetry','','[]','鏝圬累瓴甓，几席面春叢。',48,'全唐诗/poet.song.100000.json','["鏝圬累瓴甓，几席面春叢。", "林塢純真趣，衣巾質古風。", "寧非迂叟合，豈與漫郎同。", "不巧姑云爾，何妨詩更工。"]'),
('5d5c78fd-5b94-4f55-ab0f-2efa59e01011','送趙憲御史赴江西三絕  其一','蘇籀','宋','宋诗','song-poetry','','[]','崆峒日煖嵐巒麗，章貢桃花春漲豪。',32,'全唐诗/poet.song.100000.json','["崆峒日煖嵐巒麗，章貢桃花春漲豪。", "避傳封人候驄馬，道旁武吏各鞬櫜。"]'),
('cff4eafb-2d2b-4e7b-9dc0-8e6d7f68174b','送趙憲御史赴江西三絕  其二','蘇籀','宋','宋诗','song-poetry','','[]','賈生纂著五十八，元歎風規自伯喈。',32,'全唐诗/poet.song.100000.json','["賈生纂著五十八，元歎風規自伯喈。", "貪吏革心寬貶坐，頑甿耒耜不椎埋。"]'),
('067e6e91-f84c-4b2e-8c26-6adbf5ce1bb1','送趙憲御史赴江西三絕  其三','蘇籀','宋','宋诗','song-poetry','','[]','冷坐從嘲瓶井眉，俗流淺拙更忘遺。',32,'全唐诗/poet.song.100000.json','["冷坐從嘲瓶井眉，俗流淺拙更忘遺。", "道鳴庶矣多聞力，建武官僚舊漢儀。"]'),
('a7a7e965-a330-4e35-a3a4-77dc7a5d30c3','寒食後出郊一首','蘇籀','宋','宋诗','song-poetry','','[]','澹沱東風酒一巵，笙篁雞鞠傲春暉。',64,'全唐诗/poet.song.100000.json','["澹沱東風酒一巵，笙篁雞鞠傲春暉。", "綠波泛灧心微蕩，邃苑提携手未揮。", "藿靡莎長縈冶步，猗儺花亞罥薰衣。", "桃溪飛彈遊童過，竹塢聞棋道士歸。"]'),
('653c4a76-4650-4a5d-9fd2-168434c610c5','龍翔真歇和尚求詩贈一首','蘇籀','宋','宋诗','song-poetry','','[]','象骨巖居閩府教，江海兩封黄紙召。',240,'全唐诗/poet.song.100000.json','["象骨巖居閩府教，江海兩封黄紙召。", "孤雲自南仍更東，阻覲堯蓂友廊廟。", "講通明論毗曇經，一佛出世祇爲人。", "凝師白傅有真契，鑿齒彌天必相值。", "河漢滔滔渺涯涘，三反九折時遊戲。", "簦屩躋堂累千輩，鍧雷激電非思議。", "毫忽微差失大千，同盡鴛鴻與螻蟻。", "菩提一切皆具足，刮膜分光誠豈弟。", "體味龍宮七佛書，盧老面目云何是。", "餘生流浪無明窟，迴首塵塵非自己。", "季咸鬼眼必見窺，和璞妙算應不遺。", "大士知言善呵蔽，朝聞夕殞甘如飴。", "疑蛇一祛病當愈，識路還家要有時。", "金華士女涕泗流，胡爲决往龍翔遊。", "是間雖住亦非住，奔軼常行祖師處。"]'),
('085283b2-5937-49e5-956e-38043e1fa884','送富樞知三衢三首  其一','蘇籀','宋','宋诗','song-poetry','','[]','琳館屢青書带草，璽封薦捧紫芝泥。',64,'全唐诗/poet.song.100000.json','["琳館屢青書带草，璽封薦捧紫芝泥。", "寅車暫此紆台紱，黄閣依前執命珪。", "表按山川袴襦內，勸農雲水插秧齊。", "論毗國是惟公韙，令順民心不曰卑。"]'),
('25e9a045-9930-4286-a8c2-6eb61e172a56','送富樞知三衢三首  其二','蘇籀','宋','宋诗','song-poetry','','[]','代天襟量服英髦，能扈王舟出海潮。',64,'全唐诗/poet.song.100000.json','["代天襟量服英髦，能扈王舟出海潮。", "輕重裴公陳梗切，安危汲孺絕麾招。", "吟牋訪古羊騰石，奕局行春柯爛樵。", "謝傅不應丘壑尚，絕塵機警冠當朝。"]'),
('526d7b0a-bd31-4bc2-a050-5370bbebb95f','送富樞知三衢三首  其三','蘇籀','宋','宋诗','song-poetry','','[]','山林引避一無求，遄返巖廊豈自由。',64,'全唐诗/poet.song.100000.json','["山林引避一無求，遄返巖廊豈自由。", "聖主尊賢載謨誥，故家紀善付春秋。", "公誠願獎朝中意，密勿謀先天下憂。", "臭味久令參籍湜，斐然攀賦畔牢愁。"]'),
('3f773d55-8d83-41e3-9562-35a228222a78','示兒子詡','蘇籀','宋','宋诗','song-poetry','','[]','屬詞更聽三年後，爲善須無一念乖。',32,'全唐诗/poet.song.100000.json','["屬詞更聽三年後，爲善須無一念乖。", "孔里高高若崧岱，論思積習見巖崖。"]'),
('b5680d29-4b69-44a4-9cca-099818e327ca','送中書潘舍人省上二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','紫微雞省待論思，少作英辭寤柬奇。',64,'全唐诗/poet.song.100000.json','["紫微雞省待論思，少作英辭寤柬奇。", "高浪駕天輸朗漢，紫霄即日奮長離。", "然明東里今同道，德裕封敖適此時。", "應笑迂慵畸已甚，嗚呼鶴巘綴蟬枝。"]'),
('dec7be96-f851-4878-96ca-934c5fafc439','送中書潘舍人省上二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','亟紓多難一羣心，惕厲咨嗟憯測深。',64,'全唐诗/poet.song.100000.json','["亟紓多難一羣心，惕厲咨嗟憯測深。", "漢制春溫勸敦本，周家夙戒豈無箴。", "該淹伯始萬端理，煩悉姬公五誥尋。", "愈近清光綴經席，皇風如玉亦如金。"]'),
('5b6bc6bf-eba2-4ed3-91d6-cea8e03307d4','訪鹿田二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','隱士雲凝北山麓，將軍樹竦碧崖寒。',64,'全唐诗/poet.song.100000.json','["隱士雲凝北山麓，將軍樹竦碧崖寒。", "烏犍戶富犂千畝，蒼簳梯空擢萬竿。", "犖犖馬鞭貪快睹，森森僧席飫奇觀。", "未應泉石減天竺，自古英靈招考槃。"]'),
('1f5e658e-fc31-4836-8ff1-4fe248794139','訪鹿田二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','夕陽紅曬稊生粉，曉露凝清栗脫蓬。',64,'全唐诗/poet.song.100000.json','["夕陽紅曬稊生粉，曉露凝清栗脫蓬。", "樂歲人并厖彘飽，高城地隔馬牛風。", "禽鼯天籟互鳴囀，林薄山屏競蔚蓊。", "採杞擷芎薪水暇，吾從龐老興何窮。"]'),
('2d7409ab-96fa-4c8a-a770-07e7f55ec77a','武林春日二絕  其一','蘇籀','宋','宋诗','song-poetry','','[]','越羅初御柳煙深，慵病相從老見尋。',32,'全唐诗/poet.song.100000.json','["越羅初御柳煙深，慵病相從老見尋。", "酒罷塵杯膠燥吻，春無顧藉一分心。"]'),
('7e491c5e-9e61-43af-bd29-667f45fe5566','武林春日二絕  其二','蘇籀','宋','宋诗','song-poetry','','[]','何人亹亹共揮麈，有物娟娟散百花。',32,'全唐诗/poet.song.100000.json','["何人亹亹共揮麈，有物娟娟散百花。", "不向箇中吟蓓蕾，久晴風日漲塵沙。"]'),
('7d861288-a55e-497e-b73a-4b2925c6d3f8','邵公濟求泰定山房十詩 下馬橋','蘇籀','宋','宋诗','song-poetry','','[]','泉下顔光祿，二紀瞻馬首。',24,'全唐诗/poet.song.100000.json','["泉下顔光祿，二紀瞻馬首。", "停驂肅松檟，風節應不朽。"]'),
('42658e36-5752-40bd-a1a6-c458064a3107','邵公濟求泰定山房十詩 邵公泉','蘇籀','宋','宋诗','song-poetry','','[]','源深派河漢，蹙蹙尋常窄。',24,'全唐诗/poet.song.100000.json','["源深派河漢，蹙蹙尋常窄。", "嗜芰借甘滋，無涯君子澤。"]'),
('e9b4e09a-8e10-441b-ada2-f482e0740ba0','邵公濟求泰定山房十詩 褒勸堂','蘇籀','宋','宋诗','song-poetry','','[]','易經傳父子，前後弓帛賁。',24,'全唐诗/poet.song.100000.json','["易經傳父子，前後弓帛賁。", "衣鉢堂室中，千古發潛祕。"]'),
('2f7ab3dc-2754-4972-ac0b-7fddddcada90','邵公濟求泰定山房十詩 松門','蘇籀','宋','宋诗','song-poetry','','[]','晝扃熟鹿守，晨啟素鴉馴。',24,'全唐诗/poet.song.100000.json','["晝扃熟鹿守，晨啟素鴉馴。", "延陵掛孤劍，吳月照峩岷。"]');
